window.__ARXIV_DATA__ = {"papers":[{"id":"2606.30638v1","title":"Open-Vocabulary and Referring Segmentation for 3D Gaussians Using 2D Detectors","abstract":"3D Gaussian Splatting (3DGS) has emerged at the forefront of 3D scene reconstruction. Extending 3DGS with language-driven, open-vocabulary understanding has gained significant attention for real-world applications such as embodied AI. Recent methods achieve this by learning an instance feature attribute and assigning semantics by distilling high-dimensional Contrastive Language-Image Pretraining (CLIP) features directly into the scene representation. However, the instance grouping mechanisms of these methods either require a predefined number of instances or suffer from noise in their bottom-up grouping strategies. Furthermore, the reliance on CLIP restricts semantic understanding to simple noun phrases, preventing complex spatial reasoning and referential expression grounding. We present GaussDet, a method that circumvents the need for dense CLIP features by leveraging discrete, open-vocabulary 2D object detectors with referring expression capabilities. We learn instance features for individual Gaussians to decompose the scene into 3D instance groups. By rendering these groups and aggregating semantic votes from multi-view 2D detections, we generate a robust View-Aggregated Semantic Label Distribution (VASD) for each 3D instance. This view-aggregation strategy acts as a strong regularizer, attenuating spurious labels caused by low-quality instance grouping. Our approach enables a straightforward, zero-shot extension from simple language queries to complex referential grounding. Extensive evaluations across two key tasks -- open-vocabulary segmentation (LeRF-OVS, ScanNet) and referring expression grounding (Ref-LeRF) -- demonstrate that GaussDet achieves consistent improvements over existing methods. Most notably, we achieve a substantial 16.7% mIoU improvement in referential grounding within a strict zero-shot setting.","authors":["Jameel Hassan","Yasiru Ranasinghe","Vishal Patel"],"published":"2026-06-29T17:58:41Z","updated":"2026-06-29T17:58:41Z","abstract_url":"https://arxiv.org/abs/2606.30638v1","html_url":"https://arxiv.org/html/2606.30638v1","pdf_url":"https://arxiv.org/pdf/2606.30638v1.pdf","matched_keywords":["3d","representation","instance"],"source_used":"html","source_text_chars":51976,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d, representation, instance 相关；摘要显示其主要贡献为：3D Gaussian Splatting (3DGS) has emerged at the forefront of 3D scene reconstruction. Extending 3DGS with language-driven, open-vocabulary understanding has gained significant attention for real-world applications such as embodied AI. Recent methods achieve t...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-30T04:58:52+00:00","status":"fallback"},"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30632v1","title":"GROW$^2$: Grounding Which and Where for Robot Tool Use","abstract":"Can the robot use a plate to cut a cake if no knife is available? Tool use greatly expands robot capabilities, but to use tools creatively beyond their intended functions, the robot faces the challenge of $\\textit{open-world affordance grounding}$: select an open-category object to act as a tool and localize its specific region of action. To this end, we introduce GROW$^2$ (GROunding Which and Where), which leverages object parts as a natural abstraction to split the grounding process hierarchically into semantic and geometric levels, thus bypassing the need for data-heavy, end-to-end training. Semantically, GROW$^2$ harnesses the commonsense reasoning of Vision-Language Models (VLMs) to parse a natural-language task instruction, select a suitable object as the tool, and identify task-relevant parts on the tool and the target object. Geometrically, vision foundation models then ground the selected parts into precise 3D regions from a single RGB-D image. Experiments on established benchmarks show that GROW$^2$ outperforms state-of-the-art baselines on affordance prediction benchmarks. Further, it achieves zero-shot generalization over open-category objects and outperforms baselines in both simulated and real-world robot tool use experiments.","authors":["Yuhong Deng","Yuyao Liu","David Hsu"],"published":"2026-06-29T17:56:53Z","updated":"2026-06-29T17:56:53Z","abstract_url":"https://arxiv.org/abs/2606.30632v1","html_url":"https://arxiv.org/html/2606.30632v1","pdf_url":"https://arxiv.org/pdf/2606.30632v1.pdf","matched_keywords":["3d"],"source_used":"html","source_text_chars":76069,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d 相关；摘要显示其主要贡献为：Can the robot use a plate to cut a cake if no knife is available? Tool use greatly expands robot capabilities, but to use tools creatively beyond their intended functions, the robot faces the challenge of $\\textit{open-world affordance grounding}$: select an...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-30T04:58:52+00:00","status":"fallback"},"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30611v1","title":"Reweighting Framewise Attention in Video Transformers for Facial Expression Understanding","abstract":"Understanding facial expressions in videos requires modeling subtle and localized facial dynamics under unconstrained conditions. Although recent Vision Transformer~(ViT)-based video models have shown strong performance through large-scale self-supervised pretraining, their attention mechanisms often emphasize dominant global motions and coarse temporal dynamics, limiting sensitivity to fine-grained facial variations. To address this limitation, we propose MiRA (Marginal-induced Attention Redistribution), a plug-in frame-marginal attention redistribution framework for ViT backbones that enhances spatio-temporal selectivity toward subtle facial dynamics without introducing additional trainable parameters. MiRA derives frame-level confidence and intra-frame concentration statistics from self-attention maps to estimate frame-wise marginal importance and redistribute attention toward spatiotemporally localized facial cues. We first introduce a principled \\textit{exact mode} based on post-softmax attention redistribution. To further improve efficiency, we propose \\textit{flashLite mode}, a lightweight pre-softmax approximation that integrates frame-marginal redistribution into FlashAttention kernels while preserving the effectiveness of the exact formulation. Experimental results on challenging Facial Expression Recognition~(FER) benchmarks demonstrate consistent improvements over strong ViT baselines.","authors":["Seongro Yoon","Donghyeon Cho","Jinsun Park","François Brémond"],"published":"2026-06-29T17:46:10Z","updated":"2026-06-29T17:46:10Z","abstract_url":"https://arxiv.org/abs/2606.30611v1","html_url":"https://arxiv.org/html/2606.30611v1","pdf_url":"https://arxiv.org/pdf/2606.30611v1.pdf","matched_keywords":["video"],"source_used":"html","source_text_chars":70941,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video 相关；摘要显示其主要贡献为：Understanding facial expressions in videos requires modeling subtle and localized facial dynamics under unconstrained conditions. Although recent Vision Transformer~(ViT)-based video models have shown strong performance through large-scale self-supervised pre...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-30T04:58:52+00:00","status":"fallback"},"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30608v1","title":"UnfoldArt: Zero-Shot Recovery of Full Articulated 3D Objects from Text or Image","abstract":"Articulated 3D objects are essential for interactive environments in embodied AI, robotics, and virtual reality, but reconstructing their structure and motion from sparse observations remains challenging. Existing approaches remain largely constrained by lack of supervised data or lack the priors needed to reliably recover articulation, hidden geometry, and internal object structure. We present the first debate-driven agentic approach to articulated 3D object reconstruction from text or image inputs that both grounds articulation reasoning in concrete motion and exposes the occluded geometry revealed under articulation. High-level agents reason about object semantics and motion using knowledge from vision-language and video models, while low-level agents estimate articulation parameters and interaction points; together, they engage in a two-round structured debate that first exploits global--local disagreement and then grounds the agents in freely generated video. The same video prior, conditioned on the agreed articulation, then drives each part through its motion to expose occluded interiors and geometry that cannot be inferred from a single static view. By combining agentic reasoning with a video generative prior, our approach jointly infers articulation and reconstructs complete 3D articulated objects, producing high-fidelity geometry, internal structure, and motion-consistent states beyond directly observed surfaces.","authors":["Mohamed el amine boudjoghra","Ivan Laptev","Angela Dai"],"published":"2026-06-29T17:44:53Z","updated":"2026-06-29T17:44:53Z","abstract_url":"https://arxiv.org/abs/2606.30608v1","html_url":"https://arxiv.org/html/2606.30608v1","pdf_url":"https://arxiv.org/pdf/2606.30608v1.pdf","matched_keywords":["video","3d","agent"],"source_used":"html","source_text_chars":82192,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, 3d, agent 相关；摘要显示其主要贡献为：Articulated 3D objects are essential for interactive environments in embodied AI, robotics, and virtual reality, but reconstructing their structure and motion from sparse observations remains challenging. Existing approaches remain largely constrained by lack...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-30T04:58:52+00:00","status":"fallback"},"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30599v1","title":"Goku: A Million-Scale Universal Dataset and Benchmark for Instruction-Based Video Editing","abstract":"Existing instruction-based video editing datasets commonly focus on single-task appearance editing, failing to meet the complex creative demands of real-world scenarios. To bridge this gap, we present Goku, a large-scale dataset featuring 2 million high-quality, instruction-aligned video editing pairs, which is the first to extend task boundaries from basic appearance editing to multi-task and structural manipulations(e.g., precise control of subject movement). To tackle the data synthesis challenges inherent in these complex tasks, we design an efficient data synthesis pipeline that decomposes complex edits into controllable sub-problems and introduce a progressive filtering system for data reliability throughout the whole process. Furthermore, we explore the optimal network structures on Goku, and propose Goku-Edit. To deeply comprehend complex editing instructions, Goku-Edit leverages an MLLM as its text encoder and adopts a decoupled dual-branch design: a dedicated mask branch handles structural control, freeing the main branch for appearance rendering. A comprehensive video editing benchmark, Goku-Bench, is also proposed with 1,000 human-verified test cases and 7 novel editing-specific metrics. Evaluated on Goku-Bench, Goku-Edit obtains up to +8% improvement on other open-source models in terms of instruction following.","authors":["Sen Liang","Cong Wang","Zhentao Yu","Fengbin Guan","Zhengguang Zhou","Teng Hu","Youliang Zhang","Yuan Zhou","Xin Li","Qinglin Lu","Zhibo Chen"],"published":"2026-06-29T17:38:15Z","updated":"2026-06-29T17:38:15Z","abstract_url":"https://arxiv.org/abs/2606.30599v1","html_url":"https://arxiv.org/html/2606.30599v1","pdf_url":"https://arxiv.org/pdf/2606.30599v1.pdf","matched_keywords":["video"],"source_used":"html","source_text_chars":45019,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video 相关；摘要显示其主要贡献为：Existing instruction-based video editing datasets commonly focus on single-task appearance editing, failing to meet the complex creative demands of real-world scenarios. To bridge this gap, we present Goku, a large-scale dataset featuring 2 million high-quali...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-30T04:58:52+00:00","status":"fallback"},"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30598v1","title":"Towards in-the-wild Egocentric 3D Hand-Object Pose Estimation","abstract":"Estimating accurate 3D hand-object pose from in-the-wild egocentric RGB remains challenging due to severe occlusions and ambiguous contact. Existing learning-based methods often struggle to generalise to in-the-wild scenes and are limited by the scarcity of supervision. We address these issues with two contributions. First, we introduce EPIC-Contact, an in-the-wild egocentric dataset of 2.3K clips (62.3K frames) with dense, bijective 3D hand-object contact correspondences and posed meshes. Second, we propose HOPformer, an end-to-end transformer that jointly predicts bi-manual hand and object pose in a single forward pass. A cross-attention decoder conditions object features on hand priors, producing robust pose estimation. We test HOPformer on the in-lab 3D dataset, ARCTIC, as well as our newly introduced EPIC-Contact dataset. HOPformer reaches 82.4% success rate on ARCTIC (+6.2 pts over current SOTA). On EPIC-Contact, it nearly doubles the success rate while reducing contact deviation by 75%. EPIC-Contact, HOPformer code and checkpoints are released: https://sid2697.github.io/epic-contact.","authors":["Siddhant Bansal","Zhifan Zhu","Shashank Tripathi","Jiahe Zhao","Michael J. Black","Dima Damen"],"published":"2026-06-29T17:38:12Z","updated":"2026-06-29T17:38:12Z","abstract_url":"https://arxiv.org/abs/2606.30598v1","html_url":"https://arxiv.org/html/2606.30598v1","pdf_url":"https://arxiv.org/pdf/2606.30598v1.pdf","matched_keywords":["3d"],"source_used":"html","source_text_chars":87321,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d 相关；摘要显示其主要贡献为：Estimating accurate 3D hand-object pose from in-the-wild egocentric RGB remains challenging due to severe occlusions and ambiguous contact. Existing learning-based methods often struggle to generalise to in-the-wild scenes and are limited by the scarcity of s...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-30T04:58:52+00:00","status":"fallback"},"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30597v1","title":"Learning from Reliable Latent Prompts for Visual Recognition with Missing Modalities","abstract":"Large-scale multimodal models (LMMs) have achieved superior performance in visual recognition by synergizing information across diverse, massive-scale paired modalities. In real-world scenarios, however, missing-modality inputs are ubiquitous, causing models optimized for modality-complete data to exhibit precipitous performance degradation. Existing research has introduced prompt learning to mitigate this issue, typically by generating dynamic prompts from instance-level features, regardless of whether the input modalities are complete or partially absent. However, such input-conditioned strategies are hindered by the escalating unreliability of instance-level features; as higher missing rates increase the proportion of incomplete modalities, the resulting instability in prompt learning limits the model's performance. To address this limitation, we hypothesize that learnable latent prompts themselves encapsulate stable, modality-intrinsic priors that are decoupled from corrupted inputs. Consequently, we propose a novel paradigm: Learning from Reliable Latent Prompts. Unlike prior methods, we model input-agnostic learnable prompts as stable latent anchors that enable robust guidance and effective cross-modal knowledge compensation, even under extreme missing rates (e.g., 90%). Empirical results across three benchmark datasets demonstrate that our \"learn-from-latent-prompts\" approach achieves state-of-the-art performance across a wide range of missing-modality scenarios. Extensive experiments further confirm the effectiveness of this paradigm in providing a robust solution to the missing-modality problem.","authors":["Taixi Chen","Nancy Guo"],"published":"2026-06-29T17:36:47Z","updated":"2026-06-29T17:36:47Z","abstract_url":"https://arxiv.org/abs/2606.30597v1","html_url":"https://arxiv.org/html/2606.30597v1","pdf_url":"https://arxiv.org/pdf/2606.30597v1.pdf","matched_keywords":["instance","multimodal"],"source_used":"html","source_text_chars":58458,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 instance, multimodal 相关；摘要显示其主要贡献为：Large-scale multimodal models (LMMs) have achieved superior performance in visual recognition by synergizing information across diverse, massive-scale paired modalities. In real-world scenarios, however, missing-modality inputs are ubiquitous, causing models...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-30T04:58:52+00:00","status":"fallback"},"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30576v1","title":"Beyond 2D Matching: A Unified Single-Stage Framework for Geometry-Aware Cross-View Object Geo-Localization","abstract":"Cross-view object geo-localization (CVOGL) aims to locate a target object from a query view (e.g., ground or drone) within a geo-tagged reference image (e.g., satellite). Existing approaches heavily rely on 2D appearance matching and are constrained by limited datasets lacking geometric metadata, diverse prompts, and standard field-of-view imagery. To address these intertwined challenges, we first introduce \\dataset, a large-scale, high-fidelity building dataset comprising over 220,000 ground-satellite and drone-satellite pairs. It provides multi-modal prompts (points, boxes, masks) and camera poses to enable flexible target referring and explicit spatial modeling. Furthermore, we propose a novel single-stage Geometry-Aware Geo-localization framework (GAGeo), built upon the permutation-equivariant 3D foundation model $π^3$. By seamlessly integrating visual features, referring prompts, and learnable task tokens, our model adapts the inherited 3D prior to jointly predict bounding boxes, segmentation masks, and camera poses in a single forward pass. Additionally, we introduce a contrastive loss that utilizes the satellite view as a universal anchor, implicitly aligning ground and drone representations to enable zero-shot ground-to-drone localization without requiring triplet training data. Extensive experiments demonstrate that our approach significantly outperforms state-of-the-art methods, exhibiting exceptional generalization ability in unseen scenes and novel cross-view setups.","authors":["Liyao Wang","Ruipu Wu","Haojun Xu","Lei Shi","Linjiang Huang","Si Liu"],"published":"2026-06-29T17:19:49Z","updated":"2026-06-29T17:19:49Z","abstract_url":"https://arxiv.org/abs/2606.30576v1","html_url":"https://arxiv.org/html/2606.30576v1","pdf_url":"https://arxiv.org/pdf/2606.30576v1.pdf","matched_keywords":["3d","representation"],"source_used":"html","source_text_chars":45437,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d, representation 相关；摘要显示其主要贡献为：Cross-view object geo-localization (CVOGL) aims to locate a target object from a query view (e.g., ground or drone) within a geo-tagged reference image (e.g., satellite). Existing approaches heavily rely on 2D appearance matching and are constrained by limite...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-30T04:58:53+00:00","status":"fallback"},"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30557v1","title":"EcoVideo: Entropy-Orchestrated Video Generation Paradigm in Cloud-Edge Dynamics","abstract":"DiT video generation is latency-intensive due to iterative full-frame denoising, while prior cloud-edge methods largely rely on static inter-step decoupling and cannot leverage inter-frame similarity or adapt to system dynamics. We propose EcoVideo, an entropy-orchestrated framework for dynamic inter-frame decoupling: early-stage self-attention entropy provides a training-free estimate of frame-wise information density for frame selection; a cloud large model denoises sparse high-entropy keyframes; and an edge lightweight model reconstructs the remaining frames via motion-aware interpolation with refinement for temporal stability. EcoVideo further adapts the keyframe budget and edge refinement depth to real-time bandwidth and compute availability, optimizing end-to-end latency under constraints. Experiments on representative DiT video generators show improved quality--efficiency trade-offs and up to 2.9x end-to-end speedup in low-bandwidth, compute-limited edge settings. Code is available at https://github.com/IF-LAB-PKU/EcoVideo.","authors":["Jiayu Chen","Hengyi Zhang","Maoliang Li","Minyu Li","Zihao Zheng","Xuanzhe Liu","Guojie Luo","Xiang Chen"],"published":"2026-06-29T16:51:56Z","updated":"2026-06-29T16:51:56Z","abstract_url":"https://arxiv.org/abs/2606.30557v1","html_url":"https://arxiv.org/html/2606.30557v1","pdf_url":"https://arxiv.org/pdf/2606.30557v1.pdf","matched_keywords":["video"],"source_used":"html","source_text_chars":46822,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video 相关；摘要显示其主要贡献为：DiT video generation is latency-intensive due to iterative full-frame denoising, while prior cloud-edge methods largely rely on static inter-step decoupling and cannot leverage inter-frame similarity or adapt to system dynamics. We propose EcoVideo, an entrop...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-30T04:58:53+00:00","status":"fallback"},"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30552v1","title":"Training Vision-Language-Action Models with Dense Embodied Chain-of-Thought Supervision","abstract":"Cross-embodiment transfer in vision-language-action (VLA) models remains challenging because low-level state and action spaces differ fundamentally across robot platforms. We observe that the high-level cognitive process underlying manipulation, including scene perception, object identification, task planning, and sub-task decomposition, is largely shared across embodiments. Based on this observation, we present ZR-0, a 2.6 billion parameter end-to-end VLA model that uses dense Embodied Chain-of-Thought (ECoT) supervision to align cross-embodiment representations within the vision-language model (VLM). ZR-0 adopts a dual-stream architecture: a pre-trained VLM (System 2) generates structured ECoT reasoning during training, while a Diffusion Transformer-based action expert (System 1) produces continuous action chunks via flow matching. The two components are coupled through cross-attention, with an attention mask that restricts the action expert to input prompt features only, enabling ECoT generation to be entirely skipped at inference without any performance loss. ZR-0 is pre-trained on ProcCorpus-60M, a large-scale dataset comprising approximately 60 million frames (approximately 1,000 hours) from over 400K trajectories, with dense ECoT annotations covering 96.8% of all frames. We evaluate ZR-0 on three simulation benchmarks spanning single-arm (LIBERO), bimanual (RoboTwin 2.0), and humanoid (RoboCasa GR-1 Tabletop) embodiments, as well as real-world experiments on the xArm platform, demonstrating strong performance across all settings. Code and model checkpoints are available at https://github.com/RUCKBReasoning/ZR-0.","authors":["Haoyang Li","Guanlin Li","Youhe Feng","Chen Zhao","Zhuoran Wang","Yang Li","Qizhe Wei","Shifeng Bao","Haitao Shen","Yihan Zhao","Tong Yang","Jing Zhang"],"published":"2026-06-29T16:48:48Z","updated":"2026-06-29T16:48:48Z","abstract_url":"https://arxiv.org/abs/2606.30552v1","html_url":"https://arxiv.org/html/2606.30552v1","pdf_url":"https://arxiv.org/pdf/2606.30552v1.pdf","matched_keywords":["representation","diffusion"],"source_used":"html","source_text_chars":67553,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation, diffusion 相关；摘要显示其主要贡献为：Cross-embodiment transfer in vision-language-action (VLA) models remains challenging because low-level state and action spaces differ fundamentally across robot platforms. We observe that the high-level cognitive process underlying manipulation, including sce...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-30T04:58:53+00:00","status":"fallback"},"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30545v1","title":"StereoGS: Sparse-View 3D Gaussian Splatting via Stereo Priors","abstract":"3D Gaussian Splatting (3DGS) has achieved remarkable success in real-time novel view synthesis, yet it suffers from severe overfitting under sparse-view settings due to insufficient geometric constraints. While recent methods introduce monocular depth priors to mitigate this, they inherently struggle with scale ambiguity and cross-view inconsistency, leading to defective geometry. In this paper, we propose StereoGS, a novel sparse-view 3DGS framework that integrates stereo priors to establish reliable binocular consistency. Unlike scale-agnostic monocular constraints, StereoGS introduces a Stereo Depth Regularization by constructing virtual stereo pairs during optimization and leveraging a foundation stereo model to enforce absolute scale and binocular-consistent structures. To further suppress overfitting and eliminate redundant primitives, we design a Gradient-Aware Opacity Decay strategy that dynamically penalizes Gaussians based on their relative opacity gradient magnitudes. Combined with a Consistency-Aware Dense Initialization using zero-shot multi-view depth estimation, StereoGS effectively anchors primitives to accurate scene surfaces. Extensive experiments on LLFF, DTU, Mip-NeRF360, and Blender datasets demonstrate that StereoGS achieves state-of-the-art performance in sparse-view settings without incurring any additional inference overhead. Project Page: https://stringerywh00.github.io/StereoGS_project_page/","authors":["Wenhao Yuan","Yiyuan Ge","Deli Cai"],"published":"2026-06-29T16:45:57Z","updated":"2026-06-29T16:45:57Z","abstract_url":"https://arxiv.org/abs/2606.30545v1","html_url":"https://arxiv.org/html/2606.30545v1","pdf_url":"https://arxiv.org/pdf/2606.30545v1.pdf","matched_keywords":["3d"],"source_used":"html","source_text_chars":66340,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d 相关；摘要显示其主要贡献为：3D Gaussian Splatting (3DGS) has achieved remarkable success in real-time novel view synthesis, yet it suffers from severe overfitting under sparse-view settings due to insufficient geometric constraints. While recent methods introduce monocular depth priors...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-30T04:58:53+00:00","status":"fallback"},"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30537v1","title":"Learning from Mistakes: Rollout-Retrieval Lifelong Policy Learning for Autonomous Driving","abstract":"Autonomous driving policies should be able to improve continually as deployment exposes them to increasingly diverse and long-tail traffic situations. However, most learning-based policies are trained or fine-tuned on expert demonstrations and then rely largely on generalization to handle challenging closed-loop scenarios, lacking an explicit mechanism to correct and retain the mistakes exposed in these scenarios. This paper studies autonomous driving policy improvement from a lifelong learning perspective: Can a pretrained policy improve continually by accumulating corrective knowledge derived from its own mistakes, while retaining previously acquired driving competence? To answer this question, we propose Rollout-Retrieval Lifelong Policy Learning (R$^2$LPL), a policy learning framework that retrieves corrective targets from recoverable policy-induced mistakes and retains the resulting knowledge through lifelong policy learning. R^2LPL addresses a key bottleneck in continual policy improvement: closed-loop mistakes reveal where the policy is weak, but do not directly specify what the policy should learn. By filtering recoverable mistake-related states and retrieving feasible corrective targets, R$^2$LPL turns sparse failure evidence into compact supervised knowledge for stable and sample-efficient policy improvement. We evaluate R$^2$LPL on large-scale closed-loop nuPlan benchmarks. With only a few rollout and continual-learning cycles, R$^2$LPL elevates a learning-based planner with moderate initial performance to state-of-the-art performance across the evaluated benchmarks, especially on the challenging and long-tail Test14-hard split. These results demonstrate the effectiveness of R$^2$LPL in converting recoverable closed-loop mistakes into corrective knowledge for sustained policy improvement.","authors":["Cheng Gong","Haoyang Wang","Chao Lu","Zirui Li","Jianwei Gong"],"published":"2026-06-29T16:37:50Z","updated":"2026-06-29T16:37:50Z","abstract_url":"https://arxiv.org/abs/2606.30537v1","html_url":"https://arxiv.org/html/2606.30537v1","pdf_url":"https://arxiv.org/pdf/2606.30537v1.pdf","matched_keywords":["retrieval"],"source_used":"html","source_text_chars":92633,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 retrieval 相关；摘要显示其主要贡献为：Autonomous driving policies should be able to improve continually as deployment exposes them to increasingly diverse and long-tail traffic situations. However, most learning-based policies are trained or fine-tuned on expert demonstrations and then rely large...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-30T04:58:53+00:00","status":"fallback"},"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30534v1","title":"Orca: The World is in Your Mind","abstract":"We introduce Orca, an initial instantiation of a general world foundation model. Orca learns a unified world latent space from multimodal world signals and exposes it through multimodal readout interfaces. Rather than optimizing isolated next-token, next-frame, or next-action prediction, we are centered on Next-State-Prediction modeling, offering a unified state-transition modeling route toward understanding, predicting, and acting upon the world. Orca learns through two complementary paradigms: unconscious learning captures dense natural state transitions from continuous videos, and conscious learning models sparse meaningful state transitions by language-described events and VQA supervision. For pre-training, we construct a large-scale world-learning inventory data, including 125K hours of video data and 160M event annotations. After pre-training, Orca learns a unified world latent space. To examine whether the learned latent supports downstream, we evaluate it by three representative downstream readouts: text generation, image prediction, and embodied action generation. Orca's backbone is frozen, and only the lightweight modality-specific decoders are trainable. Experiments show the scalability of the proposed paradigm and verify that stronger world latent enables stronger downstream readouts. Orca outperforms similar-sized specialized baselines. These results show that Orca, as a general world foundation model, presents a promising approach to understanding, predicting, and acting upon the world. Finally, we discuss the current limitations, aiming to provide useful insights and inspiration for the community.","authors":["Yihao Wang","Yuheng Ji","Mingyu Cao","Yanqing Shen","Runze Xiao","Huaihai Lyu","Senwei Xie","Euan Liu","Klara Tian","Tianfeng Long","Yichi Zhang","Zhengliang Cai","Ruike Chen","Jifan Zhao","Ruochuan Shi","Zihan Tang","Jing Lyu","Wenxing Tan","Ningbo Zhang","Yangtao Hu","Yuming Gao","Xiansheng Chen","Junkai Zhao","Congsheng Xu","Boan Zhu","Ziqi Wang","Yupu Feng","Qiongqiong Zhang","Yingli Zhao","Yulong Ao","Shaoxuan Xie","You Liu","Guocai Yao","Leiduo Zhang","Xiaodan Liu","Yunyan Zhang","Yance Jiao","Xinyan Yang","Jiaxing Wei","Xu Liu","Tengfei Pan","Shaokai Nie","Chunlei Men","Sen Cui","Xiaojie Jin","Hongyang Li","Jianlan Luo","Yao Mu","Yunchao Wei","Jun Yan","Hang Zhao","Xiaolong Zheng","Jiaming Li","Yonghua Lin","Tiejun Huang","Zhongyuan Wang","Pengwei Wang"],"published":"2026-06-29T16:36:10Z","updated":"2026-06-29T16:36:10Z","abstract_url":"https://arxiv.org/abs/2606.30534v1","html_url":"https://arxiv.org/html/2606.30534v1","pdf_url":"https://arxiv.org/pdf/2606.30534v1.pdf","matched_keywords":["video","multimodal"],"source_used":"html","source_text_chars":100192,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, multimodal 相关；摘要显示其主要贡献为：We introduce Orca, an initial instantiation of a general world foundation model. Orca learns a unified world latent space from multimodal world signals and exposes it through multimodal readout interfaces. Rather than optimizing isolated next-token, next-fram...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-30T04:58:53+00:00","status":"fallback"},"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30528v1","title":"$μ$Flow: Leveraging Average Images for Improving Generalisation of Deepfake Faces Detectors","abstract":"Current generative models, including GANs and diffusion models, have reached an outstanding level of photorealism, posing significant risks to privacy and security. To ensure real-world applicability, deepfake detectors must generalise effectively to unseen generators. However, most existing approaches rely on supervised training with both real and fake images, which limits their generalisation especially across generators categories (e.g. GANs vs DMs). In this work, we introduce $μ$Flow, a one-class deepfake detector trained only on real images without relying on pseudo-deepfakes or synthetic artifacts. Our approach builds on the observation that averaging multiple images amplifies consistent generative traces, producing highly discriminative feature representations. We leverage this property by modelling the distribution of features extracted from averaged images and training a normalizing flow to align the feature space of individual images with this distribution. This alignment yields a likelihood-based criterion that separates real and fake samples while promoting strong generalisation. We evaluate $μ$Flow on a fully out-of-distribution setting, where both real and fake datasets are unseen during training. Experimental results show that our method significantly outperforms SOTA detectors. Project page: https://opontorno.github.io/MuFlow.","authors":["Orazio Pontorno","Mattia Litrico","Luca Guarnera","Mario Valerio Giuffrida","Sebastiano Battiato"],"published":"2026-06-29T16:31:57Z","updated":"2026-06-29T16:31:57Z","abstract_url":"https://arxiv.org/abs/2606.30528v1","html_url":"https://arxiv.org/html/2606.30528v1","pdf_url":"https://arxiv.org/pdf/2606.30528v1.pdf","matched_keywords":["representation","diffusion"],"source_used":"html","source_text_chars":49263,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation, diffusion 相关；摘要显示其主要贡献为：Current generative models, including GANs and diffusion models, have reached an outstanding level of photorealism, posing significant risks to privacy and security. To ensure real-world applicability, deepfake detectors must generalise effectively to unseen g...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-30T04:58:53+00:00","status":"fallback"},"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30514v1","title":"3D Scene-Adaptive Trajectory-Controllable Human Image Animation with Camera Movement","abstract":"Human image animation, which aims to generate a video of a reference subject following a provided action sequence, has received increasing research interest. With the development of diffusion-based/flow-based video foundation models, existing animation works have began to upgrade the guidance information from 2D skeleton/pose to 3D modeling conditions. Despite achieving reasonable results, these approaches face challenges in synthesizing trajectory-controllable human motion within natural scene under changed camera views. In this work, we present a scene-adaptive human image animation framework that controls both human motion and camera trajectories within a reconstructed 3D environment for video generation. To achieve this, we first develop a ground-adaptive 3D motion retargeting approach to enable user-friendly motion trajectory control adapting to the changes of elevations of ground and orientations automatically. Then we design a viewpoint-adaptive latent fusion mechanism to inject point-cloud geometric priors through scene-visibility masking into the generative process, providing precise guidance of viewpoint changes under camera control. Experiments on two standard human image animation benchmark datasets demonstrate remarkable improvements of our method over the state of the arts in related video generation metics. Project page: https://robinhood256100.github.io/web-disp","authors":["Deyin Liu","Jicheng Xu","Lin Yuanbo Wu","Xiaowei Zhao","Xiatian Zhu","Zhe Jin","Anjan Dutta"],"published":"2026-06-29T16:22:54Z","updated":"2026-06-29T16:22:54Z","abstract_url":"https://arxiv.org/abs/2606.30514v1","html_url":"https://arxiv.org/html/2606.30514v1","pdf_url":"https://arxiv.org/pdf/2606.30514v1.pdf","matched_keywords":["video","3d","diffusion"],"source_used":"html","source_text_chars":40092,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, 3d, diffusion 相关；摘要显示其主要贡献为：Human image animation, which aims to generate a video of a reference subject following a provided action sequence, has received increasing research interest. With the development of diffusion-based/flow-based video foundation models, existing animation works...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-30T04:58:54+00:00","status":"fallback"},"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30498v1","title":"On the Faithfulness of Post-Hoc Concept Bottleneck Models","abstract":"Human decision-making interprets the world through high-level concepts, such as recognizing a bird by its belly color. To bridge the gap between opaque deep learning representations and human understanding, Post-Hoc Concept Bottleneck Models (post-hoc CBMs) project latent features onto interpretable concept spaces using auxiliary datasets or vision-language models. However, relying on target task accuracy as the primary measure of post-hoc CBM success obscures whether the learned concepts are semantically meaningful or merely predictive artifacts. For example, random concept projections can achieve competitive accuracy despite being semantically meaningless. In this work, we analyze the learned projections directly and identify two failure cases: First, for concept projections learned from auxiliary data, covariate shifts can lead to unfaithful concept representations for the target task. In particular, we provide an upper bound on the error introduced by this shift. Second, systematic label noise in surrogate concept labels generated by vision-language models leads to unfaithful projections. After formalizing these failure modes, we introduce novel metrics that decouple concept faithfulness from predictive accuracy. Our empirical results across real-world and synthetic benchmarks confirm that these metrics identify unfaithful behaviors that standard accuracy-based evaluation fails to detect.","authors":["Laines Schmalwasser","Jan Blunk","Niklas Penzel","Julia Niebling","Joachim Denzler"],"published":"2026-06-29T16:02:29Z","updated":"2026-06-29T16:02:29Z","abstract_url":"https://arxiv.org/abs/2606.30498v1","html_url":"https://arxiv.org/html/2606.30498v1","pdf_url":"https://arxiv.org/pdf/2606.30498v1.pdf","matched_keywords":["representation"],"source_used":"html","source_text_chars":119266,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation 相关；摘要显示其主要贡献为：Human decision-making interprets the world through high-level concepts, such as recognizing a bird by its belly color. To bridge the gap between opaque deep learning representations and human understanding, Post-Hoc Concept Bottleneck Models (post-hoc CBMs) p...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-30T04:58:54+00:00","status":"fallback"},"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30476v1","title":"PS-MOT: Cultivating Instance Awareness from Point Seeds for Multi-Object Tracking","abstract":"We introduce Point-supervised Multi-Object Tracking (PS-MOT) as a cost-effective alternative to traditional bounding box supervision, shifting the focus from spatial fitting to topological center-driven representation. However, PS-MOT faces challenges, e.g., spatial ambiguity and identity drift due to the lack of explicit geometric structure and scale constraints. To address these, we propose PS-Track, a hierarchical pipeline transitioning from points to instances across data, model, and loss levels. At the data level, we introduce Temporal-Feedback Prompting (TFP) to evolve points into temporally consistent pseudo-labels using negative spatial cues and motion priors. At the model level, we design the Point-Excited Wavelet Attention (PEWA) module, which leverages semantic correlations to activate high-frequency components, ``hallucinating'' object boundaries. At the loss level, Uncertainty-Guided Gaussian Learning (UGL) models pseudo-labels as probabilistic distributions, dynamically calibrating supervision intensity. Experiments on DanceTrack, EmboTrack, SportsMOT, and JRDB demonstrate that PS-Track provides a feasible and effective point-supervised alternative across diverse tracking scenarios, establishing a new state-of-the-art for point-supervised tracking. The source code is available at https://github.com/xifen523/PS-MOT.","authors":["Kai Luo","Fei Teng","Mengfei Duan","Wanjun Jia","Xu Wang","Hao Shi","Kunyu Peng","Zhiyong Li","Kailun Yang"],"published":"2026-06-29T15:36:00Z","updated":"2026-06-29T15:36:00Z","abstract_url":"https://arxiv.org/abs/2606.30476v1","html_url":"https://arxiv.org/html/2606.30476v1","pdf_url":"https://arxiv.org/pdf/2606.30476v1.pdf","matched_keywords":["representation","instance"],"source_used":"html","source_text_chars":77953,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation, instance 相关；摘要显示其主要贡献为：We introduce Point-supervised Multi-Object Tracking (PS-MOT) as a cost-effective alternative to traditional bounding box supervision, shifting the focus from spatial fitting to topological center-driven representation. However, PS-MOT faces challenges, e.g.,...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-30T04:58:54+00:00","status":"fallback"},"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30458v1","title":"Cross-Resolution Semantic Transfer for Robust Text-to-Image Retrieval in Low-Resolution Surveillance","abstract":"Text-to-image person re-identification (TIPR) retrieves target persons using natural language descriptions. However, existing methods largely overlook resolution variance in real-world surveillance. They characterize cross-resolution TIPR through two coupled failure modes: Evidence Reliability Collapse (ERC), where degraded visual tokens become unreliable for grounding fine-grained text, and Ranking Distribution Drift (RDD), where mixed-resolution galleries distort similarity neighborhoods and destabilize retrieval rankings. To address this challenge, we propose Cross-Resolution Semantic Transfer (CRST), a CLIP-style framework with three modules: resolution-conditioned reasoning, text-guided refinement and CR-RDA. Resolution-conditioned reasoning estimates token reliability to suppress corrupted evidence. Text-guided refinement injects semantic priors to recover discriminative cues. CR-RDA transfers HR neighborhood geometry to stabilize LR ranking under mixed resolutions. Experiments on CUHK-PEDES, ICFG-PEDES, and RSTPReid show that CRST improves ultra-low-resolution Rank-1 and mAP on average by 5.7% and 5.3%, while stabilizing mixed-resolution retrieval without sacrificing high-resolution accuracy.The code will be made publicly available.","authors":["Wenjie Qian","Bin Yang","Xiao Wang","Wenke Huang","Ling Mei","Xin Xu","Mang Ye"],"published":"2026-06-29T15:24:03Z","updated":"2026-06-29T15:24:03Z","abstract_url":"https://arxiv.org/abs/2606.30458v1","html_url":"https://arxiv.org/html/2606.30458v1","pdf_url":"https://arxiv.org/pdf/2606.30458v1.pdf","matched_keywords":["retrieval"],"source_used":"html","source_text_chars":44381,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 retrieval 相关；摘要显示其主要贡献为：Text-to-image person re-identification (TIPR) retrieves target persons using natural language descriptions. However, existing methods largely overlook resolution variance in real-world surveillance. They characterize cross-resolution TIPR through two coupled...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-30T04:58:54+00:00","status":"fallback"},"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30456v1","title":"Vision-Language-Action Models: Experimental Insights from a Real-World UR5 Platform","abstract":"This project investigates whether recent Vision-Language-Action (VLA) models can be transferred from controlled research benchmarks to a real-world robotic platform, specifically a UR5e manipulator, in a reproducible and operationally meaningful manner. The work integrates real-robot data acquisition, dataset engineering (compatible with the RLDS format), and the fine-tuning and deployment of OpenVLA and OpenVLA-OFT models, with systematic validation of action representations and control interfaces. The project resulted in several foundational assets: (i) a complete real-robot data acquisition pipeline, (ii) a dataset conversion workflow aligned with RLDS standards, (iii) an initial fine-tuning and inference infrastructure for VLA models, and (iv) a structured set of experimental observations grounded in real-robot trials. These elements collectively establish a reproducible framework for evaluating learning-based manipulation systems beyond simulation. Empirically, the experiments reveal a consistent gap between promising offline indicators and unstable closed-loop behavior on the physical system: this gap cannot be attributed solely to model limitations, it is strongly influenced by action semantics, coordinate frame conventions, temporal alignment between modalities, image preprocessing consistency, and dataset coverage and quality. These observations lead to a key interpretation: the successful deployment of VLA systems in real-world settings depends less on incremental improvements in model capacity and more on precise control of the entire data-model-control pipeline. The project reframes VLA-based robotics from a primarily model-centric challenge to a system-level problem; it highlights the difficulty of running robust task execution on the real robot and provides a clear, experimentally grounded understanding of the conditions required for reliable deployment.","authors":["Mathilde Hochedel","Marc Lalonde"],"published":"2026-06-29T15:23:34Z","updated":"2026-06-29T15:23:34Z","abstract_url":"https://arxiv.org/abs/2606.30456v1","html_url":"https://arxiv.org/html/2606.30456v1","pdf_url":"https://arxiv.org/pdf/2606.30456v1.pdf","matched_keywords":["representation"],"source_used":"html","source_text_chars":87652,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation 相关；摘要显示其主要贡献为：This project investigates whether recent Vision-Language-Action (VLA) models can be transferred from controlled research benchmarks to a real-world robotic platform, specifically a UR5e manipulator, in a reproducible and operationally meaningful manner. The w...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-30T04:58:54+00:00","status":"fallback"},"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30436v1","title":"Robust and Efficient Monocular 3D Gaussian SLAM for Kilometer-Scale Outdoor Scenes","abstract":"Scaling monocular 3D Gaussian Splatting (3DGS) SLAM to kilometer-level outdoor environments poses two tightly coupled challenges: fragile long-term pose tracking and excessive memory overhead during large-scale mapping. In this paper, we propose KiloGS-SLAM, a highly efficient and robust monocular 3DGS-SLAM system that jointly addresses both bottlenecks. Since high-fidelity scene reconstruction fundamentally relies on drift-free camera poses, we first introduce a motion-adaptive hybrid tracking module. This module features a condition-triggered three-tier solving pipeline. It dynamically switches between Essential matrix and PnP models to handle geometric degeneracies. An on-demand foundation model can also be activated to rescue the trajectory from catastrophic drift. To ensure the system can sustain these long trajectories without memory exhaustion, we subsequently design a lifecycle-managed Gaussian mapping strategy. By integrating probabilistic initialization with chunk-based multi-view densification and pruning, this full-pipeline optimization effectively reduces primitive redundancy while preserving high-frequency details. Together, the robust tracking guarantees the geometric foundation required for accurate mapping, while the memory-efficient lifecycle-managed mapping enables large-scale operation. Extensive experiments across three challenging outdoor datasets demonstrate that our approach achieves state-of-the-art tracking accuracy and rendering quality, successfully scaling to sequences of over 10,000 frames on a single GPU.","authors":["Sicheng Yu","Dongxu Shen","Beizhen Zhao","Guanzhi Ding","Hao Wang"],"published":"2026-06-29T15:12:18Z","updated":"2026-06-29T15:12:18Z","abstract_url":"https://arxiv.org/abs/2606.30436v1","html_url":"https://arxiv.org/html/2606.30436v1","pdf_url":"https://arxiv.org/pdf/2606.30436v1.pdf","matched_keywords":["3d"],"source_used":"html","source_text_chars":75699,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d 相关；摘要显示其主要贡献为：Scaling monocular 3D Gaussian Splatting (3DGS) SLAM to kilometer-level outdoor environments poses two tightly coupled challenges: fragile long-term pose tracking and excessive memory overhead during large-scale mapping. In this paper, we propose KiloGS-SLAM,...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-30T04:58:54+00:00","status":"fallback"},"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30421v1","title":"OWMDrive: Causality-Aware End-to-End Autonomous Driving via 4D Occupancy World Model","abstract":"Autonomous driving systems are steadily moving toward end-to-end paradigms to mitigate the limited adaptability of rule-based pipelines in complex traffic environments. However, most existing learning-based methods still make decisions from static representations of the current scene, without explicit future rollouts or modeling of the temporal causal dynamics in traffic interactions. This limitation often results in unstable or overly conservative planning under high-uncertainty conditions, such as occlusions and unexpected events. To overcome these challenges, we introduce OWMDrive, a generative end-to-end driving framework built upon an Occupancy World Model for multi-step 3D occupancy forecasting, which serves as a conditional prior to guide diffusion-based planning. Conditioned on both current observations and predicted future states, the planner iteratively refines trajectory candidates to generate a reinforced driving trajectory. By explicitly modeling scene evolution over future horizons, OWMDrive captures key spatiotemporal causal dependencies, which leads to more foresighted and robust trajectory generation. Extensive experiments demonstrate that OWMDrive significantly improves planning reliability and safety, especially in challenging and partially observable driving scenarios.","authors":["Junjie Cheng","Ruiqi Song","Ye Wu","Nanxing Zeng","Ximiao Li","Yunfeng Ai"],"published":"2026-06-29T15:05:41Z","updated":"2026-06-29T15:05:41Z","abstract_url":"https://arxiv.org/abs/2606.30421v1","html_url":"https://arxiv.org/html/2606.30421v1","pdf_url":"https://arxiv.org/pdf/2606.30421v1.pdf","matched_keywords":["3d","representation","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30417v1","title":"Beyond Point Estimates for Glaucoma Visual Field Forecasting with Diffusion Models","abstract":"Forecasting visual fields (VFs) is critical for personalized monitoring and treatment planning in glaucoma. This is inherently uncertain due to heterogeneous disease progression and measurement variability, yet most existing methods produce single deterministic predictions that fail to represent this uncertainty. We formulate VF forecasting as a probabilistic prediction problem and the use of conditioned denoising diffusion models to generate distributions of plausible future VFs from longitudinal observations with irregular follow-up intervals. Experiments on two independent VF cohorts show that diffusion-based predictions produce well-calibrated distributions for clinically relevant VF measures. When reduced to a standard point-estimate, the proposed approach achieves state-of-the-art accuracy compared to clinical baselines and prior learning-based methods. Our results highlight the advantages of distributional modeling for VF forecasting and support a shift from point-estimate prediction toward uncertainty-aware, clinically interpretable risk assessment in glaucoma.","authors":["Marta Colmenar Herrera","Pablo Márquez Neila","Şerife Seda Kucur Ergünay","Martin S. Zinkernagel","Raphael Sznitman"],"published":"2026-06-29T15:04:50Z","updated":"2026-06-29T15:04:50Z","abstract_url":"https://arxiv.org/abs/2606.30417v1","html_url":"https://arxiv.org/html/2606.30417v1","pdf_url":"https://arxiv.org/pdf/2606.30417v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30408v1","title":"SA-Homo: Scale Adaptive Homography Estimation for Scale Variation Scenarios","abstract":"Homography estimation, as one of the fundamental problems in computer vision, remains challenged by scale variation scenarios where image pairs potentially exhibit significant scale discrepancies. Existing deep learning frameworks frequently suffer from a significant performance degradation in such cases, as they rely on limited displacement assumptions and local feature consistency that might not hold under large scale gaps. In this paper, we propose SA-Homo, a novel scale-adaptive homography estimation framework designed to achieve robust alignment across a wide range of scale discrepancy ratios. We adopt a hierarchical scale alignment strategy that transitions from the global perspective with a heavy module to a local perspective with a light module. Specifically, we introduce the Scale-aware Discrepancy Bridging Module (SDBM) for initial alignment, which utilizes a Multi-scale Linear Attention Cascade (MLAC) to capture long-range dependencies and mitigate feature inconsistencies, along with a global Cross-scale Similarity Matrix Block (CSMB) for scale robust correlation representation. Once the initial scale gap is bridged, a lightweight Iterative Homography Estimation Refinement Module (IHERM) progressively polishes the result using local correlations. To facilitate this research, we contribute the HMSA dataset, a high-resolution, multi-modal satellite benchmark specifically tailored for scale-variant challenges. Extensive experiments demonstrate that SA-Homo maintains high precision even under 8$\\times$ scale discrepancies, outperforming state-of-the-art methods in both conventional scale-similar scenarios and challenging scale variation scenarios. Code and collected datasets are available at https://github.com/shangxuanx330/SA_Homo","authors":["Shangxuan Xie","Haifeng Wu","Yuhang Wang","Huarong Jia","Wen Li"],"published":"2026-06-29T14:51:53Z","updated":"2026-06-29T14:51:53Z","abstract_url":"https://arxiv.org/abs/2606.30408v1","html_url":"https://arxiv.org/html/2606.30408v1","pdf_url":"https://arxiv.org/pdf/2606.30408v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30393v1","title":"SADL: What to Ignore? A Benchmark for Subject-Aware Distractor Localization","abstract":"Photographs frequently contain \\emph{visual distractors} besides foregrounds and backgrounds of the intended subject, competing for attention and weakening composition. While modern editing tools streamline object removal, identifying which objects to remove remains a mostly manual process. Existing saliency models and open-vocabulary detectors operate without subject awareness, failing to adapt to shifting user intent. Furthermore, context-agnostic removal may disrupt the scene's semantic coherence (e.g., keep the person but remove the chair they are sitting on). To address these limitations, we formalize the task of subject-aware distractor localization, which identifies distractors while retaining compositionally essential objects. This paper introduces \\textsc{SADL}, the first real-world benchmark for this task, comprising 1,800 subject-aware cases across 1,000 photographs to enable systematic evaluation and facilitate future research. In total, there are 14,617 annotated candidates, including a robust set of 1,938 hard negatives to stress-test exclusion calibration. We evaluate seven proprietary and open-weight Vision-Language Models (VLMs) on a sequential pipeline of distractor classification followed by exclusion filtering, structured around five inclusion factors and three contextual exclusion rules. Our analysis reveals that VLMs are highly capable of identifying distractors, but then over-apply exclusion, which systematically suppresses true distractors at scale. By exposing this critical bottleneck, \\textsc{SADL} provides a foundational diagnostic tool to advance subject-conditioned reasoning in multimodal systems.","authors":["Cao-Tri Nguyen","Nguyen-Khoa Luong","Vinh-Tiep Nguyen","Minh-Triet Tran"],"published":"2026-06-29T14:45:38Z","updated":"2026-06-29T14:45:38Z","abstract_url":"https://arxiv.org/abs/2606.30393v1","html_url":"https://arxiv.org/html/2606.30393v1","pdf_url":"https://arxiv.org/pdf/2606.30393v1.pdf","matched_keywords":["multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30378v1","title":"OmniCoT: A Benchmark for Global and Multi-Step Panoramic Reasoning","abstract":"Multimodal Large Language Models (MLLMs) have demonstrated promising spatial reasoning capabilities, while these abilities remain underexplored in the emerging visual modality of panoramic imagery. The full 360°$\\times$180° field of view of panoramas essentially supports complex global multi-step reasoning, which is also the fundamental advantage of panoramas in applications such as embodied intelligence. However, existing panoramic benchmarks largely focus on simplistic queries that rely on local cues or single-/few-step reasoning, thereby ignoring the fundamental advantage of panoramas and failing to fully exploit their potential. To address this gap, we introduce OmniCoT, a panoramic spatial reasoning suite designed to enable MLLMs to use global evidence and perform multi-step inference across viewpoints. It includes OmniCoT-B (6.7K data) for evaluation, which measures both answer accuracy and reasoning quality, OmniCoT-Real (1K data) as a manually annotated real-world subset to quantify the Sim-to-Real gap. For training, OmniCoT-T (14.3K data) is purpose-built with structured stepwise Chain-of-Thought annotations that explicitly link intermediate reasoning steps to panoramic evidence. Based on OmniCoT-T, we introduce OmniCoT-R1 and adopt a two-stage training strategy tailored to the geometrically complex panoramic space, where Supervised Fine-tuning (SFT) anchors reasoning to panoramic evidence (e.g., bearings, proximity) and GRPO penalizes geometrically incoherent paths to consolidate global 360° spatial consistency. Through OmniCoT, we aim to recalibrate the difficulty of panoramic spatial reasoning to better align with the intrinsic capabilities of panoramic imagery, thereby fostering meaningful progress in this research area.","authors":["Haocong He","Chenfei Liao","Zichen Wen","Zihao Dongfang","Xu Zheng","Bin Ren","Chang Su","Zixin Zhang","Harold Haodong Chen","Hongfei Zhang","Weijia Li","Kailun Yang","Conghui He","Xuming Hu","Nicu Sebe","Linfeng Zhang"],"published":"2026-06-29T14:38:20Z","updated":"2026-06-29T14:38:20Z","abstract_url":"https://arxiv.org/abs/2606.30378v1","html_url":"https://arxiv.org/html/2606.30378v1","pdf_url":"https://arxiv.org/pdf/2606.30378v1.pdf","matched_keywords":["multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30376v1","title":"FlowAWR: Online Adaptive Flow Reinforcement via Advantage-Weighted Rectification","abstract":"Aligning generative flow models on continuous spaces via online reinforcement learning is constrained by intractable trajectory likelihoods. Existing density-approximated policy gradient methods rely on stochastic SDE samplers to construct tractable transition kernels, which introduce training-inference inconsistencies and necessitates Classifier-Free Guidance (CFG). While implicit frameworks such as DiffusionNFT directly optimize forward-process velocity fields, its heuristic fixed-magnitude corrections prevent optimization strength from relative intra-group quality. We propose \\textit{Flow Advantage-Weighted Rectification} (\\textbf{FlowAWR}), a paradigm that recasts continuous generative policy optimization as supervised regression toward a theoretically optimal velocity field. Starting from the optimal policy of a KL-constrained reward maximization, FlowAWR derives the optimal velocity field that admits a magnitude-aware, advantage-weighted rectification form, yielding SDE-free optimization and CFG-free generation. In comparative evaluations on SD3.5-Medium, FlowAWR achieves improved alignment performance alongside a 2$\\times$ to 5$\\times$ convergence acceleration over DiffusionNFT (e.g., reaching a 24.12 PickScore in 1.2k steps, versus 23.82 in 2.0k steps for DiffusionNFT and 23.50 in $>$4k steps for FlowGRPO). Under multi-reward constraints, FlowAWR sustains generation quality, satisfying structural rules while maintaining stable out-of-domain performance.","authors":["Zheming Fu","Ruizhe He","Wei Shang","Xiaoxiao Ma","Lei Wang","Chang Liu","Siming Fu"],"published":"2026-06-29T14:37:36Z","updated":"2026-06-29T14:37:36Z","abstract_url":"https://arxiv.org/abs/2606.30376v1","html_url":"https://arxiv.org/html/2606.30376v1","pdf_url":"https://arxiv.org/pdf/2606.30376v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30374v1","title":"Set-Inclusive Uncertainty Modeling for Robust Brain Tumor Segmentation","abstract":"Multimodal MRI is essential for accurate brain tumor segmentation. However, acquiring all modalities at inference is often challenging in practice, which causes intrinsic uncertainty due to unavoidable information loss. Without modeling this uncertainty, existing methods encode incomplete evidence into deterministic representations that appear plausible but lack reliability. In this regime, we propose a probabilistic representation framework that models representations as Gaussian distributions, where their mean captures task information and their variance measures uncertainty from missing evidence. To make variance reflect information deficiency, we regularize the mean from each partial configuration toward its full-modality counterpart, while scaling the variance with the discrepancy between their aligned means. We further introduce a set-inclusive strategy that exploits the hierarchical structure of modality subsets and enforces an ordering constraint to maintain their consistent uncertainty relationships. Extensive experiments on BraTS 2018 and 2020 demonstrate that our approach offers superior performance over baselines across diverse missing-modality scenarios. Code and model checkpoint are available at https://github.com/atlas-sky/SIUM.","authors":["Seunghun Baek","Jihwan Park","Jaeyoon Sim","Hoseok Lee","Seungjoo Lee","Won Hwa Kim"],"published":"2026-06-29T14:35:55Z","updated":"2026-06-29T14:35:55Z","abstract_url":"https://arxiv.org/abs/2606.30374v1","html_url":"https://arxiv.org/html/2606.30374v1","pdf_url":"https://arxiv.org/pdf/2606.30374v1.pdf","matched_keywords":["representation","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30370v1","title":"MUSE: Unlocking Timestep as Native Task Steering for One-Step Dense Prediction","abstract":"Monocular dense prediction has recently seen remarkable success by repurposing pre-trained diffusion models. This opens a promising yet challenging avenue for more efficient multi-task learning paradigm. However, existing multi-task diffusion methods often introduce parameter-heavy adapters, experts, or learnable task tokens, leading to computational redundancy. In this paper, we reveal an inherent mechanism within one-step diffusion models: the native, fixed sinusoidal timestep embedding can be repurposed as an endogenous task steering signal. Based on this discovery, we propose Multi-task Unified eStimation via timestep Embedding (MUSE), a parameter-free, single-model multi-tasking approach for dense prediction. We interpret this mechanism via Manifold Decoupling, where discrete, fixed timestep values deterministically steer the generation process towards decoupled, task-specific manifolds in the latent space. Extensive experiments across 10 datasets demonstrate that MUSE achieves highly competitive performance on both monocular depth and normal estimation, and its efficacy generalizes across U-Net and DiT architectures. Our work offers a concise and efficient path toward generalist vision models by simply unlocking the latent potential of existing generation infrastructure.","authors":["Shuo Zhou","Zhaoxin Li","Xiujuan Chai"],"published":"2026-06-29T14:34:16Z","updated":"2026-06-29T14:34:16Z","abstract_url":"https://arxiv.org/abs/2606.30370v1","html_url":"https://arxiv.org/html/2606.30370v1","pdf_url":"https://arxiv.org/pdf/2606.30370v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30355v1","title":"Residual-Guided Expert Specialization for Incomplete Multimodal Learning","abstract":"As real-world prediction systems often face missing modalities at inference, incomplete multimodal learning (IML) remains a practical challenge. While prior methods aim to learn representations robust to missing inputs, representations from incomplete modalities inevitably deviate from their full-modality counterparts due to missing evidence. To explicitly leverage these deviations, we propose MARS (Missingness-Aware Residual-guided Specialization), a mixture-of-experts framework that guides expert specialization based on how representations are reshaped by missingness. By contrasting task representations derived from incomplete inputs with their complete counterparts during training, we derive a privileged residual signal that captures this representational gap. The residual signal guides a residual router to assign samples to experts specialized for the corresponding deviation patterns. In parallel, a feature router learns to imitate this routing behavior using only incomplete inputs, enabling deployment without access to full modalities. To mitigate this train-test router gap, we develop a discrepancy-aware noise regularization that adaptively perturbs the residual router's decisions when the feature router deviates, enhancing expert robustness under imperfect imitation. Experiments on multimodal classification (CASIA-SURF, CREMA-D, UPMC Food-101) and segmentation (MCubeS) under missing scenarios show that MARS consistently surpasses baselines while remaining efficient and extensible to diverse backbones and tasks.","authors":["Seunghun Baek","Jihwan Park","Jaeyoon Sim","Minjae Jeong","Hoseok Lee","Won Hwa Kim"],"published":"2026-06-29T14:24:05Z","updated":"2026-06-29T14:24:05Z","abstract_url":"https://arxiv.org/abs/2606.30355v1","html_url":"https://arxiv.org/html/2606.30355v1","pdf_url":"https://arxiv.org/pdf/2606.30355v1.pdf","matched_keywords":["representation","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30352v1","title":"FastPano3D: Feed-Forward Indoor Panoramic 3D Reconstruction from a Single Image","abstract":"Recent advances in 3D scene reconstruction have highlighted the intricate trade-offs among rendering quality, inference efficiency, and data dependency. To address the challenge of rapidly reconstructing detailed 3D indoor scenes from minimal input, we introduce FastPano3D, an end-to-end framework that directly generates renderable 3D Gaussian representations from a single panoramic image. Unlike perspective-based methods, panoramic images inherently suffer from equirectangular projection distortions and spatially non-uniform feature distributions, making direct feed-forward Gaussian generation particularly challenging. In contrast to existing Gaussian Splatting based methods that rely on multi-view supervision or per-scene optimization, FastPano3D employs a lightweight feature encoder, adaptive Gaussian sampling, and a point-cloud-guided refinement strategy to achieve efficient and accurate scene generation without any test-time optimization. Our approach reconstructs high-fidelity 3D scenes within seconds, achieving up to 156 times faster inference than prior state-of-the-art methods such as Pano2Room, while using only half the parameters. Extensive experiments demonstrate that FastPano3D delivers rendering quality comparable to NeRF- and 3DGS-based reconstructions, establishing a new benchmark for rapid, single-view 3D scene inference.","authors":["Jianqiang Li","Liumei Zhang","Wenjia Guo","Tianlong Feng","Yongzhi Liao","Di Lu","Hanchi Ren","Jingjing Deng"],"published":"2026-06-29T14:23:12Z","updated":"2026-06-29T14:23:12Z","abstract_url":"https://arxiv.org/abs/2606.30352v1","html_url":"https://arxiv.org/html/2606.30352v1","pdf_url":"https://arxiv.org/pdf/2606.30352v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30347v1","title":"FFAvatar: Feed-Forward 4D Head Avatar Reconstruction from Sparse Portrait Images","abstract":"We present FFAvatar, a Transformer-based 3D Gaussian framework for fast construction of high-quality and animatable 4D head avatars from one or more reference portrait images. Unlike existing feed-forward approaches that require a fixed number of input views, FFAvatar supports incremental reconstruction, progressively refining the avatar representation as additional reference images become available. At the core of our method is an alternating attention mechanism that disentangles identity appearance from expression and viewpoint variations, enabling the reconstruction of a canonical 3D appearance that remains consistent across poses and facial expressions. To balance visual fidelity and computational efficiency, we introduce a sparse-to-dense learning paradigm. Coarse appearance features are first learned using sparse primitives anchored to the FLAME vertex level and are subsequently densified in the UV domain to capture fine-grained geometric and texture details. We further propose a plug-and-play motion refinement module that enables subject-specific dynamic personalization by modeling residual motion beyond parametric deformation. Extensive experiments demonstrate that FFAvatar efficiently produces high-fidelity and controllable 4D head avatars, achieving superior flexibility, driving efficiency, and identity-consistent rendering across diverse expressions and viewpoints.","authors":["Jianjiang Yao","Ke Xian","Renxiang Dai","Robert Caiming Qiu"],"published":"2026-06-29T14:21:33Z","updated":"2026-06-29T14:21:33Z","abstract_url":"https://arxiv.org/abs/2606.30347v1","html_url":"https://arxiv.org/html/2606.30347v1","pdf_url":"https://arxiv.org/pdf/2606.30347v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30344v1","title":"Early Cue Precision Shapes Visual Shortcut Learning in Controlled Cue-Manipulation Benchmarks","abstract":"Visual classifiers can achieve high matched-distribution accuracy while relying on low-level cues that fail under conflict or suppression. We test whether this failure is shaped by early cue precision: the reliability with which a low-level cue predicts the label during early learning or downstream probe fitting. Across synthetic shape-texture tasks, sequential digit training, a 10-class frozen-representation audit, and a CIFAR-10 natural-image-based texture-overlay benchmark, we manipulate object-texture match probability and evaluate matched-ID accuracy, conflict accuracy, texture-choice rate, and suppression behavior. Degraded-but-predictive input does not substitute for cue decorrelation. In 10-class digit probes, conflict accuracy drops from 0.589 under chance-like cue precision to 0.005 under target-perfect texture. In CIFAR-10 frozen probes, conflict accuracy drops from 0.569 to 0.114, while texture choice rises from 0.049 to 0.855; this ordering persists across texture-overlay strengths alpha in {0.15,0.25,0.35,0.50}. End-to-end CIFAR-10 training shows that low early cue precision improves pre-target conflict behavior, but shortcut-rich fine-tuning can rapidly overwrite this benefit. Cue decorrelation must therefore be maintained during downstream adaptation rather than treated as a one-time inoculation.","authors":["Chanho Park","Woochan Lee","Janyeong Oh","Geongho Gong","Minshu Kim","Yeachan Kwak","Seongim Choi"],"published":"2026-06-29T14:20:30Z","updated":"2026-06-29T14:20:30Z","abstract_url":"https://arxiv.org/abs/2606.30344v1","html_url":"https://arxiv.org/html/2606.30344v1","pdf_url":"https://arxiv.org/pdf/2606.30344v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30332v1","title":"UniGP: Taming Diffusion Transformer for Prior-Preserved Unified Generation and Perception","abstract":"Recent advances in diffusion models have shown impressive performance in controllable image generation and dense prediction tasks. However, existing approaches typically treat diffusion-based controllable generation and dense prediction as separate tasks, overlooking the potential benefits of jointly modeling the heterogeneous distributions. In this work, we introduce UniGP, a framework built upon MMDiT, which unifies controllable generation and dense prediction through simple joint training, without the need for complex task-specific designs or losses, while preserving the backbone's versatile priors. By learning controllable generation and prediction under different conditions, our model effectively captures the joint distribution of image-geometry pairs. UniGP is capable of versatile controllable generation, dense prediction, and joint generation. Specifically, the proposed UniGP consists of DUGP and a unified dataset training strategy. The former, following the principle of Occam's razor, uses only a copied image branch of MMDiT to model dense distributions beyond RGB, while the latter integrates heterogeneous datasets into a unified training framework to jointly model generation and perception tasks. Extensive experiments demonstrate that our unified model surpasses prior unified approaches and performs on par with specialized methods. Furthermore, we demonstrate that multi-task joint training provides complementary benefits: generative priors enrich perceptual details, while perceptual learning improves structural alignment in generation.","authors":["Qin Guo","Hao Luo","Dongxu Yue","Weixuan Jin","Xiao Fu","Fan Wang","Dan Xu"],"published":"2026-06-29T14:13:27Z","updated":"2026-06-29T14:13:27Z","abstract_url":"https://arxiv.org/abs/2606.30332v1","html_url":"https://arxiv.org/html/2606.30332v1","pdf_url":"https://arxiv.org/pdf/2606.30332v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30319v1","title":"BrainJanus: A Unified Model for Understanding and Generation across Brain, Vision, and Language","abstract":"Modeling the bidirectional correspondence between external sensory stimuli and internal neural activity has emerged as a critical frontier in neuroscience. However, existing approaches predominantly treat brain encoding and decoding as isolated tasks, relying heavily on unimodal alignment and external priors while overlooking the brain's intrinsic nature as a multimodal integration system. To address these limitations, we propose BrainJanus, the first unified brain model that integrates brain, vision, and language within a single framework. Specifically, we introduce a Unified Brain Tokenizer to quantize continuous neural dynamics into discrete tokens aligned with visual and linguistic representations in a shared Omni space. Building on this, we utilize an All-in-One autoregressive architecture that leverages next-token prediction to enable seamless any-to-any generation, which encompasses image-to-brain and text-to-brain encoding, and brain-to-image and brain-to-text decoding. Extensive experiments demonstrate that BrainJanus achieves superior performance across diverse benchmarks. Furthermore, our framework exhibits zero-shot generalization and preserves interpretable biological topography, highlighting its potential as a general-purpose brain modeling paradigm. The code is available at \\href{https://github.com/HaitaoWuTJU/BrainJanus}{GitHub}.","authors":["Haitao Wu","Qirui Zhang","Zhouheng Yao","Shangquan Sun","Qihao Zheng","Mianxin Liu","Chi Zhang","Wanli Ouyang","Chunfeng Song","Changqing Zhang","Jiamin Wu"],"published":"2026-06-29T14:02:15Z","updated":"2026-06-29T14:02:15Z","abstract_url":"https://arxiv.org/abs/2606.30319v1","html_url":"https://arxiv.org/html/2606.30319v1","pdf_url":"https://arxiv.org/pdf/2606.30319v1.pdf","matched_keywords":["representation","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30313v1","title":"TRACE: A Concept Bottleneck Model for Longitudinal 3D Glioblastoma Response Assessment","abstract":"Longitudinal glioblastoma response assessment requires comparing subtle tumor changes across MRI time points using structured clinical criteria such as RANO. However, most deep learning methods predict response labels directly from imaging features, which limits clinical inspection, verification, and correction. We introduce TRACE, a RANO 2.0-aligned concept bottleneck model for interpretable 4-class glioblastoma response classification on longitudinal 3D MRI. TRACE processes paired baseline and follow-up multimodal MRI scans with a shared 3D vision encoder, predicts clinically meaningful tumor measurements as root concepts, computes downstream RANO-derived concepts through deterministic rules, and incorporates scan interval and new-lesion information as passthrough concepts. This design frames response assessment as structured concept reasoning rather than direct image-to-label prediction. Using 5-fold patient-wise cross-validation on the LUMIERE dataset, TRACE achieves a 4-class macro F1 of 0.4769 and a binary progression-versus-non-progression macro F1 of 0.7085. It improves over a concept bottleneck baseline and remains within the range of published non-interpretable deep learning approaches. Ablation studies show that the expert RANO graph and intervention-consistency training are important for performance, while intervention experiments demonstrate that correcting concepts can improve downstream predictions. These results suggest that structured concept bottlenecks offer a transparent and clinically aligned direction for longitudinal glioblastoma response assessment, while highlighting the need for larger protocol-aligned datasets and external validation.","authors":["Alia Tarek","Hamsa Saberr","Hamza Elghonemy","Youssef Afify","Tamer Basha","Omair Shahzad Bhatti","Abdulrahman M. Selim","Hasan Md Tusfiqur Alam Daniel Sonntag"],"published":"2026-06-29T13:56:17Z","updated":"2026-06-29T13:56:17Z","abstract_url":"https://arxiv.org/abs/2606.30313v1","html_url":"https://arxiv.org/html/2606.30313v1","pdf_url":"https://arxiv.org/pdf/2606.30313v1.pdf","matched_keywords":["3d","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30308v1","title":"The Surprising Effectiveness of Video Diffusion Models for Hand Motion Reconstruction","abstract":"4D hand motion reconstruction from egocentric video is bottlenecked by clear limitations of existing methods: image-based pipelines depend on a detector that fails under heavy occlusion, while video-based methods rely on temporal modules learned only from scarce hand-pose annotations, a narrow signal insufficient to model motion dynamics, occlusion reasoning, and hand-object interaction. These capabilities, however, are exactly what video generative models must implicitly acquire when trained to synthesize coherent video at internet scale. Motivated by this, we present ViDiHand, which leverages the representations of a pretrained video diffusion model to reconstruct 4D two-hand pose. We adapt it via a hand-overlay rendering objective that specializes its features for hands while preserving its world priors. A decoder then recovers metric-scale pose from the adapted features. The whole pipeline operates directly on full frames--no detector, no infiller, and no test-time optimization. On ARCTIC, HOT3D, and HOI4D, ViDiHand substantially outperforms prior methods, establishing video diffusion models as a powerful new foundation for hand motion reconstruction and a promising route to scalable in-the-wild data collection for embodied AI. Project page: https://vidihand.github.io.","authors":["Yuxi Wang","Chengkai Jin","Yufei Liu","Wenqi Ouyang","Tianyi Wei","Zhiwei Zeng","Siyuan Huang","Zhiqi Shen","Xingang Pan"],"published":"2026-06-29T13:53:00Z","updated":"2026-06-29T13:53:00Z","abstract_url":"https://arxiv.org/abs/2606.30308v1","html_url":"https://arxiv.org/html/2606.30308v1","pdf_url":"https://arxiv.org/pdf/2606.30308v1.pdf","matched_keywords":["video","3d","representation","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30292v1","title":"DreamForge-World 0.1 Preview: A Low-Compute Real-Time Controllable World Model","abstract":"We present DreamForge-World 0.1 Preview, a preview foundational world model for real-time interactive world simulation. The system adapts the LongLive 1 autoregressive video stack, itself derived from Wan2.1-T2V-1.3B, with a residual action pathway inspired by the Matrix-Game family. DreamForge-World 0.1 Preview focuses on a complementary axis to frontier-scale world simulators: low-compute adaptation, consumer-GPU runtime, and broad interactive capability coverage. It supports live keyboard and mouse control, multimodal initialization, mid-stream reprompting, dual-view operation, and minute-scale interactive rollouts at native 480p resolution, reaching up to 14 to 15 FPS FPS on a single RTX 4090 with a low memory footprint. By leveraging open video backbones and applying targeted adaptation runs, we build the preview system with high cost-efficiency. DF-World 0.1 Preview is not yet a memory-complete or frontier-quality world simulator, but demonstrates a practical low-compute route toward real-time controllable world-model previews on consumer GPUs.","authors":["Daniyel Ayupov","Artur Markov-Tsoy"],"published":"2026-06-29T13:35:44Z","updated":"2026-06-29T13:35:44Z","abstract_url":"https://arxiv.org/abs/2606.30292v1","html_url":"https://arxiv.org/html/2606.30292v1","pdf_url":"https://arxiv.org/pdf/2606.30292v1.pdf","matched_keywords":["video","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30288v1","title":"VisReflect: Latent Visual Reflection for Fine-Grained Perception in Long Visual Context","abstract":"Large Vision Language Models (LVLMs) have achieved remarkable success on vision-language tasks, yet fine-grained perception over high-resolution images and long-context videos remains challenging. As the number of visual tokens increases, the visual attention sink phenomenon becomes increasingly severe, causing irrelevant tokens to absorb a disproportionate amount of attention mass. Recent approaches attempt to mitigate this issue by explicitly predicting bounding boxes or temporal spans and re-encoding the cropped visual regions. Such methods depend on unreliable numeric localization in the discrete token space and incur significant computational overhead due to additional forward passes. In this work, we propose **VisReflect**, a simple yet effective framework that improves fine-grained perception in long visual contexts through latent visual reflection. Instead of decoding intermediate predictions into discrete tokens, the model generates continuous visual reflection that represents question-relevant visual features in the latent space. These reflections selectively emphasize salient regions or frames, guiding attention towards relevant visual tokens within a single forward pass. We conduct comprehensive evaluations on challenging high-resolution image benchmarks, including BLINK, V*, and HRBench-4K/8K, as well as video understanding benchmarks such as MVBench, VideoMME, and MLVU. Our method consistently improves over strong baselines, achieving gains of 4.1% on image benchmarks and 1.8% on video benchmarks. Compared with zooming-based methods, our model achieves comparable performance while reducing inference time by roughly 44% on video understanding.","authors":["Xiaoqian Shen","Mohamed Elhoseiny"],"published":"2026-06-29T13:30:17Z","updated":"2026-06-29T13:30:17Z","abstract_url":"https://arxiv.org/abs/2606.30288v1","html_url":"https://arxiv.org/html/2606.30288v1","pdf_url":"https://arxiv.org/pdf/2606.30288v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30262v1","title":"Intermediate Text Representation Guided Text-to-Image Generation for Enhancing One-and-Only Alignment","abstract":"Text-to-image (T2I) diffusion models often fail to faithfully render explicit textual descriptions, instead defaulting to strongly learned visual priors due to a phenomenon referred to as concept association bias. We show that such bias is particularly strong for one-and-only (OAO) objects, entities that exist in a single canonical form, such as celestial bodies, landmarks, and artworks. The deeply ingrained visual identity for these concepts often resists modification through prompting alone. Addressing this challenge, we first identify through an information-theoretic analysis that the final text embedding discards concept-level information present in the intermediate-layer text representations, reducing the mutual information available to the subsequent denoising process. We then propose Intermediate Text Representation (IR)-guided diffusion, which injects intermediate hidden states of the text encoder into the conditioning signal during early denoising steps, recovering suppressed concepts without any additional training, optimization, or external models. To systematically evaluate the challenging task of aligning generative outputs with unusual prompts for OAO objects, we introduce OAO-AttackBench, a benchmark comprising counterfactual prompts that directly conflict with the core visual identity of OAO objects. Experiments on four benchmarks, including OAO-AttackBench, show that our method achieves up to a 19.1 percentage-point improvement in VQAScore while preserving generation fidelity and human preference. Project page: https://soyoun-won.github.io/one-and-only-ir-guidance/.","authors":["Soyoun Won","Aryan Yazdan Parast","Basim Azam","Jean Honorio","Naveed Akhtar"],"published":"2026-06-29T13:09:39Z","updated":"2026-06-29T13:09:39Z","abstract_url":"https://arxiv.org/abs/2606.30262v1","html_url":"https://arxiv.org/html/2606.30262v1","pdf_url":"https://arxiv.org/pdf/2606.30262v1.pdf","matched_keywords":["representation","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30248v1","title":"Your Data Manifold is Secretly a Reward Model: Shell-LCC for Text-to-Video Generation","abstract":"Recent text-to-video (T2V) diffusion models rely heavily on auxiliary reward signals (e.g., via reward models or DPO) to align generated content with human aesthetics and improve realism. These signals, however, incur substantial computational overhead, require costly human annotations, and often yield limited improvement in fine-grained local details. In this paper, we argue that your data manifold is secretly a reward model. By explicitly modeling the manifold structure of high-quality Supervised Fine-Tuning (SFT) data and encouraging video latents to lie on this manifold, we derive dense, differentiable, and nearly cost-free reward signals that significantly improve video quality, particularly in mitigating low-level distortions. Our modeling builds upon Local Coordinate Coding (LCC), which captures the `skeleton' of the manifold. However, directly applying LCC suffers from mean regression, pulling latents toward the geometric mean and losing high-frequency details. We therefore extend it to Shell Local Coordinate Coding (Shell-LCC), which models the manifold `surface' as an isotropic shell to align with the true high-density region. Experiments demonstrate that our approach improves realism, enhances high-frequency details, reduces over-smoothing artifacts, and alleviates motion blur.","authors":["Shihao Zhang","Yuguang Yan","Junzhe Zhang","Wei Zhao","Bohan Wang","Hanwang Zhang"],"published":"2026-06-29T12:57:34Z","updated":"2026-06-29T12:57:34Z","abstract_url":"https://arxiv.org/abs/2606.30248v1","html_url":"https://arxiv.org/html/2606.30248v1","pdf_url":"https://arxiv.org/pdf/2606.30248v1.pdf","matched_keywords":["video","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30244v1","title":"Semantic-Driven Scale and Spatial Selection for Efficient Cross-Modal Alignment in Referring Remote Sensing Image Segmentation","abstract":"Referring Remote Sensing Image Segmentation (RRSIS) seeks to localize and segment the target object or region specified by a natural language expression in a remote sensing image. While existing RRSIS models have benefited from large-scale foundation models, they predominantly rely on full fine-tuning. These approaches are computationally intensive and may weaken the generalization ability of pre-trained models, as extensive fine-tuning on significantly smaller downstream datasets can distort the well-structured feature representations learned during large-scale pre-training. Although Parameter-Efficient Tuning (PET) offers a potential alternative, existing PET frameworks primarily focus on single-modal optimization, failing to capture the complex cross-modal dependencies required for multimodal reasoning, while simultaneously struggling to bridge the substantial domain gap between natural scenes and aerial imagery. To address these limitations, we propose a novel framework, Semantic-driven Scale and Spatial Selection for Efficient Cross-modal Alignment (S4ECA), which enables effective and efficient cross-modal interaction through parameter-efficient adaptation. Specifically, we design a dual-encoder adapter architecture. The textual adapter employs learnable queries to distill highly semantic language proxies from word-level embeddings, facilitating early grounding. Simultaneously, the visual adapter refines hierarchical feature representations through a multi-scale dense extractor, followed by a language-guided scale and spatial selection mechanism that dynamically emphasizes relevant visual contexts, ensuring precise cross-modal alignment. By updating only 2.4% of the backbone parameters, our proposed model achieves state-of-the-art performance on the RRSIS-D and RefSegRS datasets, demonstrating superior efficiency and precision in complex aerial scenarios.","authors":["Kun Li","Shengxi Gui","Francesco Nex","Michael Ying Yang"],"published":"2026-06-29T12:54:10Z","updated":"2026-06-29T12:54:10Z","abstract_url":"https://arxiv.org/abs/2606.30244v1","html_url":"https://arxiv.org/html/2606.30244v1","pdf_url":"https://arxiv.org/pdf/2606.30244v1.pdf","matched_keywords":["representation","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30220v1","title":"From Accuracy to Visual Dependence: Auditing and Filtering Modality Collapse in Traffic VideoQA","abstract":"High benchmark accuracy does not guarantee genuine use of visual evidence. We study this problem in traffic accident Video Question Answering (VideoQA), where correct answers should depend on scene-specific visual evidence but may instead be inferred from textual shortcuts. Through an audit of four public benchmarks, we find that several recent open-weight Vision-Language Models (VLMs) perform competitively, and sometimes better, without video input. On the MM-AU benchmark, removing video consistently improves accuracy, and adding more frames further degrades performance. To quantify visual dependence, we introduce two dataset-level diagnostics: Blind Gap, measuring above-chance text-only performance, and Visual Gain, measuring the marginal benefit of adding video. We further propose an instance-level Shortcut Score that combines text-only confidence with visual necessity signals, enabling continuous, training-free filtering of shortcut-prone questions. The resulting subsets reduce shortcut bias and improve visual grounding. Our findings reveal large differences in grounding quality across benchmarks and show that visually grounded evaluation, not just high accuracy, is essential in safety-critical VideoQA.","authors":["Sena Korkut","María Alejandra Bravo Sarmiento","Sanghwan Kim","Zeynep Akata"],"published":"2026-06-29T12:33:15Z","updated":"2026-06-29T12:33:15Z","abstract_url":"https://arxiv.org/abs/2606.30220v1","html_url":"https://arxiv.org/html/2606.30220v1","pdf_url":"https://arxiv.org/pdf/2606.30220v1.pdf","matched_keywords":["video","instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30183v1","title":"DrivenMorph: Bridging Attention Mechanism and Variational Image Registration via Difference Modeling","abstract":"Medical image registration benefits significantly from deep learning, yet existing approaches often lack physical explainability and fine-grained deformation control. Motivated by Demons algorithms, we propose a novel DrivenMorph framework that bridges attention mechanisms with variational image registration by incorporating difference modeling as a physically inspired inductive bias. The resulting driving force, computed from local differences in the latent feature space, provides explicit semantic guidance throughout the registration process. It directly drives the registration process through a neural Demons layer that simulates force-displacement interactions to generate smooth and anatomically consistent deformation. Unlike previous methods, our approach not only integrates traditional registration principles with popular deep networks, providing an explainable and efficient solution for learning-based medical image registration, but also separates difference modeling from deformation, improving modularity and explainability. Extensive experiments on multiple 3D brain MRI datasets demonstrate superior performance over state of-the-art learning-based and optimization-based methods. Furthermore, visualizations and statistical analyses confirm that the learned driving force aligns closely with actual deformation patterns, supporting its explanatory value.","authors":["Mingke Li","Jianping Zhang","Jinqiu Deng"],"published":"2026-06-29T11:57:51Z","updated":"2026-06-29T11:57:51Z","abstract_url":"https://arxiv.org/abs/2606.30183v1","html_url":"https://arxiv.org/html/2606.30183v1","pdf_url":"https://arxiv.org/pdf/2606.30183v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30179v1","title":"HiRes: A Hierarchical Cascaded Method for Resistor Value Identification","abstract":"Accurate identification of resistor values from unconstrained images remains a challenging computer vision task due to variations in lighting, orientation, scale, and background complexity. This paper presents HiRes, a hierarchical cascaded pipeline for end-to-end resistor value identification directly from full-frame images. The approach combines object detection (YOLOv8n), semantic segmentation (UNet++ with EfficientNet-B2), and structured geometric decoding via projection along the resistor axis. To improve robustness, we incorporate geometric filtering, gap-preserving band separation, and validation against the E24 resistor series. Experiments across diverse real-world images show that HiRes achieves a detection mAP50 of 0.9906, a segmentation mIoU of 0.8444, and an end-to-end identification accuracy of 85.8% (95% CI: 78.0-91.9%), outperforming the publicly available classical baseline, CVResist, which fails to generalize beyond controlled conditions. In addition, our architecture outperforms state-of-the-art MLLMs on our challenging test set, offering a lower cost, high efficiency, and an interpretable alternative method. These results demonstrate the effectiveness of integrating learned visual representations with structured reasoning for robust resistor interpretation. Code and dataset are available at https://github.com/HiRes491/HiRes.","authors":["Rama Y. AlHamidi","Aseel A. Mohamed","Mustafa A. Eltayeb","Osama Hasoneh","Mohammad Shaqfeh"],"published":"2026-06-29T11:55:06Z","updated":"2026-06-29T11:55:06Z","abstract_url":"https://arxiv.org/abs/2606.30179v1","html_url":"https://arxiv.org/html/2606.30179v1","pdf_url":"https://arxiv.org/pdf/2606.30179v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30168v1","title":"Latent Noise Mask for Reducing Visual Redundancy in Multimodal Large Language Models","abstract":"Multimodal large language models (MLLMs) often fail in fine-grained visual reasoning, as question-relevant visual cues are diluted by dense and redundant image tokens. Recent multimodal reasoning methods usually extend chain-of-thought from language models into visual or latent spaces, seeking to add intermediate reasoning states while overlooking the negative impact of redundant visual tokens. We propose LatEnt Noise maSk (Lens), a question-conditioned visual evidence purification framework that empowers MLLMs to reason with cleaner visual cues in latent space. Lens introduces a lightweight Lens Evidence Token (LET) to score which visual tokens support the current question and preserve them during decoding. Guided by the LET scores, it injects adaptive latent noise into low-relevance tokens, softly suppressing distractors without changing the model backbone or token sequence. With only one temporary learnable control token and a lightweight noise generator, Lens adds minimal overhead while improving the base MLLM by 2.4-6.4 points on most VQA datasets and by 4.1-6.4 points on grounding tasks. These results show that multimodal reasoning can benefit more directly from cleaner question-relevant visual evidence than from simply extending the reasoning trace.","authors":["Kai Jiang","Ruishu Zhu","Siqi Huang","Hongyuan Zhang","Xuelong Li"],"published":"2026-06-29T11:44:09Z","updated":"2026-06-29T11:44:09Z","abstract_url":"https://arxiv.org/abs/2606.30168v1","html_url":"https://arxiv.org/html/2606.30168v1","pdf_url":"https://arxiv.org/pdf/2606.30168v1.pdf","matched_keywords":["multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30147v1","title":"T2LDM++: A Self-Conditioned Representation Guided Diffusion Model for Realistic Text-to-LiDAR Scene Generation","abstract":"Recent progress in Text-to-Image generation benefits from large-scale Text-Image pairs. However, the scarcity of Text-LiDAR pairs often causes over-smoothed scenes and limited controllability. In this paper, we rethink the limitations of Text-LiDAR generation task, focusing on alleviating insufficient training priors and constructing controllable Text-LiDAR data. We propose a \\textbf{T}ext-\\textbf{to}-\\textbf{L}iDAR \\textbf{D}iffusion \\textbf{M}odel for LiDAR scene generation, T2LDM++, with a Self-Conditioned Representation Guidance (SCRG). Specifically, to alleviate object over-smoothing, SCRG employs a Guidance Network (GN) to provide reconstruction-based soft supervision to the Denoising Network (DN). This enables DN to learn geometry-aware representations through reconstruction guidance, leading to more accurate denoising in DDPMs. Meanwhile, through analysis and design, SCRG exhibits more effective and lightweight, while decoupled in inference, avoiding computational overhead. Furthermore, we construct two high-quality Text-LiDAR benchmarks ($>$100K samples) using a generalized strategy of geometric annotations, along with a controllability metric. Moreover, a directional position prior is designed to mitigate street distortion, further improving scene fidelity. Additionally, T2LDM++ supports multiple conditions, including (Semantic, Box, BEV, Camera)-to-LiDAR, Sparse-to-Dense, and Dense-to-Sparse generation, by learning a control encoder via frozen DN. With effective prior modeling and high-quality Text-LiDAR benchmarks, T2LDM++ can generate realistic LiDAR scenes with rich geometric details in unconditional and conditional settings.","authors":["Wentao Qu","Qi Zhang","Chenxu Wang","Guofeng Mei","Yongfei Liu","Xiaoshui Huang","Gim Hee Lee","Liang Xiao"],"published":"2026-06-29T11:23:11Z","updated":"2026-06-29T11:23:11Z","abstract_url":"https://arxiv.org/abs/2606.30147v1","html_url":"https://arxiv.org/html/2606.30147v1","pdf_url":"https://arxiv.org/pdf/2606.30147v1.pdf","matched_keywords":["representation","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30131v1","title":"Hyper-Network Neural Functional Maps for Unsupervised Robust 3D Shape Matching","abstract":"Functional maps are the cornerstone of recent non-rigid 3D shape matching methods due to their efficiency and performance. However, existing methods struggle with challenging scenarios, such as partiality, topological noise, and raw point clouds. A primary bottleneck is that significant intrinsic distortion prevents truncated spectral bases from being accurately aligned via linear transformations (i.e., functional maps). To address this, we introduce a hyper-network that predicts non-linear neural functional maps (NFM), learned in an unsupervised manner, to better align spectral bases. Specifically, we model the NFM as an MLP with skip-connection to refine standard FM and employ a hyper-network to predict its weights, conditioned on standard FM. Our framework is trained using a novel unsupervised spectral alignment loss. Experiments demonstrate that our approach can be seamlessly integrated into state-of-the-art unsupervised deep functional map pipelines, substantially improving matching accuracy in demanding scenarios.","authors":["Dongliang Cao","Florian Bernard"],"published":"2026-06-29T11:09:05Z","updated":"2026-06-29T11:09:05Z","abstract_url":"https://arxiv.org/abs/2606.30131v1","html_url":"https://arxiv.org/html/2606.30131v1","pdf_url":"https://arxiv.org/pdf/2606.30131v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30108v1","title":"LETT-NeXt: A Lightweight RECIST-Guided Model for 3D CT Lesion Segmentation","abstract":"RECIST diameter measurements are widely used for tumor response assessment, but they provide only a limited 2D description of lesion extent. We present LETT-NeXt, a lightweight RECIST-guided model that predicts 3D lesion masks from CT volumes and RECIST markers for the CVPR 2026 Foundation Models for Pan-cancer Segmentation in CT Images competition. LETT-NeXt extracts a RECIST-centered regional crop, encodes the RECIST line and endpoints as two prompt channels, and concatenates them with the CT input. A compact MedNeXt-v2 encoder--decoder predicts the lesion mask, followed by prompt-aware component selection and adaptive AutoZoom inference. On the public validation set, LETT-NeXt achieved a Dice Similarity Coefficient (DSC) of 79.4 $\\pm$ 10.1 and a Normalized Surface Dice (NSD) of 72.3 $\\pm$ 16.2. On the hidden test set, it achieved a DSC of 73.9 and an NSD of 67.3, corresponding to a challenge score of 70.6\\%. On the public validation mirror, LETT-NeXt completed CPU inference in 6.9 $\\pm$ 3.0 s per case with a peak memory use of 3.6 GB. Code is available at github.com/Ahus-AIM/lett-next.","authors":["Sebastian Aas","Elias Stenhede","Arian Ranjbar"],"published":"2026-06-29T10:44:51Z","updated":"2026-06-29T10:44:51Z","abstract_url":"https://arxiv.org/abs/2606.30108v1","html_url":"https://arxiv.org/html/2606.30108v1","pdf_url":"https://arxiv.org/pdf/2606.30108v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30101v1","title":"SIR: Structured Image Representations for Explainable Robot Learning","abstract":"Existing robot policies based on learned visual embeddings lack explicit structure and are sensitive to visual distractions. Thus, the representations that drive their behaviour are often opaque, making their decision-making process difficult to interpret. To address this, we introduce Structured Image Representations (SIR), a method that leverages Scene Graphs (SGs) as an intermediate representation for robot policy learning. Our approach first constructs a fully connected graph, using image-derived features as initial node representations. Then, a module learns to sparsify this graph end-to-end, creating a task-relevant sub-graph that is passed to the action generation model. This process makes our model intrinsically explainable. Evaluations on RoboCasa show that our sparse graph policies outperform image-based baselines on average with 19.5% vs 14.81% success rate. Most importantly, we show that the learned sparse graphs are a powerful tool for model analysis. By analysing when the model's sub-graph deviates from human expectation, such as by including distractor nodes or omitting key objects, we successfully uncover dataset biases, including spurious correlations and positional biases. https://github.com/intuitive-robots/SIR_Model","authors":["Paul Mattes","Jan Schwab","Jens Bosch","Nils Blank","Maximilian Xiling Li","Minh-Trung Tang","Moritz Haberland","Rudolf Lioutikov"],"published":"2026-06-29T10:37:21Z","updated":"2026-06-29T10:37:21Z","abstract_url":"https://arxiv.org/abs/2606.30101v1","html_url":"https://arxiv.org/html/2606.30101v1","pdf_url":"https://arxiv.org/pdf/2606.30101v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30097v1","title":"CylindTrack: Depth-Aware Cylindrical Motion Modeling for Panoramic Multi-Object Tracking","abstract":"Multi-Object Tracking (MOT) is a core capability for embodied perception, and panoramic cameras are attractive for embodied systems because their 360° field of view reduces blind spots and keeps surrounding targets observable for longer durations. However, panoramic MOT is not a straightforward extension of perspective MOT. In equirectangular panoramic videos, the horizontal image domain is periodic rather than Euclidean, which breaks planar motion assumptions and makes IoU-based association unreliable near the 0°/360° seam. Meanwhile, large-FoV scenes often contain more objects, stronger scale variation, and more frequent interactions, making online association particularly sensitive to unstable frame-wise depth cues. To address these issues, we propose CylindTrack, a depth-aware cylindrical tracking-by-detection framework for panoramic MOT. CylindTrack first introduces Depth-Temporal Trajectory Modeling (DTM), which promotes instance depth from an isolated frame-wise cue to a temporally filtered trajectory-level state. To improve the reliability of depth observations, we further develop Spherical Spatio-Temporal Consistency Learning (SSTC), which combines a Temporal Mixer and Spherical Geometry-aware Attention to enhance temporal coherence and panoramic geometric alignment in depth-aware representations. Finally, we design a Topology-Aware Cylindrical Motion Model (TCMM) that lifts horizontal motion into a continuous angular state space and performs seam-consistent motion prediction and association in the periodic panoramic domain. By jointly modeling trajectory-level depth consistency and panoramic topology, CylindTrack improves identity preservation and trajectory continuity in challenging panoramic scenes. The source code will be released at https://github.com/warriordby/CylindTrack.","authors":["Buyin Deng","Kai Luo","Lingxin Huang","Xinqi Liu","Fei Cheng","Hang Zheng","Liming Yin","Kailun Yang"],"published":"2026-06-29T10:32:08Z","updated":"2026-06-29T10:32:08Z","abstract_url":"https://arxiv.org/abs/2606.30097v1","html_url":"https://arxiv.org/html/2606.30097v1","pdf_url":"https://arxiv.org/pdf/2606.30097v1.pdf","matched_keywords":["video","representation","instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30082v1","title":"Clinical Risk-Aware Multi-Level Grading for Coronary Artery Stenosis through Curved Feature Reconstruction","abstract":"Developing a multi-level grading model for coronary artery stenosis holds great clinical significance for the diagnosis of coronary artery disease. However, designing an effective multi-level deep learning algorithm faces significant challenges. Specifically, utilizing CCTA or 3D SCPR images alone presents inherent shortcomings: CCTA images are difficult to analyze due to the tortuous paths of blood vessels, while 3D SCPR images are prone to abnormal distortions that hinder accurate grading. Furthermore, different stenosis grades are associated with varying clinical risks, and incorporating this association into the algorithm is non-trivial. To address the former problems, we propose the Curved Feature Reconstruction (CFR) module, which uses vessel curves as prior and employs a point-by-point correspondence strategy to precisely align and fuse features from both 3D SCPR and CCTA images. Meanwhile, a Clinical Risk-Aware (CR) Loss is employed to introduce clinical risk relevance into the network training so that the algorithm can better align with the clinical diagnosis. The experimental results on a in-house dataset reveal that our approach significantly outperforms other methods, and several ablation studies also demonstrate the effectiveness of our proposed designs.","authors":["Shishuang Zhao","Hongtai Li","Junjie Hou","Yuhang Liu"],"published":"2026-06-29T10:17:22Z","updated":"2026-06-29T10:17:22Z","abstract_url":"https://arxiv.org/abs/2606.30082v1","html_url":"https://arxiv.org/html/2606.30082v1","pdf_url":"https://arxiv.org/pdf/2606.30082v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30067v1","title":"Neural Subspace Reallocation: Continual Learning as Retrieval-Based Subspace Memory Management","abstract":"We introduce Neural Subspace Reallocation (NSR), which reframes continual learning as memory management over parameter subspaces. Instead of treating Low-Rank Adaptation (LoRA) modules as disposable per-task adapters, NSR manages them as compressible, retrievable memory units on a frozen backbone through a recurring cycle: (1) compress learned LoRAs via SVD, (2) reserve them in a TaskKnowledgeBank, (3) recall related past LoRAs by embedding similarity to warm-start new or returning tasks, and (4) reallocate the active subspace accordingly, with distillation protecting prior tasks. We prove that in cyclic environments any memoryless allocation policy incurs cumulative regret Omega(T(M-1)Delta_switch) relative to a history-aware policy backed by the Bank (Theorem 1). Empirically, on Split-CIFAR-100 the Bank reduces cyclic recovery time by 10x, exactly as predicted, and on the heterogeneous 5-Datasets benchmark NSR achieves the highest accuracy and the least forgetting, about 9x closer to zero backward transfer than the memoryless heuristics. Crucially, we run a controlled study that isolates which component matters: holding the Bank fixed and varying only the allocation rule, we find that a simple similarity-based retrieval rule matches or beats a learned reinforcement-learning controller (recovering recurring tasks in 0 vs 1.8 steps and reaching equal accuracy). Our central, honest finding is therefore that the memory mechanism -- compression and similarity retrieval -- rather than a learned allocation policy, drives continual-learning performance under fixed capacity. A memory-budget analysis confirms the compressed Bank stays small -- 0.29 MB of parameter memory per task -- so a top-K retention cap bounds the total footprint while preserving fast recovery for retained tasks.","authors":["Byeong Hoon Yoon"],"published":"2026-06-29T10:00:29Z","updated":"2026-06-29T10:00:29Z","abstract_url":"https://arxiv.org/abs/2606.30067v1","html_url":"https://arxiv.org/html/2606.30067v1","pdf_url":"https://arxiv.org/pdf/2606.30067v1.pdf","matched_keywords":["retrieval"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30058v1","title":"Emergence of a Shared Canonical Object Frame from In-the-Wild Videos","abstract":"Comparing object orientations and positions across different instances requires their poses to be expressed in a shared canonical frame. Establishing such frames has traditionally required manual annotation, creating a scaling bottleneck that limits category and instance diversity. We show that a shared canonical frame can instead emerge from self-supervised training on object-centric videos captured in the wild, using only noisy camera poses from Structure-from-Motion. Our key idea is to route all training sequences through a shared geometric bottleneck: a coarse canonical mesh that carries no category-specific detail. By learning dense correspondences from image pixels to this mesh, and estimating per-sequence alignments from noisy SfM geometry, a common canonical frame emerges from multi-view consistency and the semantic priors of the feature extractor, without any canonical pose labels or category conditioning. Trained in a self-supervised manner on 160,000 in-the-wild object videos, our method achieves competitive accuracy on category-level pose estimation benchmarks compared to methods that rely on canonical pose supervision. The code and checkpoint is available on https://github.com/Fischer-Tom/Emergent-Canonical-Frame/.","authors":["Tom Fischer","Martin Sundermeyer","Adam Kortylewski","Eddy Ilg"],"published":"2026-06-29T09:48:39Z","updated":"2026-06-29T09:48:39Z","abstract_url":"https://arxiv.org/abs/2606.30058v1","html_url":"https://arxiv.org/html/2606.30058v1","pdf_url":"https://arxiv.org/pdf/2606.30058v1.pdf","matched_keywords":["video","instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30054v1","title":"Illuminating Unified Multimodal Model for Free-form Interleaved Text-Image Generation","abstract":"The advancement of generative AI models capable of producing text and image marks a critical step forward in the realm of multimodal intelligence, particularly for tasks involving the interleaving of both modalities. To advance this intelligence to the next stage, it is crucial for models to autonomously generate free-form interleaved text-image sequences. In this paper, we introduce ILLUME-X, an advanced unified multimodal paradigm that enables high-quality, free-form interleaved text-image generation by improving multimodal data efficiency and stabilizing the multimodal training process. ILLUME-X comprises three key components: (i) an expanded training data pipeline optimized for interleaved text-image generation, (ii) a progressive training strategy with self-adaptive objectives for free-length multimodal token sequences, and (iii) an objective and comprehensive evaluation method ILScore for interleaved text-image sequences. Notably, our ILLUME-X outperforms previous unified models across multiple interleaved text-image generation tasks like style transfer, image decomposition and storytelling.","authors":["Chonghuinan Wang","Zhikai Chen","Chunwei Wang","Yecong Wan","Junwei Yang","Zhixin Wang","Wei Zhang","Jiaqi Xu","Renjing Pei","Xiaohe Wu","Fan Li","Wangmeng Zuo"],"published":"2026-06-29T09:45:15Z","updated":"2026-06-29T09:45:15Z","abstract_url":"https://arxiv.org/abs/2606.30054v1","html_url":"https://arxiv.org/html/2606.30054v1","pdf_url":"https://arxiv.org/pdf/2606.30054v1.pdf","matched_keywords":["multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30049v1","title":"Bridging the Gap Between Image Restoration and Navigational Safety in Hazy Conditions: A New Visibility Estimation Metric for Maritime Surveillance","abstract":"Visibility distance is critical to maritime navigational safety because it determines the effective observation range of shipborne and shore-based monitoring systems. Under hazy conditions, degraded visual information shortens observable distance and increases navigational risks and economic losses. Although numerous image dehazing methods have been developed, conventional image quality assessment metrics, such as PSNR, SSIM, FSIM, FADE, and NIQE, cannot establish a physically interpretable relationship between restoration quality and practical visibility thresholds. To address this limitation, this work proposes a visibility-oriented evaluation framework that links dehazing performance with visible-distance estimation. First, a Maritime Simulated Visibility Dataset (MSVD) is constructed using Unity3D to simulate maritime traffic scenes under graded visibility conditions. The dataset provides paired hazy and clear images with precise visibility annotations, enabling quantitative analysis of visibility restoration. Second, a dehazing visibility evaluation metric is developed by using object detection accuracy as an intermediate indicator. By establishing a mapping between visibility distance and detection performance, the proposed metric converts image restoration improvements into measurable visibility gains. Six representative dehazing methods are evaluated using both conventional image quality metrics and the proposed visibility metric. Experimental results under different imaging conditions demonstrate that MSVD provides a reliable benchmark for evaluating dehazing performance across graded visibility levels, while the proposed metric enables interpretable and reliable visible-distance estimation, thereby supporting the assessment of navigational safety and operational efficiency.","authors":["Wentao Feng","Guobei Peng","Wengang Mao","Ryan Wen Liu"],"published":"2026-06-29T09:42:25Z","updated":"2026-06-29T09:42:25Z","abstract_url":"https://arxiv.org/abs/2606.30049v1","html_url":"https://arxiv.org/html/2606.30049v1","pdf_url":"https://arxiv.org/pdf/2606.30049v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30047v1","title":"Argus: Metric Panoramic 3D Reconstruction for Indoor Scenes","abstract":"Metric feed-forward 3D reconstruction for panoramic data remains under-explored due to the lack of large-scale panoramic RGB-D training data. We present Realsee3D, a hybrid dataset of 10K indoor scenes (1K real, 9K synthetic) with 299K panoramic viewpoints and precise metric annotations, and Argus, a feed-forward network trained on it for metric panoramic 3D reconstruction. In the sparse unordered capture setting of Realsee3D, a poorly chosen coordinate anchor can cause global pose drift. Argus addresses this with a learned covisibility module that selects the geometrically optimal reference view to anchor the metric world frame. To further improve multi-task learning, we decompose the bidirectional pixel-to-world mapping into interpretable sub-steps with per-step supervision and cross-coordinate joint constraints, reinforcing geometric consistency across prediction branches. On the Realsee3D benchmark, Argus achieves state-of-the-art metric performance in camera pose estimation, depth estimation, and point cloud reconstruction. Project page: https://argus-paper.realsee.ai.","authors":["Xi Li","Linyuan Li","Yan Wu","Tong Rao","Kai Zhang","Xinchen Hui","Cihui Pan"],"published":"2026-06-29T09:39:17Z","updated":"2026-06-29T09:39:17Z","abstract_url":"https://arxiv.org/abs/2606.30047v1","html_url":"https://arxiv.org/html/2606.30047v1","pdf_url":"https://arxiv.org/pdf/2606.30047v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30045v1","title":"Walking in the Implicit: Interactive World Exploration via Neural Scene Representation","abstract":"Interactive video generation systems for camera-controlled world exploration roll out growing sequences of latent video frames, entangling state transition with high-frequency observation synthesis. We propose Walking in the Implicit, a scene-centric paradigm that changes the rollout variable from frame latents to a fixed-length, renderable implicit state, termed Neural Implicit Scene (NIS). This factorizes interactive generation into stochastic transition of a compact scene state and deterministic pose-conditioned rendering given the sampled state. We instantiate this paradigm as NeuWorld: a transformer VAE learns locally anchored NIS from sparse posed frames, and a diffusion transformer evolves NIS conditioned on future camera trajectories and geometry-aware retrieved history. By reusing the VAE encoder as a unified conditioner, NeuWorld maps camera, reference-image, and history cues into the same NIS modality, avoiding external heterogeneous encoders. Trained from scratch on public posed-view data without pretrained video backbones or auxiliary 3D reconstructors, NeuWorld achieves strong long-horizon consistency with favorable inference efficiency.","authors":["Zhiqi Li","Chengrui Dong","Zhenhua Du","Hangning Zhou","Cong Qiu","Hailong Qin","Mu Yang","Dongxu Wei","Peidong Liu"],"published":"2026-06-29T09:37:33Z","updated":"2026-06-29T09:37:33Z","abstract_url":"https://arxiv.org/abs/2606.30045v1","html_url":"https://arxiv.org/html/2606.30045v1","pdf_url":"https://arxiv.org/pdf/2606.30045v1.pdf","matched_keywords":["video","3d","representation","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30027v1","title":"Cross-Modal Iteration Distillation for Robust IHD Screening: The IDNet Framework and A New Benchmark","abstract":"Color Fundus Photography (CFP) offers a low-cost and non-invasive route for ischemic heart disease (IHD) screening, but current studies are limited by scarce public benchmarks and ineffective fusion of retinal images with sparse clinical variables. We propose IDNet, a multimodal framework with a Cross-Modal Distillation Aggregator (CDA) that uses learnable queries to sequentially integrate left-eye, right-eye, and clinical features, mitigating the imbalance between high-dimensional visual features and low-dimensional tabular inputs. We also construct a reproducible UK Biobank benchmark with open-source curation and quality-control pipelines, yielding 50,410 images from 25,205 subjects. On this benchmark, IDNet outperforms image-only, clinical-only, and several multimodal baselines, and CDA consistently improves multiple visual encoders as a plug-in fusion module.","authors":["Yongchang Gao","Junjie Pang","Shuaiyu Yang","Yusheng Yang","Xichao Jia","Shaojie Li","Hongfei Zhang","Jia Mu"],"published":"2026-06-29T09:27:06Z","updated":"2026-06-29T09:27:06Z","abstract_url":"https://arxiv.org/abs/2606.30027v1","html_url":"https://arxiv.org/html/2606.30027v1","pdf_url":"https://arxiv.org/pdf/2606.30027v1.pdf","matched_keywords":["multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30026v1","title":"MuseBench: Benchmarking Intent-Level Audiovisual Arts Understanding in MLLMs","abstract":"Audiovisual arts encompass diverse creative disciplines, including cinema, visual arts, stage performance, and game design, where artistic meaning arises from deliberate combinations of visual, auditory, and narrative elements (e.g., fear amplified through claustrophobic framing, or grief conveyed through silence and lingering close-ups). True artistic understanding extends beyond recognizing what is depicted to reasoning about why it is expressed through particular creative choices. Despite the strong progress of multimodal large language models (MLLMs), this critical aspect of artistic understanding remains underexplored, as existing benchmarks largely measure perceptual recognition while overlooking reasoning about creative intent. To address this gap, we introduce Musebench, a comprehensive benchmark designed to evaluate MLLMs on nuanced artistic understanding. It comprises 4,016 questions spanning cinematic arts, static visual arts, stage performing arts, and game arts, distilled from over 10K candidate video essays that pair professional commentary with visual demonstration. To capture the open-ended nature of artistic analysis at scale, the benchmark combines single-select and variable-option multi-select questions. All questions are generated and refined through a four-phase iterative pipeline combining shortcut filtering, adversarial distractors, and expert validation. Comprehensive zero-shot evaluation of 28 state-of-the-art MLLMs reveals that even the best-performing model achieves only 48.29% accuracy, substantially below human expert performance of 87.18%, exposing a significant gap in current models' creative domain expertise.","authors":["Yuxuan Fan","Gyusik Seo","Jing Hao","Jaemin Cho","Mohit Bansal","Jaehong Yoon"],"published":"2026-06-29T09:27:02Z","updated":"2026-06-29T09:27:02Z","abstract_url":"https://arxiv.org/abs/2606.30026v1","html_url":"https://arxiv.org/html/2606.30026v1","pdf_url":"https://arxiv.org/pdf/2606.30026v1.pdf","matched_keywords":["video","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30024v1","title":"IBRSteG: Learning a Generalizable Steganography Framework for 3D Gaussian Splatting","abstract":"Recent advances in deep learning have notably improved steganographic message hiding. However, designing a generalizable steganographic approach for 3D Gaussian Splatting (3DGS) that can embed meaningful 3D scene content remains challenging. In this paper, we propose IBRSteG, a generalizable framework for 3DGS steganography that enables undetectable concealment of secret scenes within a steganographic scene. Unlike existing approaches whose parameter generation is rigidly coupled with the specific scene, we formulate 3D steganography as a feed-forward 3D Gaussian embedding process that generalizes across different 3DGS scenes. To realize this, we introduce GAS (Gaussian Attributes Steganographer), a network that learns a scene-independent embedding function by injecting the attributes of secret 3D Gaussian points into a cover scene, thereby directly reconstructing the steganographic scenes without per-scene finetuning or optimization. By transforming 3D Gaussian into these structured attributes, these attributes are compatible with 2D learning paradigms and benefit from their structured nature, thereby enhancing generalization to unseen 3DGS scenes. Extensive experiments on established datasets demonstrate that IBRSteG can effectively conceal different scenes with high visual quality, and achieves superior capacity and security. Code is available at https://github.com/LingXiang2023/IBRSteG.","authors":["Fanye Kong","Hongyu Xia","Yu Zheng","Boyang Gong","Jie Zhou","Jiwen Lu"],"published":"2026-06-29T09:25:58Z","updated":"2026-06-29T09:25:58Z","abstract_url":"https://arxiv.org/abs/2606.30024v1","html_url":"https://arxiv.org/html/2606.30024v1","pdf_url":"https://arxiv.org/pdf/2606.30024v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30020v1","title":"Uncertainty Estimation in Pathology Foundation Models via Deep Mutual Learning","abstract":"Pathology foundation models (PFMs) offer generalizable representations for whole-slide image (WSI) analysis, yet their clinical adoption remains limited. Specifically, their predictions lack reliable confidence estimates, and no single PFM is universally best across tasks, which severely undermines trust in medical settings. To overcome this, we propose $\\mathtt{DICE}$, a plug-and-play framework that ensembles $K$ frozen PFMs and models their disagreement as a proxy for uncertainty estimation. To ensure this proxy yields meaningful estimates, we align the ensemble members via deep mutual learning, and theoretically show that this objective upper-bounds the model uncertainty. Additionally, we demonstrate that the ensemble's consensus localizes abnormalities at the patch level without any explicit supervision. We evaluate $\\mathtt{DICE}$ on three challenging WSI benchmarks. Notably, our framework provides reliable uncertainty estimates that accurately flag failure-prone cases under in- and out-of-distribution settings, while matching or outperforming SOTA baselines in classification, calibration, and localization. Overall, $\\mathtt{DICE}$ takes a crucial step toward translating PFMs into uncertainty-aware decision-support systems.","authors":["Gbègninougbo Aurel Davy Tchokponhoue","Sevda Öğüt","Ali Idri","Dorina Thanou","Pascal Frossard"],"published":"2026-06-29T09:24:22Z","updated":"2026-06-29T09:24:22Z","abstract_url":"https://arxiv.org/abs/2606.30020v1","html_url":"https://arxiv.org/html/2606.30020v1","pdf_url":"https://arxiv.org/pdf/2606.30020v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30019v1","title":"OmniDance: Multimodal Driven Dance Video Generation with Large-scale Internet Data","abstract":"Music-driven dance video generation aims to synthesize expressive human motion that is temporally aligned with music while maintaining high visual fidelity. Despite recent progress, existing methods still face two key limitations: the lack of large-scale, high-quality dance video datasets, and the absence of principled frameworks for integrating music as a complementary conditioning signal into Video Generation Foundation Models. To address these limitations, we introduce CIPE-Dance, a large-scale Internet-sourced dance video dataset with choreography-informed text annotations, constructed via a progressive expert pipeline. To the best of our knowledge, CIPE-Dance is the largest dataset for dance video generation to date, comprising 300k high-quality clips over 400 hours and covering diverse dancers, environments, and dance genres. We further propose OmniDance, a framework-level recipe for integrating music into a TI2V foundation model without sacrificing its original controllability or visual fidelity. Motivated by the complementary roles of text as low-frequency semantics and music as high-frequency temporal dynamics, OmniDance co-designs a depth-aware specialization architecture, an anchored easy-to-hard curriculum learning strategy, and a modality-specialized time-dependent CFG strategy, enabling unified TI2V, MI2V, and MTI2V generation. Extensive experiments on CIPE-Dance demonstrate that OmniDance achieves state-of-the-art performance across all three tasks and exhibits robust multimodal integration capability. Project is available at https://github.com/AMAP-ML/OmniDance.","authors":["Kaixing Yang","Jiashu Zhu","Xulong Tang","Ziqiao Peng","Xiangyue Zhang","Chubin Chen","Puwei Wang","Jiahong Wu","Xiangxiang Chu","Hongyan Liu","Jun He"],"published":"2026-06-29T09:23:53Z","updated":"2026-06-29T09:23:53Z","abstract_url":"https://arxiv.org/abs/2606.30019v1","html_url":"https://arxiv.org/html/2606.30019v1","pdf_url":"https://arxiv.org/pdf/2606.30019v1.pdf","matched_keywords":["video","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30017v1","title":"Monte Carlo Energy Aggregation for Mobile 3D Gaussian Splatting","abstract":"Recent advances in 3D Gaussian Splatting have demonstrated unprecedented success in novel view synthesis. However, the substantial inference and storage overhead driven by high-order Spherical Harmonics (SH) are primary bottlenecks for mobile platforms. In this paper, we present Flux-GS, a real-time Gaussian Splatting method designed to achieve high-fidelity rendering with significantly reduced overhead for resource-constrained mobile platforms. We first propose a Monte Carlo Specular Energy Aggregator, sampling third-order radiance residuals and aggregating specular energy into a compact latent space. In this way, our method effectively preserves visually salient lighting features in lower-order bands without expensive distillation or pre-training. To mitigate the high-frequency details lost during compression, we introduce an Attribute-Conditioned SH Enhancement module. This module predicts Gaussian-aware offsets based on intrinsic Gaussian attributes, which enhance the first-order SH representation prior to inference, without extra inference costs. Furthermore, the original single-view gradient-based densification is prone to producing excessive Gaussians and overfitting to a certain view. We address these limitations by proposing a Multi-view Alpha-based Densification and Pruning strategy. By leveraging multi-view guidance, we ensure multi-view structure consistency and the precise removal of redundant primitives. Extensive experiments demonstrate that Flux-GS achieves substantial parameter reduction while maintaining competitive visual quality, offering a robust and scalable solution for real-time mobile rendering. Code: \\textcolor{magenta}{\\href{https://xiaobiaodu.github.io/flux-gs-project/}{https://xiaobiaodu.github.io/flux-gs-project/}}.","authors":["Xiaobiao Du","YuAn Wang","Hao Li","Bosheng Wang","Xun Sun","Xin Yu"],"published":"2026-06-29T09:21:57Z","updated":"2026-06-29T09:21:57Z","abstract_url":"https://arxiv.org/abs/2606.30017v1","html_url":"https://arxiv.org/html/2606.30017v1","pdf_url":"https://arxiv.org/pdf/2606.30017v1.pdf","matched_keywords":["3d","agent","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30014v1","title":"Shell-Supervised Gaussian Splatting for Urban Real-to-Sim Reconstruction","abstract":"Real-to-sim reconstruction for embodied AI requires geometry that is useful for collision reasoning, navigation, and agent-environment interaction, not only photorealistic novel-view synthesis. However, close-range urban facades are difficult for video-to-3D reconstruction: glass, reflections, repeated windows, and weak texture can produce visually plausible renderings with unstable surface geometry. We introduce shell-supervised Gaussian Splatting, a reconstruction-stage framework that uses an external facade structural shell as lightweight geometric supervision for video-driven Gaussian reconstruction. The method aligns an exterior shell to the video reconstruction frame, renders per-view depth, camera-space normal, and valid-mask maps, and applies these cues through mask-gated losses during Gaussian optimization. This design preserves RGB-driven appearance while regularizing only visible shell-supported facade regions. Experiments on anonymized close-range urban facade scenes show improved facade orientation and visible-surface point-cloud consistency over photo-only, monocular-cue, and surface-oriented Gaussian baselines, while maintaining comparable held-out rendering quality.","authors":["Yuan Yang","Peijun Lu","Fangzhou Lu","Sai Fan","Siqi Yan","Chenyuan Zhang","Haobo Liang","Yichen Wang"],"published":"2026-06-29T09:19:24Z","updated":"2026-06-29T09:19:24Z","abstract_url":"https://arxiv.org/abs/2606.30014v1","html_url":"https://arxiv.org/html/2606.30014v1","pdf_url":"https://arxiv.org/pdf/2606.30014v1.pdf","matched_keywords":["video","3d","agent"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30012v1","title":"SkelEM: Training-Signal Decoupling of Skeleton and Diffusion for Self-supervised Axial Super-Resolution in Volume Microscopy","abstract":"Volume microscopy, including electron and light microscopy, suffers from severe anisotropic resolution due to physical axial sectioning. Existing self-supervised axial super-resolution (ASR) methods face a trilemma bounded by overly smoothed regression textures, structural hallucinations of pure diffusion models, and prohibitive inference latency. In this paper, we propose Skeleton-refinE Microscopy (SkelEM), a self-supervised framework that decouples ASR at the training-signal level: a frozen topological network and a diffusion refiner are optimized by disjoint objectives, separating low-frequency topology formulation from high-frequency detail enhancement. Building on this deterministic skeleton, we exploit a unified cycle-consistent mechanism on input sparse slices to simultaneously extract a real-domain residual prior and bidirectionally align the diffusion refiner, washing away cross-plane artifacts without synthetic bias. By truncating the reverse diffusion process with this physical prior, SkelEM achieves high-fidelity detail restoration in merely $\\le 5$ steps. To rigorously assess cross-instrument generalization, we further introduce BRAVE-ASR, a new benchmark of co-aligned anisotropic and isotropic volumes acquired on a Plasma-FIB instrument. Across public benchmarks, SkelEM achieves the most favorable balance across the fidelity-perception trade-off among self-supervised methods, with state-of-the-art downstream membrane segmentation performance and robust zero-shot generalization across distinct modalities.","authors":["Bohao Chen","Yanchao Zhang","Yanan Lv","Chenxun Deng","Hua Han","Xi Chen"],"published":"2026-06-29T09:19:04Z","updated":"2026-06-29T09:19:04Z","abstract_url":"https://arxiv.org/abs/2606.30012v1","html_url":"https://arxiv.org/html/2606.30012v1","pdf_url":"https://arxiv.org/pdf/2606.30012v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30003v1","title":"GeoEdit: Geometry-Aware Object Editing via Dual-Branch Denoising","abstract":"Precisely manipulating objects in a single photograph (translation, rotation, scaling) while obeying 3D physical constraints remains unsolved for diffusion-based editors. Current 2D methods lack spatial awareness and produce perspective violations. Forcing structural proxies into the latent space also disrupts variance homogeneity, and the resulting self-attention leakage leads to ghosting and background blur. The core difficulty is asymmetric: the relocated object must follow a rigid geometry, yet the uncovered background needs freedom to synthesize plausible content. We present GeoEdit, a training-free Lift-Manipulate-Render-Denoise pipeline that satisfies both constraints. We decouple scene and object in 3D, align them through point correspondence, and render a geometry-aligned proxy with a structural depth map. A Dual-Branch Denoising stage then refines this proxy: a video diffusion backbone preserves object identity, while 3D constraints are injected into the foreground within a narrow denoising window at matching noise variance (variance-homogeneous injection). The background denoises freely. Because the injected signal matches the native latent statistics, self-attention stays undisturbed. We also introduce GeoEditBench, a pose-aware benchmark covering object translation, object rotation, and camera movement with pose-aware evaluation metrics. Experiments confirm consistent gains in geometric accuracy, identity fidelity, and background quality. Our codes are available at https://github.com/Heey731/GeoEdit.","authors":["Yi He","Jiangming Wang","Xinyu Wang","Mark Fong","Songchun Zhang","Yuxuan Xue","Hai-Tao Zheng","Yue Ma"],"published":"2026-06-29T09:12:20Z","updated":"2026-06-29T09:12:20Z","abstract_url":"https://arxiv.org/abs/2606.30003v1","html_url":"https://arxiv.org/html/2606.30003v1","pdf_url":"https://arxiv.org/pdf/2606.30003v1.pdf","matched_keywords":["video","3d","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30001v1","title":"SICAGE: Speaker-Independent Culture-Aware Gesture Generation using TED4C-L Dataset","abstract":"Recent co-speech gesture generation methods often overlook cultural differences, limiting their effectiveness in human-agent interaction. Moreover, culture-conditioned models are rarely evaluated under speaker-disjoint splits, so apparent \"cultural\" behavior may be confounded with speaker-specific gesturing style. We introduce SICAGE, a modular framework for culture-aware co-speech gesture generation that conditions motion synthesis models on speaker-independent cultural representations. SICAGE learns these representations from audio and text by treating each speaker as a separate domain while imposing invariance across speakers. This encourages representations to remain culture-discriminative while reducing dependence on speaker identity. The resulting cultural embeddings condition a multimodal generator to produce culturally appropriate gestures. We instantiate this idea with two domain generalization approaches: adversarial learning and Fishr regularization. We further introduce ALaDiT, a real-time diffusion-based gesture generator designed to efficiently incorporate the learned cultural embeddings. To validate our method, we built TED4C-L, a 106-hour multimodal dataset of 764 TED speakers from four cultural groups. Experiments show that SICAGE improves motion realism, diversity, beat synchronization, semantic relevance, and cultural consistency.","authors":["Ariel Gjaci","Antonio Sgorbissa","Vittorio Murino"],"published":"2026-06-29T09:11:15Z","updated":"2026-06-29T09:11:15Z","abstract_url":"https://arxiv.org/abs/2606.30001v1","html_url":"https://arxiv.org/html/2606.30001v1","pdf_url":"https://arxiv.org/pdf/2606.30001v1.pdf","matched_keywords":["agent","representation","multimodal","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.29997v1","title":"Rigel: Self-Distilled Score Adaptation for Image and Video Captioning Evaluation","abstract":"Automatic evaluation of image and video captioning is essential for benchmarking multimodal systems, although standard evaluation metrics show limited alignment with human judgments. Recent approaches using large language models (LLMs), commonly referred to as LLM-as-a-Judge, have improved alignment with human judgments but still suffer from a mismatch between large-vocabulary language modeling and evaluation over a small label set. To address this, we propose Rigel, an automatic evaluation metric for image and video captioning, based on self-distilled score adaptation. The metric employs an evaluation-specific scoring head distilled from a frozen LLM, which captures judgment signals in a task-aligned space without relying on large-vocabulary token sets. We then refine the LLM backbone with human judgment data. To train Rigel, we constructed the Vid-Lepus dataset, which contains 3,338 video clips, 33,380 reference captions, and 5,637 candidate captions. Experiments on multiple benchmarks show that Rigel outperforms state-of-the-art metrics, achieving over 10-point improvements on ActivityNet-Fact in the reference-free setting.","authors":["Shuitsu Koyama","Kazuki Matsuda","Yuiga Wada","Shinnosuke Hirano","Daichi Yashima","Komei Sugiura"],"published":"2026-06-29T09:07:29Z","updated":"2026-06-29T09:07:29Z","abstract_url":"https://arxiv.org/abs/2606.29997v1","html_url":"https://arxiv.org/html/2606.29997v1","pdf_url":"https://arxiv.org/pdf/2606.29997v1.pdf","matched_keywords":["video","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.29977v1","title":"A multi-architecture study of specificity refinement and false-positive mechanism analysis in prostate MRI","abstract":"Objectives: To characterize residual false positives in prostate MRI detection, and to evaluate a lightweight post-hoc refinement head for case-level specificity. Materials and Methods: This retrospective study used PI-CAI (5-fold cross-validation) and Prostate158 (n=158; external). A context-aware evidence head and an 89,216-parameter refinement head were trained on a frozen detection backbone; the evidence head was also trained on four further backbones (bare nnU-Net, bare U-Net, bare Mamba, MIGF-Mamba). For each false-positive region, T2-weighted, apparent-diffusion-coefficient, and high-b-value contrast ratios versus peri-lesional rings were compared against ground-truth lesions and contralateral benign regions. Results: False positives were closer to true cancers than to benign tissue in evidence and raw T2-weighted and apparent-diffusion-coefficient contrast, reproducing 35/35 across five architectures (Cohen's d 1.10; FP/benign evidence ratio 2.38x) and 105/105 across modality-perturbation scenarios. On PI-CAI fold-0, refinement raised case-level specificity from 0.469 to 0.549 (+17.2%) at preserved sensitivity (0.943); 5-fold cross-validation showed fold-conditional behavior (9/15 observations positive; range -22% to +28%). On Prostate158, both models saturated (McNemar pooled p=0.69), while the false-positive contrast-matching finding replicated. Conclusion: Residual false positives are contrast-matched to cancer (sharing raw imaging features rather than histologically confirmed mimicry), reproducing across five architectures -- a data-level imaging property, not model-specific artifacts; post-hoc refinement adds practical specificity in-domain but is fold-conditional.","authors":["Yongbo Shu","Kewen Chen","Yifeng Yuan","Zirui Xin","Luo Lei","Yang Yang","Xi Chen","Aijing Luo"],"published":"2026-06-29T08:50:34Z","updated":"2026-06-29T08:50:34Z","abstract_url":"https://arxiv.org/abs/2606.29977v1","html_url":"https://arxiv.org/html/2606.29977v1","pdf_url":"https://arxiv.org/pdf/2606.29977v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.29976v1","title":"Learning Efficient 4D Gaussian Representations from Monocular Videos with Flow Splatting","abstract":"Reconstructing dynamic 3D scenes from monocular videos is challenging due to scene complexity and temporal dynamics. With the advancement of 3D Gaussian Splatting in novel view synthesis, existing methods extend 3D Gaussians to 4D domain with deformation fields, trajectories or spatiotemporal 4D volumes to model scene element deformation. However, these methods suffer from long training time, low rendering speed or high memory consumption for per-frame reconstruction of 4D volumes, without fully exploiting dense dynamic information. To address this issue, we propose Flow Splatting, which constructs the velocity field and enables the conventional splatting technique to render optical flow from the velocity field to supervise dynamics learning process from monocular videos. Specifically, we extend 4D volumes with time varying means and covariance to represent complex dynamics. Then, we construct and approximate the velocity field naturally based on this representations. While conventional volume rendering techniques support to render color fields, we extend the volume rendering strategy to splat the velocity field by considering the influence of camera motions. We conduct experiments on various benchmarks to demonstrate the efficiency and effectiveness of our method. Compared to the state-of-the-art methods, our model achieves better image quality with less time consumption and higher rendering speed.","authors":["Shengjun Zhang","Jinzhao Li","Xin Fei","Yueqi Duan"],"published":"2026-06-29T08:50:27Z","updated":"2026-06-29T08:50:27Z","abstract_url":"https://arxiv.org/abs/2606.29976v1","html_url":"https://arxiv.org/html/2606.29976v1","pdf_url":"https://arxiv.org/pdf/2606.29976v1.pdf","matched_keywords":["video","3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.29964v1","title":"Variance Reduction on the Camera Axis: Multi-View Score Distillation for 3D","abstract":"Score distillation turns a pretrained 2D diffusion model into a 3D generator, but the per-step gradient is estimated from a single randomly chosen view: it is high-variance and blind to global shape consistency. Prior work addresses this by retraining the diffusion prior on multi-view data; this improves consistency but makes the sampling contribution inseparable from prior quality. We instead isolate the sampling axis. The per-step gradient is one noisy sample of an expectation over views; aggregating K samples per step at a fixed total UNet budget reduces variance without touching the prior. We introduce Multi-View Aggregated Score Distillation (MV-SDI), which aggregates gradients from K views per step via gradient accumulation, keeping peak memory unchanged and the 2D prior frozen, and draws views as antithetic antipodal pairs, a prior-independent geometric property, for balanced angular coverage. At a fixed 10,000-UNet-call budget, K=2 raises CLIP R-Precision from 74.8% to 83.8% and CLIP score from 0.297 to 0.312, with consistent gains on HPSv2 and ImageReward and a 0.0% divergence rate on the 43-prompt benchmark; optimization steps halve as a consequence. K=4 gives a fourfold step reduction at R-Precision 86.9% and CLIP 0.307, still well above the single-view baseline on every alignment metric. MV-SDI is compatible with gradient-based score-distillation pipelines, including Score Distillation via Inversion, and requires no retraining and no multi-view data.","authors":["Marian Lupascu","Mihai Sorin Stupariu","Ionut Mironica"],"published":"2026-06-29T08:41:42Z","updated":"2026-06-29T08:41:42Z","abstract_url":"https://arxiv.org/abs/2606.29964v1","html_url":"https://arxiv.org/html/2606.29964v1","pdf_url":"https://arxiv.org/pdf/2606.29964v1.pdf","matched_keywords":["3d","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.29963v1","title":"Explainability-Aware Frustum Attack: Exposing Structural Vulnerabilities in LiDAR-Based 3D Object Detectors","abstract":"The structural vulnerabilities of point cloud-based 3D object detectors remain poorly understood. Prior work has studied adversarial robustness primarily on isolated 3D object models, while recent LiDAR spoofing attacks target richer and more realistic driving scenes but focus mainly on physical realizability rather than understanding detector behavior or attack efficiency. In this work, we investigate how LiDAR-based detectors rely on spatial evidence in complex scenes and whether these reliance patterns can be exploited to induce failures more efficiently. To this end, we propose an explainability-guided adversarial analysis methodology. We introduce the Saliency-LiDAR (SALL) method, which aggregates Integrated Gradient attributions across scenes to produce universal saliency maps for LiDAR-based 3D object detectors. Guided by these maps, we design the Explainability-aware Frustum Attack (EFA), which selectively perturbs only the most influential frustums rather than uniformly attacking entire object regions. Experiments on KITTI and nuScenes, across detectors such as PointPillars and SECOND, show that EFA reduces detection recall by more than 15 percentage points while requiring 25-50% fewer perturbed frustums than the state-of-the-art non-saliency-aware baseline. These findings reveal that modern 3D detectors concentrate discriminative evidence in a small subset of spatial regions, exposing a structural robustness vulnerability in current LiDAR perception systems. Our code is released at https://github.com/SecMindLab/Saliency_LiDAR.","authors":["Chengzeng You","Binbin Xu","Soteris Demetriou"],"published":"2026-06-29T08:40:16Z","updated":"2026-06-29T08:40:16Z","abstract_url":"https://arxiv.org/abs/2606.29963v1","html_url":"https://arxiv.org/html/2606.29963v1","pdf_url":"https://arxiv.org/pdf/2606.29963v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.29941v1","title":"Seeing Touch from Motion: A Unified Modality-Aware Visuo-Tactile Policy with Tactile Motion Correlation","abstract":"Visuo-Tactile policies leveraging optical tactile sensors have shown great promise in contact-rich manipulation. These sensors achieve high spatial resolution and multi-dimensional force sensing by utilizing an internal camera to monitor the deformation of their elastic gel surface, thereby indirectly inferring tactile cues. Despite their advantages, extracting fine-grained contact states necessary for contact-rich manipulation remains an open challenge. Existing methods typically use either raw images or cumulative motion fields to represent tactile cues. However, both are prone to perception ambiguity. Raw tactile images mainly capture appearance changes, while cumulative motion fields only reflect the aggregate gel deformation. Consequently, distinct fine-grained contact states can exhibit highly similar patterns, making it difficult to explicitly distinguish subtle contact variations. To address this issue, we explore the dynamic priors of tactile motion and discover that the correlation between transient and cumulative motion can explicitly distinguish fine-grained contact states. Based on this insight, we propose a motion-aware tactile representation to facilitate contact-rich manipulation. Beyond tactile representation, effective fusion of tactile and visual modalities is also critical. Most existing fusion methods either directly concatenate features from each modality or train modality-specific networks separately and fuse their outputs. However, these strategies struggle to simultaneously model cross-modal interactions and preserve modality-specific characteristics. In this work, we take advantage of the Mixture-of-Transformers architecture and propose a unified modality-aware visuo-tactile policy that captures cross-modal complementarity while maintaining modality-specific properties.","authors":["Shengqi Xu","Guojin Zhong","Yang Liu","Fanjie Wang","Hu Luo","Hanyu Zhou","Weiyao Zhang","Ziyi Ye","Zuxuan Wu","Yu-Gang Jiang"],"published":"2026-06-29T08:20:18Z","updated":"2026-06-29T08:20:18Z","abstract_url":"https://arxiv.org/abs/2606.29941v1","html_url":"https://arxiv.org/html/2606.29941v1","pdf_url":"https://arxiv.org/pdf/2606.29941v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"}],"favorites":[],"latest":{"generated_at_utc":"2026-06-30T04:58:51+00:00","category":"cs.CV","keywords":["video","retrieval","3d","agent","representation","instance","multimodal","diffusion"],"fetch_window_hours":72,"daily_window_hours":30,"match_count":73,"new_or_recent_papers":[{"id":"2606.30638v1","title":"Open-Vocabulary and Referring Segmentation for 3D Gaussians Using 2D Detectors","abstract":"3D Gaussian Splatting (3DGS) has emerged at the forefront of 3D scene reconstruction. Extending 3DGS with language-driven, open-vocabulary understanding has gained significant attention for real-world applications such as embodied AI. Recent methods achieve this by learning an instance feature attribute and assigning semantics by distilling high-dimensional Contrastive Language-Image Pretraining (CLIP) features directly into the scene representation. However, the instance grouping mechanisms of these methods either require a predefined number of instances or suffer from noise in their bottom-up grouping strategies. Furthermore, the reliance on CLIP restricts semantic understanding to simple noun phrases, preventing complex spatial reasoning and referential expression grounding. We present GaussDet, a method that circumvents the need for dense CLIP features by leveraging discrete, open-vocabulary 2D object detectors with referring expression capabilities. We learn instance features for individual Gaussians to decompose the scene into 3D instance groups. By rendering these groups and aggregating semantic votes from multi-view 2D detections, we generate a robust View-Aggregated Semantic Label Distribution (VASD) for each 3D instance. This view-aggregation strategy acts as a strong regularizer, attenuating spurious labels caused by low-quality instance grouping. Our approach enables a straightforward, zero-shot extension from simple language queries to complex referential grounding. Extensive evaluations across two key tasks -- open-vocabulary segmentation (LeRF-OVS, ScanNet) and referring expression grounding (Ref-LeRF) -- demonstrate that GaussDet achieves consistent improvements over existing methods. Most notably, we achieve a substantial 16.7% mIoU improvement in referential grounding within a strict zero-shot setting.","authors":["Jameel Hassan","Yasiru Ranasinghe","Vishal Patel"],"published":"2026-06-29T17:58:41Z","updated":"2026-06-29T17:58:41Z","abstract_url":"https://arxiv.org/abs/2606.30638v1","html_url":"https://arxiv.org/html/2606.30638v1","pdf_url":"https://arxiv.org/pdf/2606.30638v1.pdf","matched_keywords":["3d","representation","instance"],"source_used":"html","source_text_chars":51976,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d, representation, instance 相关；摘要显示其主要贡献为：3D Gaussian Splatting (3DGS) has emerged at the forefront of 3D scene reconstruction. Extending 3DGS with language-driven, open-vocabulary understanding has gained significant attention for real-world applications such as embodied AI. Recent methods achieve t...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-30T04:58:52+00:00","status":"fallback"},"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30632v1","title":"GROW$^2$: Grounding Which and Where for Robot Tool Use","abstract":"Can the robot use a plate to cut a cake if no knife is available? Tool use greatly expands robot capabilities, but to use tools creatively beyond their intended functions, the robot faces the challenge of $\\textit{open-world affordance grounding}$: select an open-category object to act as a tool and localize its specific region of action. To this end, we introduce GROW$^2$ (GROunding Which and Where), which leverages object parts as a natural abstraction to split the grounding process hierarchically into semantic and geometric levels, thus bypassing the need for data-heavy, end-to-end training. Semantically, GROW$^2$ harnesses the commonsense reasoning of Vision-Language Models (VLMs) to parse a natural-language task instruction, select a suitable object as the tool, and identify task-relevant parts on the tool and the target object. Geometrically, vision foundation models then ground the selected parts into precise 3D regions from a single RGB-D image. Experiments on established benchmarks show that GROW$^2$ outperforms state-of-the-art baselines on affordance prediction benchmarks. Further, it achieves zero-shot generalization over open-category objects and outperforms baselines in both simulated and real-world robot tool use experiments.","authors":["Yuhong Deng","Yuyao Liu","David Hsu"],"published":"2026-06-29T17:56:53Z","updated":"2026-06-29T17:56:53Z","abstract_url":"https://arxiv.org/abs/2606.30632v1","html_url":"https://arxiv.org/html/2606.30632v1","pdf_url":"https://arxiv.org/pdf/2606.30632v1.pdf","matched_keywords":["3d"],"source_used":"html","source_text_chars":76069,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d 相关；摘要显示其主要贡献为：Can the robot use a plate to cut a cake if no knife is available? Tool use greatly expands robot capabilities, but to use tools creatively beyond their intended functions, the robot faces the challenge of $\\textit{open-world affordance grounding}$: select an...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-30T04:58:52+00:00","status":"fallback"},"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30611v1","title":"Reweighting Framewise Attention in Video Transformers for Facial Expression Understanding","abstract":"Understanding facial expressions in videos requires modeling subtle and localized facial dynamics under unconstrained conditions. Although recent Vision Transformer~(ViT)-based video models have shown strong performance through large-scale self-supervised pretraining, their attention mechanisms often emphasize dominant global motions and coarse temporal dynamics, limiting sensitivity to fine-grained facial variations. To address this limitation, we propose MiRA (Marginal-induced Attention Redistribution), a plug-in frame-marginal attention redistribution framework for ViT backbones that enhances spatio-temporal selectivity toward subtle facial dynamics without introducing additional trainable parameters. MiRA derives frame-level confidence and intra-frame concentration statistics from self-attention maps to estimate frame-wise marginal importance and redistribute attention toward spatiotemporally localized facial cues. We first introduce a principled \\textit{exact mode} based on post-softmax attention redistribution. To further improve efficiency, we propose \\textit{flashLite mode}, a lightweight pre-softmax approximation that integrates frame-marginal redistribution into FlashAttention kernels while preserving the effectiveness of the exact formulation. Experimental results on challenging Facial Expression Recognition~(FER) benchmarks demonstrate consistent improvements over strong ViT baselines.","authors":["Seongro Yoon","Donghyeon Cho","Jinsun Park","François Brémond"],"published":"2026-06-29T17:46:10Z","updated":"2026-06-29T17:46:10Z","abstract_url":"https://arxiv.org/abs/2606.30611v1","html_url":"https://arxiv.org/html/2606.30611v1","pdf_url":"https://arxiv.org/pdf/2606.30611v1.pdf","matched_keywords":["video"],"source_used":"html","source_text_chars":70941,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video 相关；摘要显示其主要贡献为：Understanding facial expressions in videos requires modeling subtle and localized facial dynamics under unconstrained conditions. Although recent Vision Transformer~(ViT)-based video models have shown strong performance through large-scale self-supervised pre...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-30T04:58:52+00:00","status":"fallback"},"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30608v1","title":"UnfoldArt: Zero-Shot Recovery of Full Articulated 3D Objects from Text or Image","abstract":"Articulated 3D objects are essential for interactive environments in embodied AI, robotics, and virtual reality, but reconstructing their structure and motion from sparse observations remains challenging. Existing approaches remain largely constrained by lack of supervised data or lack the priors needed to reliably recover articulation, hidden geometry, and internal object structure. We present the first debate-driven agentic approach to articulated 3D object reconstruction from text or image inputs that both grounds articulation reasoning in concrete motion and exposes the occluded geometry revealed under articulation. High-level agents reason about object semantics and motion using knowledge from vision-language and video models, while low-level agents estimate articulation parameters and interaction points; together, they engage in a two-round structured debate that first exploits global--local disagreement and then grounds the agents in freely generated video. The same video prior, conditioned on the agreed articulation, then drives each part through its motion to expose occluded interiors and geometry that cannot be inferred from a single static view. By combining agentic reasoning with a video generative prior, our approach jointly infers articulation and reconstructs complete 3D articulated objects, producing high-fidelity geometry, internal structure, and motion-consistent states beyond directly observed surfaces.","authors":["Mohamed el amine boudjoghra","Ivan Laptev","Angela Dai"],"published":"2026-06-29T17:44:53Z","updated":"2026-06-29T17:44:53Z","abstract_url":"https://arxiv.org/abs/2606.30608v1","html_url":"https://arxiv.org/html/2606.30608v1","pdf_url":"https://arxiv.org/pdf/2606.30608v1.pdf","matched_keywords":["video","3d","agent"],"source_used":"html","source_text_chars":82192,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, 3d, agent 相关；摘要显示其主要贡献为：Articulated 3D objects are essential for interactive environments in embodied AI, robotics, and virtual reality, but reconstructing their structure and motion from sparse observations remains challenging. Existing approaches remain largely constrained by lack...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-30T04:58:52+00:00","status":"fallback"},"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30599v1","title":"Goku: A Million-Scale Universal Dataset and Benchmark for Instruction-Based Video Editing","abstract":"Existing instruction-based video editing datasets commonly focus on single-task appearance editing, failing to meet the complex creative demands of real-world scenarios. To bridge this gap, we present Goku, a large-scale dataset featuring 2 million high-quality, instruction-aligned video editing pairs, which is the first to extend task boundaries from basic appearance editing to multi-task and structural manipulations(e.g., precise control of subject movement). To tackle the data synthesis challenges inherent in these complex tasks, we design an efficient data synthesis pipeline that decomposes complex edits into controllable sub-problems and introduce a progressive filtering system for data reliability throughout the whole process. Furthermore, we explore the optimal network structures on Goku, and propose Goku-Edit. To deeply comprehend complex editing instructions, Goku-Edit leverages an MLLM as its text encoder and adopts a decoupled dual-branch design: a dedicated mask branch handles structural control, freeing the main branch for appearance rendering. A comprehensive video editing benchmark, Goku-Bench, is also proposed with 1,000 human-verified test cases and 7 novel editing-specific metrics. Evaluated on Goku-Bench, Goku-Edit obtains up to +8% improvement on other open-source models in terms of instruction following.","authors":["Sen Liang","Cong Wang","Zhentao Yu","Fengbin Guan","Zhengguang Zhou","Teng Hu","Youliang Zhang","Yuan Zhou","Xin Li","Qinglin Lu","Zhibo Chen"],"published":"2026-06-29T17:38:15Z","updated":"2026-06-29T17:38:15Z","abstract_url":"https://arxiv.org/abs/2606.30599v1","html_url":"https://arxiv.org/html/2606.30599v1","pdf_url":"https://arxiv.org/pdf/2606.30599v1.pdf","matched_keywords":["video"],"source_used":"html","source_text_chars":45019,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video 相关；摘要显示其主要贡献为：Existing instruction-based video editing datasets commonly focus on single-task appearance editing, failing to meet the complex creative demands of real-world scenarios. To bridge this gap, we present Goku, a large-scale dataset featuring 2 million high-quali...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-30T04:58:52+00:00","status":"fallback"},"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30598v1","title":"Towards in-the-wild Egocentric 3D Hand-Object Pose Estimation","abstract":"Estimating accurate 3D hand-object pose from in-the-wild egocentric RGB remains challenging due to severe occlusions and ambiguous contact. Existing learning-based methods often struggle to generalise to in-the-wild scenes and are limited by the scarcity of supervision. We address these issues with two contributions. First, we introduce EPIC-Contact, an in-the-wild egocentric dataset of 2.3K clips (62.3K frames) with dense, bijective 3D hand-object contact correspondences and posed meshes. Second, we propose HOPformer, an end-to-end transformer that jointly predicts bi-manual hand and object pose in a single forward pass. A cross-attention decoder conditions object features on hand priors, producing robust pose estimation. We test HOPformer on the in-lab 3D dataset, ARCTIC, as well as our newly introduced EPIC-Contact dataset. HOPformer reaches 82.4% success rate on ARCTIC (+6.2 pts over current SOTA). On EPIC-Contact, it nearly doubles the success rate while reducing contact deviation by 75%. EPIC-Contact, HOPformer code and checkpoints are released: https://sid2697.github.io/epic-contact.","authors":["Siddhant Bansal","Zhifan Zhu","Shashank Tripathi","Jiahe Zhao","Michael J. Black","Dima Damen"],"published":"2026-06-29T17:38:12Z","updated":"2026-06-29T17:38:12Z","abstract_url":"https://arxiv.org/abs/2606.30598v1","html_url":"https://arxiv.org/html/2606.30598v1","pdf_url":"https://arxiv.org/pdf/2606.30598v1.pdf","matched_keywords":["3d"],"source_used":"html","source_text_chars":87321,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d 相关；摘要显示其主要贡献为：Estimating accurate 3D hand-object pose from in-the-wild egocentric RGB remains challenging due to severe occlusions and ambiguous contact. Existing learning-based methods often struggle to generalise to in-the-wild scenes and are limited by the scarcity of s...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-30T04:58:52+00:00","status":"fallback"},"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30597v1","title":"Learning from Reliable Latent Prompts for Visual Recognition with Missing Modalities","abstract":"Large-scale multimodal models (LMMs) have achieved superior performance in visual recognition by synergizing information across diverse, massive-scale paired modalities. In real-world scenarios, however, missing-modality inputs are ubiquitous, causing models optimized for modality-complete data to exhibit precipitous performance degradation. Existing research has introduced prompt learning to mitigate this issue, typically by generating dynamic prompts from instance-level features, regardless of whether the input modalities are complete or partially absent. However, such input-conditioned strategies are hindered by the escalating unreliability of instance-level features; as higher missing rates increase the proportion of incomplete modalities, the resulting instability in prompt learning limits the model's performance. To address this limitation, we hypothesize that learnable latent prompts themselves encapsulate stable, modality-intrinsic priors that are decoupled from corrupted inputs. Consequently, we propose a novel paradigm: Learning from Reliable Latent Prompts. Unlike prior methods, we model input-agnostic learnable prompts as stable latent anchors that enable robust guidance and effective cross-modal knowledge compensation, even under extreme missing rates (e.g., 90%). Empirical results across three benchmark datasets demonstrate that our \"learn-from-latent-prompts\" approach achieves state-of-the-art performance across a wide range of missing-modality scenarios. Extensive experiments further confirm the effectiveness of this paradigm in providing a robust solution to the missing-modality problem.","authors":["Taixi Chen","Nancy Guo"],"published":"2026-06-29T17:36:47Z","updated":"2026-06-29T17:36:47Z","abstract_url":"https://arxiv.org/abs/2606.30597v1","html_url":"https://arxiv.org/html/2606.30597v1","pdf_url":"https://arxiv.org/pdf/2606.30597v1.pdf","matched_keywords":["instance","multimodal"],"source_used":"html","source_text_chars":58458,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 instance, multimodal 相关；摘要显示其主要贡献为：Large-scale multimodal models (LMMs) have achieved superior performance in visual recognition by synergizing information across diverse, massive-scale paired modalities. In real-world scenarios, however, missing-modality inputs are ubiquitous, causing models...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-30T04:58:52+00:00","status":"fallback"},"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30576v1","title":"Beyond 2D Matching: A Unified Single-Stage Framework for Geometry-Aware Cross-View Object Geo-Localization","abstract":"Cross-view object geo-localization (CVOGL) aims to locate a target object from a query view (e.g., ground or drone) within a geo-tagged reference image (e.g., satellite). Existing approaches heavily rely on 2D appearance matching and are constrained by limited datasets lacking geometric metadata, diverse prompts, and standard field-of-view imagery. To address these intertwined challenges, we first introduce \\dataset, a large-scale, high-fidelity building dataset comprising over 220,000 ground-satellite and drone-satellite pairs. It provides multi-modal prompts (points, boxes, masks) and camera poses to enable flexible target referring and explicit spatial modeling. Furthermore, we propose a novel single-stage Geometry-Aware Geo-localization framework (GAGeo), built upon the permutation-equivariant 3D foundation model $π^3$. By seamlessly integrating visual features, referring prompts, and learnable task tokens, our model adapts the inherited 3D prior to jointly predict bounding boxes, segmentation masks, and camera poses in a single forward pass. Additionally, we introduce a contrastive loss that utilizes the satellite view as a universal anchor, implicitly aligning ground and drone representations to enable zero-shot ground-to-drone localization without requiring triplet training data. Extensive experiments demonstrate that our approach significantly outperforms state-of-the-art methods, exhibiting exceptional generalization ability in unseen scenes and novel cross-view setups.","authors":["Liyao Wang","Ruipu Wu","Haojun Xu","Lei Shi","Linjiang Huang","Si Liu"],"published":"2026-06-29T17:19:49Z","updated":"2026-06-29T17:19:49Z","abstract_url":"https://arxiv.org/abs/2606.30576v1","html_url":"https://arxiv.org/html/2606.30576v1","pdf_url":"https://arxiv.org/pdf/2606.30576v1.pdf","matched_keywords":["3d","representation"],"source_used":"html","source_text_chars":45437,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d, representation 相关；摘要显示其主要贡献为：Cross-view object geo-localization (CVOGL) aims to locate a target object from a query view (e.g., ground or drone) within a geo-tagged reference image (e.g., satellite). Existing approaches heavily rely on 2D appearance matching and are constrained by limite...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-30T04:58:53+00:00","status":"fallback"},"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30557v1","title":"EcoVideo: Entropy-Orchestrated Video Generation Paradigm in Cloud-Edge Dynamics","abstract":"DiT video generation is latency-intensive due to iterative full-frame denoising, while prior cloud-edge methods largely rely on static inter-step decoupling and cannot leverage inter-frame similarity or adapt to system dynamics. We propose EcoVideo, an entropy-orchestrated framework for dynamic inter-frame decoupling: early-stage self-attention entropy provides a training-free estimate of frame-wise information density for frame selection; a cloud large model denoises sparse high-entropy keyframes; and an edge lightweight model reconstructs the remaining frames via motion-aware interpolation with refinement for temporal stability. EcoVideo further adapts the keyframe budget and edge refinement depth to real-time bandwidth and compute availability, optimizing end-to-end latency under constraints. Experiments on representative DiT video generators show improved quality--efficiency trade-offs and up to 2.9x end-to-end speedup in low-bandwidth, compute-limited edge settings. Code is available at https://github.com/IF-LAB-PKU/EcoVideo.","authors":["Jiayu Chen","Hengyi Zhang","Maoliang Li","Minyu Li","Zihao Zheng","Xuanzhe Liu","Guojie Luo","Xiang Chen"],"published":"2026-06-29T16:51:56Z","updated":"2026-06-29T16:51:56Z","abstract_url":"https://arxiv.org/abs/2606.30557v1","html_url":"https://arxiv.org/html/2606.30557v1","pdf_url":"https://arxiv.org/pdf/2606.30557v1.pdf","matched_keywords":["video"],"source_used":"html","source_text_chars":46822,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video 相关；摘要显示其主要贡献为：DiT video generation is latency-intensive due to iterative full-frame denoising, while prior cloud-edge methods largely rely on static inter-step decoupling and cannot leverage inter-frame similarity or adapt to system dynamics. We propose EcoVideo, an entrop...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-30T04:58:53+00:00","status":"fallback"},"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30552v1","title":"Training Vision-Language-Action Models with Dense Embodied Chain-of-Thought Supervision","abstract":"Cross-embodiment transfer in vision-language-action (VLA) models remains challenging because low-level state and action spaces differ fundamentally across robot platforms. We observe that the high-level cognitive process underlying manipulation, including scene perception, object identification, task planning, and sub-task decomposition, is largely shared across embodiments. Based on this observation, we present ZR-0, a 2.6 billion parameter end-to-end VLA model that uses dense Embodied Chain-of-Thought (ECoT) supervision to align cross-embodiment representations within the vision-language model (VLM). ZR-0 adopts a dual-stream architecture: a pre-trained VLM (System 2) generates structured ECoT reasoning during training, while a Diffusion Transformer-based action expert (System 1) produces continuous action chunks via flow matching. The two components are coupled through cross-attention, with an attention mask that restricts the action expert to input prompt features only, enabling ECoT generation to be entirely skipped at inference without any performance loss. ZR-0 is pre-trained on ProcCorpus-60M, a large-scale dataset comprising approximately 60 million frames (approximately 1,000 hours) from over 400K trajectories, with dense ECoT annotations covering 96.8% of all frames. We evaluate ZR-0 on three simulation benchmarks spanning single-arm (LIBERO), bimanual (RoboTwin 2.0), and humanoid (RoboCasa GR-1 Tabletop) embodiments, as well as real-world experiments on the xArm platform, demonstrating strong performance across all settings. Code and model checkpoints are available at https://github.com/RUCKBReasoning/ZR-0.","authors":["Haoyang Li","Guanlin Li","Youhe Feng","Chen Zhao","Zhuoran Wang","Yang Li","Qizhe Wei","Shifeng Bao","Haitao Shen","Yihan Zhao","Tong Yang","Jing Zhang"],"published":"2026-06-29T16:48:48Z","updated":"2026-06-29T16:48:48Z","abstract_url":"https://arxiv.org/abs/2606.30552v1","html_url":"https://arxiv.org/html/2606.30552v1","pdf_url":"https://arxiv.org/pdf/2606.30552v1.pdf","matched_keywords":["representation","diffusion"],"source_used":"html","source_text_chars":67553,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation, diffusion 相关；摘要显示其主要贡献为：Cross-embodiment transfer in vision-language-action (VLA) models remains challenging because low-level state and action spaces differ fundamentally across robot platforms. We observe that the high-level cognitive process underlying manipulation, including sce...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-30T04:58:53+00:00","status":"fallback"},"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30545v1","title":"StereoGS: Sparse-View 3D Gaussian Splatting via Stereo Priors","abstract":"3D Gaussian Splatting (3DGS) has achieved remarkable success in real-time novel view synthesis, yet it suffers from severe overfitting under sparse-view settings due to insufficient geometric constraints. While recent methods introduce monocular depth priors to mitigate this, they inherently struggle with scale ambiguity and cross-view inconsistency, leading to defective geometry. In this paper, we propose StereoGS, a novel sparse-view 3DGS framework that integrates stereo priors to establish reliable binocular consistency. Unlike scale-agnostic monocular constraints, StereoGS introduces a Stereo Depth Regularization by constructing virtual stereo pairs during optimization and leveraging a foundation stereo model to enforce absolute scale and binocular-consistent structures. To further suppress overfitting and eliminate redundant primitives, we design a Gradient-Aware Opacity Decay strategy that dynamically penalizes Gaussians based on their relative opacity gradient magnitudes. Combined with a Consistency-Aware Dense Initialization using zero-shot multi-view depth estimation, StereoGS effectively anchors primitives to accurate scene surfaces. Extensive experiments on LLFF, DTU, Mip-NeRF360, and Blender datasets demonstrate that StereoGS achieves state-of-the-art performance in sparse-view settings without incurring any additional inference overhead. Project Page: https://stringerywh00.github.io/StereoGS_project_page/","authors":["Wenhao Yuan","Yiyuan Ge","Deli Cai"],"published":"2026-06-29T16:45:57Z","updated":"2026-06-29T16:45:57Z","abstract_url":"https://arxiv.org/abs/2606.30545v1","html_url":"https://arxiv.org/html/2606.30545v1","pdf_url":"https://arxiv.org/pdf/2606.30545v1.pdf","matched_keywords":["3d"],"source_used":"html","source_text_chars":66340,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d 相关；摘要显示其主要贡献为：3D Gaussian Splatting (3DGS) has achieved remarkable success in real-time novel view synthesis, yet it suffers from severe overfitting under sparse-view settings due to insufficient geometric constraints. While recent methods introduce monocular depth priors...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-30T04:58:53+00:00","status":"fallback"},"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30537v1","title":"Learning from Mistakes: Rollout-Retrieval Lifelong Policy Learning for Autonomous Driving","abstract":"Autonomous driving policies should be able to improve continually as deployment exposes them to increasingly diverse and long-tail traffic situations. However, most learning-based policies are trained or fine-tuned on expert demonstrations and then rely largely on generalization to handle challenging closed-loop scenarios, lacking an explicit mechanism to correct and retain the mistakes exposed in these scenarios. This paper studies autonomous driving policy improvement from a lifelong learning perspective: Can a pretrained policy improve continually by accumulating corrective knowledge derived from its own mistakes, while retaining previously acquired driving competence? To answer this question, we propose Rollout-Retrieval Lifelong Policy Learning (R$^2$LPL), a policy learning framework that retrieves corrective targets from recoverable policy-induced mistakes and retains the resulting knowledge through lifelong policy learning. R^2LPL addresses a key bottleneck in continual policy improvement: closed-loop mistakes reveal where the policy is weak, but do not directly specify what the policy should learn. By filtering recoverable mistake-related states and retrieving feasible corrective targets, R$^2$LPL turns sparse failure evidence into compact supervised knowledge for stable and sample-efficient policy improvement. We evaluate R$^2$LPL on large-scale closed-loop nuPlan benchmarks. With only a few rollout and continual-learning cycles, R$^2$LPL elevates a learning-based planner with moderate initial performance to state-of-the-art performance across the evaluated benchmarks, especially on the challenging and long-tail Test14-hard split. These results demonstrate the effectiveness of R$^2$LPL in converting recoverable closed-loop mistakes into corrective knowledge for sustained policy improvement.","authors":["Cheng Gong","Haoyang Wang","Chao Lu","Zirui Li","Jianwei Gong"],"published":"2026-06-29T16:37:50Z","updated":"2026-06-29T16:37:50Z","abstract_url":"https://arxiv.org/abs/2606.30537v1","html_url":"https://arxiv.org/html/2606.30537v1","pdf_url":"https://arxiv.org/pdf/2606.30537v1.pdf","matched_keywords":["retrieval"],"source_used":"html","source_text_chars":92633,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 retrieval 相关；摘要显示其主要贡献为：Autonomous driving policies should be able to improve continually as deployment exposes them to increasingly diverse and long-tail traffic situations. However, most learning-based policies are trained or fine-tuned on expert demonstrations and then rely large...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-30T04:58:53+00:00","status":"fallback"},"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30534v1","title":"Orca: The World is in Your Mind","abstract":"We introduce Orca, an initial instantiation of a general world foundation model. Orca learns a unified world latent space from multimodal world signals and exposes it through multimodal readout interfaces. Rather than optimizing isolated next-token, next-frame, or next-action prediction, we are centered on Next-State-Prediction modeling, offering a unified state-transition modeling route toward understanding, predicting, and acting upon the world. Orca learns through two complementary paradigms: unconscious learning captures dense natural state transitions from continuous videos, and conscious learning models sparse meaningful state transitions by language-described events and VQA supervision. For pre-training, we construct a large-scale world-learning inventory data, including 125K hours of video data and 160M event annotations. After pre-training, Orca learns a unified world latent space. To examine whether the learned latent supports downstream, we evaluate it by three representative downstream readouts: text generation, image prediction, and embodied action generation. Orca's backbone is frozen, and only the lightweight modality-specific decoders are trainable. Experiments show the scalability of the proposed paradigm and verify that stronger world latent enables stronger downstream readouts. Orca outperforms similar-sized specialized baselines. These results show that Orca, as a general world foundation model, presents a promising approach to understanding, predicting, and acting upon the world. Finally, we discuss the current limitations, aiming to provide useful insights and inspiration for the community.","authors":["Yihao Wang","Yuheng Ji","Mingyu Cao","Yanqing Shen","Runze Xiao","Huaihai Lyu","Senwei Xie","Euan Liu","Klara Tian","Tianfeng Long","Yichi Zhang","Zhengliang Cai","Ruike Chen","Jifan Zhao","Ruochuan Shi","Zihan Tang","Jing Lyu","Wenxing Tan","Ningbo Zhang","Yangtao Hu","Yuming Gao","Xiansheng Chen","Junkai Zhao","Congsheng Xu","Boan Zhu","Ziqi Wang","Yupu Feng","Qiongqiong Zhang","Yingli Zhao","Yulong Ao","Shaoxuan Xie","You Liu","Guocai Yao","Leiduo Zhang","Xiaodan Liu","Yunyan Zhang","Yance Jiao","Xinyan Yang","Jiaxing Wei","Xu Liu","Tengfei Pan","Shaokai Nie","Chunlei Men","Sen Cui","Xiaojie Jin","Hongyang Li","Jianlan Luo","Yao Mu","Yunchao Wei","Jun Yan","Hang Zhao","Xiaolong Zheng","Jiaming Li","Yonghua Lin","Tiejun Huang","Zhongyuan Wang","Pengwei Wang"],"published":"2026-06-29T16:36:10Z","updated":"2026-06-29T16:36:10Z","abstract_url":"https://arxiv.org/abs/2606.30534v1","html_url":"https://arxiv.org/html/2606.30534v1","pdf_url":"https://arxiv.org/pdf/2606.30534v1.pdf","matched_keywords":["video","multimodal"],"source_used":"html","source_text_chars":100192,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, multimodal 相关；摘要显示其主要贡献为：We introduce Orca, an initial instantiation of a general world foundation model. Orca learns a unified world latent space from multimodal world signals and exposes it through multimodal readout interfaces. Rather than optimizing isolated next-token, next-fram...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-30T04:58:53+00:00","status":"fallback"},"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30528v1","title":"$μ$Flow: Leveraging Average Images for Improving Generalisation of Deepfake Faces Detectors","abstract":"Current generative models, including GANs and diffusion models, have reached an outstanding level of photorealism, posing significant risks to privacy and security. To ensure real-world applicability, deepfake detectors must generalise effectively to unseen generators. However, most existing approaches rely on supervised training with both real and fake images, which limits their generalisation especially across generators categories (e.g. GANs vs DMs). In this work, we introduce $μ$Flow, a one-class deepfake detector trained only on real images without relying on pseudo-deepfakes or synthetic artifacts. Our approach builds on the observation that averaging multiple images amplifies consistent generative traces, producing highly discriminative feature representations. We leverage this property by modelling the distribution of features extracted from averaged images and training a normalizing flow to align the feature space of individual images with this distribution. This alignment yields a likelihood-based criterion that separates real and fake samples while promoting strong generalisation. We evaluate $μ$Flow on a fully out-of-distribution setting, where both real and fake datasets are unseen during training. Experimental results show that our method significantly outperforms SOTA detectors. Project page: https://opontorno.github.io/MuFlow.","authors":["Orazio Pontorno","Mattia Litrico","Luca Guarnera","Mario Valerio Giuffrida","Sebastiano Battiato"],"published":"2026-06-29T16:31:57Z","updated":"2026-06-29T16:31:57Z","abstract_url":"https://arxiv.org/abs/2606.30528v1","html_url":"https://arxiv.org/html/2606.30528v1","pdf_url":"https://arxiv.org/pdf/2606.30528v1.pdf","matched_keywords":["representation","diffusion"],"source_used":"html","source_text_chars":49263,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation, diffusion 相关；摘要显示其主要贡献为：Current generative models, including GANs and diffusion models, have reached an outstanding level of photorealism, posing significant risks to privacy and security. To ensure real-world applicability, deepfake detectors must generalise effectively to unseen g...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-30T04:58:53+00:00","status":"fallback"},"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30514v1","title":"3D Scene-Adaptive Trajectory-Controllable Human Image Animation with Camera Movement","abstract":"Human image animation, which aims to generate a video of a reference subject following a provided action sequence, has received increasing research interest. With the development of diffusion-based/flow-based video foundation models, existing animation works have began to upgrade the guidance information from 2D skeleton/pose to 3D modeling conditions. Despite achieving reasonable results, these approaches face challenges in synthesizing trajectory-controllable human motion within natural scene under changed camera views. In this work, we present a scene-adaptive human image animation framework that controls both human motion and camera trajectories within a reconstructed 3D environment for video generation. To achieve this, we first develop a ground-adaptive 3D motion retargeting approach to enable user-friendly motion trajectory control adapting to the changes of elevations of ground and orientations automatically. Then we design a viewpoint-adaptive latent fusion mechanism to inject point-cloud geometric priors through scene-visibility masking into the generative process, providing precise guidance of viewpoint changes under camera control. Experiments on two standard human image animation benchmark datasets demonstrate remarkable improvements of our method over the state of the arts in related video generation metics. Project page: https://robinhood256100.github.io/web-disp","authors":["Deyin Liu","Jicheng Xu","Lin Yuanbo Wu","Xiaowei Zhao","Xiatian Zhu","Zhe Jin","Anjan Dutta"],"published":"2026-06-29T16:22:54Z","updated":"2026-06-29T16:22:54Z","abstract_url":"https://arxiv.org/abs/2606.30514v1","html_url":"https://arxiv.org/html/2606.30514v1","pdf_url":"https://arxiv.org/pdf/2606.30514v1.pdf","matched_keywords":["video","3d","diffusion"],"source_used":"html","source_text_chars":40092,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, 3d, diffusion 相关；摘要显示其主要贡献为：Human image animation, which aims to generate a video of a reference subject following a provided action sequence, has received increasing research interest. With the development of diffusion-based/flow-based video foundation models, existing animation works...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-30T04:58:54+00:00","status":"fallback"},"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30498v1","title":"On the Faithfulness of Post-Hoc Concept Bottleneck Models","abstract":"Human decision-making interprets the world through high-level concepts, such as recognizing a bird by its belly color. To bridge the gap between opaque deep learning representations and human understanding, Post-Hoc Concept Bottleneck Models (post-hoc CBMs) project latent features onto interpretable concept spaces using auxiliary datasets or vision-language models. However, relying on target task accuracy as the primary measure of post-hoc CBM success obscures whether the learned concepts are semantically meaningful or merely predictive artifacts. For example, random concept projections can achieve competitive accuracy despite being semantically meaningless. In this work, we analyze the learned projections directly and identify two failure cases: First, for concept projections learned from auxiliary data, covariate shifts can lead to unfaithful concept representations for the target task. In particular, we provide an upper bound on the error introduced by this shift. Second, systematic label noise in surrogate concept labels generated by vision-language models leads to unfaithful projections. After formalizing these failure modes, we introduce novel metrics that decouple concept faithfulness from predictive accuracy. Our empirical results across real-world and synthetic benchmarks confirm that these metrics identify unfaithful behaviors that standard accuracy-based evaluation fails to detect.","authors":["Laines Schmalwasser","Jan Blunk","Niklas Penzel","Julia Niebling","Joachim Denzler"],"published":"2026-06-29T16:02:29Z","updated":"2026-06-29T16:02:29Z","abstract_url":"https://arxiv.org/abs/2606.30498v1","html_url":"https://arxiv.org/html/2606.30498v1","pdf_url":"https://arxiv.org/pdf/2606.30498v1.pdf","matched_keywords":["representation"],"source_used":"html","source_text_chars":119266,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation 相关；摘要显示其主要贡献为：Human decision-making interprets the world through high-level concepts, such as recognizing a bird by its belly color. To bridge the gap between opaque deep learning representations and human understanding, Post-Hoc Concept Bottleneck Models (post-hoc CBMs) p...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-30T04:58:54+00:00","status":"fallback"},"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30476v1","title":"PS-MOT: Cultivating Instance Awareness from Point Seeds for Multi-Object Tracking","abstract":"We introduce Point-supervised Multi-Object Tracking (PS-MOT) as a cost-effective alternative to traditional bounding box supervision, shifting the focus from spatial fitting to topological center-driven representation. However, PS-MOT faces challenges, e.g., spatial ambiguity and identity drift due to the lack of explicit geometric structure and scale constraints. To address these, we propose PS-Track, a hierarchical pipeline transitioning from points to instances across data, model, and loss levels. At the data level, we introduce Temporal-Feedback Prompting (TFP) to evolve points into temporally consistent pseudo-labels using negative spatial cues and motion priors. At the model level, we design the Point-Excited Wavelet Attention (PEWA) module, which leverages semantic correlations to activate high-frequency components, ``hallucinating'' object boundaries. At the loss level, Uncertainty-Guided Gaussian Learning (UGL) models pseudo-labels as probabilistic distributions, dynamically calibrating supervision intensity. Experiments on DanceTrack, EmboTrack, SportsMOT, and JRDB demonstrate that PS-Track provides a feasible and effective point-supervised alternative across diverse tracking scenarios, establishing a new state-of-the-art for point-supervised tracking. The source code is available at https://github.com/xifen523/PS-MOT.","authors":["Kai Luo","Fei Teng","Mengfei Duan","Wanjun Jia","Xu Wang","Hao Shi","Kunyu Peng","Zhiyong Li","Kailun Yang"],"published":"2026-06-29T15:36:00Z","updated":"2026-06-29T15:36:00Z","abstract_url":"https://arxiv.org/abs/2606.30476v1","html_url":"https://arxiv.org/html/2606.30476v1","pdf_url":"https://arxiv.org/pdf/2606.30476v1.pdf","matched_keywords":["representation","instance"],"source_used":"html","source_text_chars":77953,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation, instance 相关；摘要显示其主要贡献为：We introduce Point-supervised Multi-Object Tracking (PS-MOT) as a cost-effective alternative to traditional bounding box supervision, shifting the focus from spatial fitting to topological center-driven representation. However, PS-MOT faces challenges, e.g.,...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-30T04:58:54+00:00","status":"fallback"},"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30458v1","title":"Cross-Resolution Semantic Transfer for Robust Text-to-Image Retrieval in Low-Resolution Surveillance","abstract":"Text-to-image person re-identification (TIPR) retrieves target persons using natural language descriptions. However, existing methods largely overlook resolution variance in real-world surveillance. They characterize cross-resolution TIPR through two coupled failure modes: Evidence Reliability Collapse (ERC), where degraded visual tokens become unreliable for grounding fine-grained text, and Ranking Distribution Drift (RDD), where mixed-resolution galleries distort similarity neighborhoods and destabilize retrieval rankings. To address this challenge, we propose Cross-Resolution Semantic Transfer (CRST), a CLIP-style framework with three modules: resolution-conditioned reasoning, text-guided refinement and CR-RDA. Resolution-conditioned reasoning estimates token reliability to suppress corrupted evidence. Text-guided refinement injects semantic priors to recover discriminative cues. CR-RDA transfers HR neighborhood geometry to stabilize LR ranking under mixed resolutions. Experiments on CUHK-PEDES, ICFG-PEDES, and RSTPReid show that CRST improves ultra-low-resolution Rank-1 and mAP on average by 5.7% and 5.3%, while stabilizing mixed-resolution retrieval without sacrificing high-resolution accuracy.The code will be made publicly available.","authors":["Wenjie Qian","Bin Yang","Xiao Wang","Wenke Huang","Ling Mei","Xin Xu","Mang Ye"],"published":"2026-06-29T15:24:03Z","updated":"2026-06-29T15:24:03Z","abstract_url":"https://arxiv.org/abs/2606.30458v1","html_url":"https://arxiv.org/html/2606.30458v1","pdf_url":"https://arxiv.org/pdf/2606.30458v1.pdf","matched_keywords":["retrieval"],"source_used":"html","source_text_chars":44381,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 retrieval 相关；摘要显示其主要贡献为：Text-to-image person re-identification (TIPR) retrieves target persons using natural language descriptions. However, existing methods largely overlook resolution variance in real-world surveillance. They characterize cross-resolution TIPR through two coupled...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-30T04:58:54+00:00","status":"fallback"},"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30456v1","title":"Vision-Language-Action Models: Experimental Insights from a Real-World UR5 Platform","abstract":"This project investigates whether recent Vision-Language-Action (VLA) models can be transferred from controlled research benchmarks to a real-world robotic platform, specifically a UR5e manipulator, in a reproducible and operationally meaningful manner. The work integrates real-robot data acquisition, dataset engineering (compatible with the RLDS format), and the fine-tuning and deployment of OpenVLA and OpenVLA-OFT models, with systematic validation of action representations and control interfaces. The project resulted in several foundational assets: (i) a complete real-robot data acquisition pipeline, (ii) a dataset conversion workflow aligned with RLDS standards, (iii) an initial fine-tuning and inference infrastructure for VLA models, and (iv) a structured set of experimental observations grounded in real-robot trials. These elements collectively establish a reproducible framework for evaluating learning-based manipulation systems beyond simulation. Empirically, the experiments reveal a consistent gap between promising offline indicators and unstable closed-loop behavior on the physical system: this gap cannot be attributed solely to model limitations, it is strongly influenced by action semantics, coordinate frame conventions, temporal alignment between modalities, image preprocessing consistency, and dataset coverage and quality. These observations lead to a key interpretation: the successful deployment of VLA systems in real-world settings depends less on incremental improvements in model capacity and more on precise control of the entire data-model-control pipeline. The project reframes VLA-based robotics from a primarily model-centric challenge to a system-level problem; it highlights the difficulty of running robust task execution on the real robot and provides a clear, experimentally grounded understanding of the conditions required for reliable deployment.","authors":["Mathilde Hochedel","Marc Lalonde"],"published":"2026-06-29T15:23:34Z","updated":"2026-06-29T15:23:34Z","abstract_url":"https://arxiv.org/abs/2606.30456v1","html_url":"https://arxiv.org/html/2606.30456v1","pdf_url":"https://arxiv.org/pdf/2606.30456v1.pdf","matched_keywords":["representation"],"source_used":"html","source_text_chars":87652,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation 相关；摘要显示其主要贡献为：This project investigates whether recent Vision-Language-Action (VLA) models can be transferred from controlled research benchmarks to a real-world robotic platform, specifically a UR5e manipulator, in a reproducible and operationally meaningful manner. The w...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-30T04:58:54+00:00","status":"fallback"},"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30436v1","title":"Robust and Efficient Monocular 3D Gaussian SLAM for Kilometer-Scale Outdoor Scenes","abstract":"Scaling monocular 3D Gaussian Splatting (3DGS) SLAM to kilometer-level outdoor environments poses two tightly coupled challenges: fragile long-term pose tracking and excessive memory overhead during large-scale mapping. In this paper, we propose KiloGS-SLAM, a highly efficient and robust monocular 3DGS-SLAM system that jointly addresses both bottlenecks. Since high-fidelity scene reconstruction fundamentally relies on drift-free camera poses, we first introduce a motion-adaptive hybrid tracking module. This module features a condition-triggered three-tier solving pipeline. It dynamically switches between Essential matrix and PnP models to handle geometric degeneracies. An on-demand foundation model can also be activated to rescue the trajectory from catastrophic drift. To ensure the system can sustain these long trajectories without memory exhaustion, we subsequently design a lifecycle-managed Gaussian mapping strategy. By integrating probabilistic initialization with chunk-based multi-view densification and pruning, this full-pipeline optimization effectively reduces primitive redundancy while preserving high-frequency details. Together, the robust tracking guarantees the geometric foundation required for accurate mapping, while the memory-efficient lifecycle-managed mapping enables large-scale operation. Extensive experiments across three challenging outdoor datasets demonstrate that our approach achieves state-of-the-art tracking accuracy and rendering quality, successfully scaling to sequences of over 10,000 frames on a single GPU.","authors":["Sicheng Yu","Dongxu Shen","Beizhen Zhao","Guanzhi Ding","Hao Wang"],"published":"2026-06-29T15:12:18Z","updated":"2026-06-29T15:12:18Z","abstract_url":"https://arxiv.org/abs/2606.30436v1","html_url":"https://arxiv.org/html/2606.30436v1","pdf_url":"https://arxiv.org/pdf/2606.30436v1.pdf","matched_keywords":["3d"],"source_used":"html","source_text_chars":75699,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d 相关；摘要显示其主要贡献为：Scaling monocular 3D Gaussian Splatting (3DGS) SLAM to kilometer-level outdoor environments poses two tightly coupled challenges: fragile long-term pose tracking and excessive memory overhead during large-scale mapping. In this paper, we propose KiloGS-SLAM,...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-30T04:58:54+00:00","status":"fallback"},"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30421v1","title":"OWMDrive: Causality-Aware End-to-End Autonomous Driving via 4D Occupancy World Model","abstract":"Autonomous driving systems are steadily moving toward end-to-end paradigms to mitigate the limited adaptability of rule-based pipelines in complex traffic environments. However, most existing learning-based methods still make decisions from static representations of the current scene, without explicit future rollouts or modeling of the temporal causal dynamics in traffic interactions. This limitation often results in unstable or overly conservative planning under high-uncertainty conditions, such as occlusions and unexpected events. To overcome these challenges, we introduce OWMDrive, a generative end-to-end driving framework built upon an Occupancy World Model for multi-step 3D occupancy forecasting, which serves as a conditional prior to guide diffusion-based planning. Conditioned on both current observations and predicted future states, the planner iteratively refines trajectory candidates to generate a reinforced driving trajectory. By explicitly modeling scene evolution over future horizons, OWMDrive captures key spatiotemporal causal dependencies, which leads to more foresighted and robust trajectory generation. Extensive experiments demonstrate that OWMDrive significantly improves planning reliability and safety, especially in challenging and partially observable driving scenarios.","authors":["Junjie Cheng","Ruiqi Song","Ye Wu","Nanxing Zeng","Ximiao Li","Yunfeng Ai"],"published":"2026-06-29T15:05:41Z","updated":"2026-06-29T15:05:41Z","abstract_url":"https://arxiv.org/abs/2606.30421v1","html_url":"https://arxiv.org/html/2606.30421v1","pdf_url":"https://arxiv.org/pdf/2606.30421v1.pdf","matched_keywords":["3d","representation","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30417v1","title":"Beyond Point Estimates for Glaucoma Visual Field Forecasting with Diffusion Models","abstract":"Forecasting visual fields (VFs) is critical for personalized monitoring and treatment planning in glaucoma. This is inherently uncertain due to heterogeneous disease progression and measurement variability, yet most existing methods produce single deterministic predictions that fail to represent this uncertainty. We formulate VF forecasting as a probabilistic prediction problem and the use of conditioned denoising diffusion models to generate distributions of plausible future VFs from longitudinal observations with irregular follow-up intervals. Experiments on two independent VF cohorts show that diffusion-based predictions produce well-calibrated distributions for clinically relevant VF measures. When reduced to a standard point-estimate, the proposed approach achieves state-of-the-art accuracy compared to clinical baselines and prior learning-based methods. Our results highlight the advantages of distributional modeling for VF forecasting and support a shift from point-estimate prediction toward uncertainty-aware, clinically interpretable risk assessment in glaucoma.","authors":["Marta Colmenar Herrera","Pablo Márquez Neila","Şerife Seda Kucur Ergünay","Martin S. Zinkernagel","Raphael Sznitman"],"published":"2026-06-29T15:04:50Z","updated":"2026-06-29T15:04:50Z","abstract_url":"https://arxiv.org/abs/2606.30417v1","html_url":"https://arxiv.org/html/2606.30417v1","pdf_url":"https://arxiv.org/pdf/2606.30417v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30408v1","title":"SA-Homo: Scale Adaptive Homography Estimation for Scale Variation Scenarios","abstract":"Homography estimation, as one of the fundamental problems in computer vision, remains challenged by scale variation scenarios where image pairs potentially exhibit significant scale discrepancies. Existing deep learning frameworks frequently suffer from a significant performance degradation in such cases, as they rely on limited displacement assumptions and local feature consistency that might not hold under large scale gaps. In this paper, we propose SA-Homo, a novel scale-adaptive homography estimation framework designed to achieve robust alignment across a wide range of scale discrepancy ratios. We adopt a hierarchical scale alignment strategy that transitions from the global perspective with a heavy module to a local perspective with a light module. Specifically, we introduce the Scale-aware Discrepancy Bridging Module (SDBM) for initial alignment, which utilizes a Multi-scale Linear Attention Cascade (MLAC) to capture long-range dependencies and mitigate feature inconsistencies, along with a global Cross-scale Similarity Matrix Block (CSMB) for scale robust correlation representation. Once the initial scale gap is bridged, a lightweight Iterative Homography Estimation Refinement Module (IHERM) progressively polishes the result using local correlations. To facilitate this research, we contribute the HMSA dataset, a high-resolution, multi-modal satellite benchmark specifically tailored for scale-variant challenges. Extensive experiments demonstrate that SA-Homo maintains high precision even under 8$\\times$ scale discrepancies, outperforming state-of-the-art methods in both conventional scale-similar scenarios and challenging scale variation scenarios. Code and collected datasets are available at https://github.com/shangxuanx330/SA_Homo","authors":["Shangxuan Xie","Haifeng Wu","Yuhang Wang","Huarong Jia","Wen Li"],"published":"2026-06-29T14:51:53Z","updated":"2026-06-29T14:51:53Z","abstract_url":"https://arxiv.org/abs/2606.30408v1","html_url":"https://arxiv.org/html/2606.30408v1","pdf_url":"https://arxiv.org/pdf/2606.30408v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30393v1","title":"SADL: What to Ignore? A Benchmark for Subject-Aware Distractor Localization","abstract":"Photographs frequently contain \\emph{visual distractors} besides foregrounds and backgrounds of the intended subject, competing for attention and weakening composition. While modern editing tools streamline object removal, identifying which objects to remove remains a mostly manual process. Existing saliency models and open-vocabulary detectors operate without subject awareness, failing to adapt to shifting user intent. Furthermore, context-agnostic removal may disrupt the scene's semantic coherence (e.g., keep the person but remove the chair they are sitting on). To address these limitations, we formalize the task of subject-aware distractor localization, which identifies distractors while retaining compositionally essential objects. This paper introduces \\textsc{SADL}, the first real-world benchmark for this task, comprising 1,800 subject-aware cases across 1,000 photographs to enable systematic evaluation and facilitate future research. In total, there are 14,617 annotated candidates, including a robust set of 1,938 hard negatives to stress-test exclusion calibration. We evaluate seven proprietary and open-weight Vision-Language Models (VLMs) on a sequential pipeline of distractor classification followed by exclusion filtering, structured around five inclusion factors and three contextual exclusion rules. Our analysis reveals that VLMs are highly capable of identifying distractors, but then over-apply exclusion, which systematically suppresses true distractors at scale. By exposing this critical bottleneck, \\textsc{SADL} provides a foundational diagnostic tool to advance subject-conditioned reasoning in multimodal systems.","authors":["Cao-Tri Nguyen","Nguyen-Khoa Luong","Vinh-Tiep Nguyen","Minh-Triet Tran"],"published":"2026-06-29T14:45:38Z","updated":"2026-06-29T14:45:38Z","abstract_url":"https://arxiv.org/abs/2606.30393v1","html_url":"https://arxiv.org/html/2606.30393v1","pdf_url":"https://arxiv.org/pdf/2606.30393v1.pdf","matched_keywords":["multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30378v1","title":"OmniCoT: A Benchmark for Global and Multi-Step Panoramic Reasoning","abstract":"Multimodal Large Language Models (MLLMs) have demonstrated promising spatial reasoning capabilities, while these abilities remain underexplored in the emerging visual modality of panoramic imagery. The full 360°$\\times$180° field of view of panoramas essentially supports complex global multi-step reasoning, which is also the fundamental advantage of panoramas in applications such as embodied intelligence. However, existing panoramic benchmarks largely focus on simplistic queries that rely on local cues or single-/few-step reasoning, thereby ignoring the fundamental advantage of panoramas and failing to fully exploit their potential. To address this gap, we introduce OmniCoT, a panoramic spatial reasoning suite designed to enable MLLMs to use global evidence and perform multi-step inference across viewpoints. It includes OmniCoT-B (6.7K data) for evaluation, which measures both answer accuracy and reasoning quality, OmniCoT-Real (1K data) as a manually annotated real-world subset to quantify the Sim-to-Real gap. For training, OmniCoT-T (14.3K data) is purpose-built with structured stepwise Chain-of-Thought annotations that explicitly link intermediate reasoning steps to panoramic evidence. Based on OmniCoT-T, we introduce OmniCoT-R1 and adopt a two-stage training strategy tailored to the geometrically complex panoramic space, where Supervised Fine-tuning (SFT) anchors reasoning to panoramic evidence (e.g., bearings, proximity) and GRPO penalizes geometrically incoherent paths to consolidate global 360° spatial consistency. Through OmniCoT, we aim to recalibrate the difficulty of panoramic spatial reasoning to better align with the intrinsic capabilities of panoramic imagery, thereby fostering meaningful progress in this research area.","authors":["Haocong He","Chenfei Liao","Zichen Wen","Zihao Dongfang","Xu Zheng","Bin Ren","Chang Su","Zixin Zhang","Harold Haodong Chen","Hongfei Zhang","Weijia Li","Kailun Yang","Conghui He","Xuming Hu","Nicu Sebe","Linfeng Zhang"],"published":"2026-06-29T14:38:20Z","updated":"2026-06-29T14:38:20Z","abstract_url":"https://arxiv.org/abs/2606.30378v1","html_url":"https://arxiv.org/html/2606.30378v1","pdf_url":"https://arxiv.org/pdf/2606.30378v1.pdf","matched_keywords":["multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30376v1","title":"FlowAWR: Online Adaptive Flow Reinforcement via Advantage-Weighted Rectification","abstract":"Aligning generative flow models on continuous spaces via online reinforcement learning is constrained by intractable trajectory likelihoods. Existing density-approximated policy gradient methods rely on stochastic SDE samplers to construct tractable transition kernels, which introduce training-inference inconsistencies and necessitates Classifier-Free Guidance (CFG). While implicit frameworks such as DiffusionNFT directly optimize forward-process velocity fields, its heuristic fixed-magnitude corrections prevent optimization strength from relative intra-group quality. We propose \\textit{Flow Advantage-Weighted Rectification} (\\textbf{FlowAWR}), a paradigm that recasts continuous generative policy optimization as supervised regression toward a theoretically optimal velocity field. Starting from the optimal policy of a KL-constrained reward maximization, FlowAWR derives the optimal velocity field that admits a magnitude-aware, advantage-weighted rectification form, yielding SDE-free optimization and CFG-free generation. In comparative evaluations on SD3.5-Medium, FlowAWR achieves improved alignment performance alongside a 2$\\times$ to 5$\\times$ convergence acceleration over DiffusionNFT (e.g., reaching a 24.12 PickScore in 1.2k steps, versus 23.82 in 2.0k steps for DiffusionNFT and 23.50 in $>$4k steps for FlowGRPO). Under multi-reward constraints, FlowAWR sustains generation quality, satisfying structural rules while maintaining stable out-of-domain performance.","authors":["Zheming Fu","Ruizhe He","Wei Shang","Xiaoxiao Ma","Lei Wang","Chang Liu","Siming Fu"],"published":"2026-06-29T14:37:36Z","updated":"2026-06-29T14:37:36Z","abstract_url":"https://arxiv.org/abs/2606.30376v1","html_url":"https://arxiv.org/html/2606.30376v1","pdf_url":"https://arxiv.org/pdf/2606.30376v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30374v1","title":"Set-Inclusive Uncertainty Modeling for Robust Brain Tumor Segmentation","abstract":"Multimodal MRI is essential for accurate brain tumor segmentation. However, acquiring all modalities at inference is often challenging in practice, which causes intrinsic uncertainty due to unavoidable information loss. Without modeling this uncertainty, existing methods encode incomplete evidence into deterministic representations that appear plausible but lack reliability. In this regime, we propose a probabilistic representation framework that models representations as Gaussian distributions, where their mean captures task information and their variance measures uncertainty from missing evidence. To make variance reflect information deficiency, we regularize the mean from each partial configuration toward its full-modality counterpart, while scaling the variance with the discrepancy between their aligned means. We further introduce a set-inclusive strategy that exploits the hierarchical structure of modality subsets and enforces an ordering constraint to maintain their consistent uncertainty relationships. Extensive experiments on BraTS 2018 and 2020 demonstrate that our approach offers superior performance over baselines across diverse missing-modality scenarios. Code and model checkpoint are available at https://github.com/atlas-sky/SIUM.","authors":["Seunghun Baek","Jihwan Park","Jaeyoon Sim","Hoseok Lee","Seungjoo Lee","Won Hwa Kim"],"published":"2026-06-29T14:35:55Z","updated":"2026-06-29T14:35:55Z","abstract_url":"https://arxiv.org/abs/2606.30374v1","html_url":"https://arxiv.org/html/2606.30374v1","pdf_url":"https://arxiv.org/pdf/2606.30374v1.pdf","matched_keywords":["representation","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30370v1","title":"MUSE: Unlocking Timestep as Native Task Steering for One-Step Dense Prediction","abstract":"Monocular dense prediction has recently seen remarkable success by repurposing pre-trained diffusion models. This opens a promising yet challenging avenue for more efficient multi-task learning paradigm. However, existing multi-task diffusion methods often introduce parameter-heavy adapters, experts, or learnable task tokens, leading to computational redundancy. In this paper, we reveal an inherent mechanism within one-step diffusion models: the native, fixed sinusoidal timestep embedding can be repurposed as an endogenous task steering signal. Based on this discovery, we propose Multi-task Unified eStimation via timestep Embedding (MUSE), a parameter-free, single-model multi-tasking approach for dense prediction. We interpret this mechanism via Manifold Decoupling, where discrete, fixed timestep values deterministically steer the generation process towards decoupled, task-specific manifolds in the latent space. Extensive experiments across 10 datasets demonstrate that MUSE achieves highly competitive performance on both monocular depth and normal estimation, and its efficacy generalizes across U-Net and DiT architectures. Our work offers a concise and efficient path toward generalist vision models by simply unlocking the latent potential of existing generation infrastructure.","authors":["Shuo Zhou","Zhaoxin Li","Xiujuan Chai"],"published":"2026-06-29T14:34:16Z","updated":"2026-06-29T14:34:16Z","abstract_url":"https://arxiv.org/abs/2606.30370v1","html_url":"https://arxiv.org/html/2606.30370v1","pdf_url":"https://arxiv.org/pdf/2606.30370v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30355v1","title":"Residual-Guided Expert Specialization for Incomplete Multimodal Learning","abstract":"As real-world prediction systems often face missing modalities at inference, incomplete multimodal learning (IML) remains a practical challenge. While prior methods aim to learn representations robust to missing inputs, representations from incomplete modalities inevitably deviate from their full-modality counterparts due to missing evidence. To explicitly leverage these deviations, we propose MARS (Missingness-Aware Residual-guided Specialization), a mixture-of-experts framework that guides expert specialization based on how representations are reshaped by missingness. By contrasting task representations derived from incomplete inputs with their complete counterparts during training, we derive a privileged residual signal that captures this representational gap. The residual signal guides a residual router to assign samples to experts specialized for the corresponding deviation patterns. In parallel, a feature router learns to imitate this routing behavior using only incomplete inputs, enabling deployment without access to full modalities. To mitigate this train-test router gap, we develop a discrepancy-aware noise regularization that adaptively perturbs the residual router's decisions when the feature router deviates, enhancing expert robustness under imperfect imitation. Experiments on multimodal classification (CASIA-SURF, CREMA-D, UPMC Food-101) and segmentation (MCubeS) under missing scenarios show that MARS consistently surpasses baselines while remaining efficient and extensible to diverse backbones and tasks.","authors":["Seunghun Baek","Jihwan Park","Jaeyoon Sim","Minjae Jeong","Hoseok Lee","Won Hwa Kim"],"published":"2026-06-29T14:24:05Z","updated":"2026-06-29T14:24:05Z","abstract_url":"https://arxiv.org/abs/2606.30355v1","html_url":"https://arxiv.org/html/2606.30355v1","pdf_url":"https://arxiv.org/pdf/2606.30355v1.pdf","matched_keywords":["representation","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30352v1","title":"FastPano3D: Feed-Forward Indoor Panoramic 3D Reconstruction from a Single Image","abstract":"Recent advances in 3D scene reconstruction have highlighted the intricate trade-offs among rendering quality, inference efficiency, and data dependency. To address the challenge of rapidly reconstructing detailed 3D indoor scenes from minimal input, we introduce FastPano3D, an end-to-end framework that directly generates renderable 3D Gaussian representations from a single panoramic image. Unlike perspective-based methods, panoramic images inherently suffer from equirectangular projection distortions and spatially non-uniform feature distributions, making direct feed-forward Gaussian generation particularly challenging. In contrast to existing Gaussian Splatting based methods that rely on multi-view supervision or per-scene optimization, FastPano3D employs a lightweight feature encoder, adaptive Gaussian sampling, and a point-cloud-guided refinement strategy to achieve efficient and accurate scene generation without any test-time optimization. Our approach reconstructs high-fidelity 3D scenes within seconds, achieving up to 156 times faster inference than prior state-of-the-art methods such as Pano2Room, while using only half the parameters. Extensive experiments demonstrate that FastPano3D delivers rendering quality comparable to NeRF- and 3DGS-based reconstructions, establishing a new benchmark for rapid, single-view 3D scene inference.","authors":["Jianqiang Li","Liumei Zhang","Wenjia Guo","Tianlong Feng","Yongzhi Liao","Di Lu","Hanchi Ren","Jingjing Deng"],"published":"2026-06-29T14:23:12Z","updated":"2026-06-29T14:23:12Z","abstract_url":"https://arxiv.org/abs/2606.30352v1","html_url":"https://arxiv.org/html/2606.30352v1","pdf_url":"https://arxiv.org/pdf/2606.30352v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30347v1","title":"FFAvatar: Feed-Forward 4D Head Avatar Reconstruction from Sparse Portrait Images","abstract":"We present FFAvatar, a Transformer-based 3D Gaussian framework for fast construction of high-quality and animatable 4D head avatars from one or more reference portrait images. Unlike existing feed-forward approaches that require a fixed number of input views, FFAvatar supports incremental reconstruction, progressively refining the avatar representation as additional reference images become available. At the core of our method is an alternating attention mechanism that disentangles identity appearance from expression and viewpoint variations, enabling the reconstruction of a canonical 3D appearance that remains consistent across poses and facial expressions. To balance visual fidelity and computational efficiency, we introduce a sparse-to-dense learning paradigm. Coarse appearance features are first learned using sparse primitives anchored to the FLAME vertex level and are subsequently densified in the UV domain to capture fine-grained geometric and texture details. We further propose a plug-and-play motion refinement module that enables subject-specific dynamic personalization by modeling residual motion beyond parametric deformation. Extensive experiments demonstrate that FFAvatar efficiently produces high-fidelity and controllable 4D head avatars, achieving superior flexibility, driving efficiency, and identity-consistent rendering across diverse expressions and viewpoints.","authors":["Jianjiang Yao","Ke Xian","Renxiang Dai","Robert Caiming Qiu"],"published":"2026-06-29T14:21:33Z","updated":"2026-06-29T14:21:33Z","abstract_url":"https://arxiv.org/abs/2606.30347v1","html_url":"https://arxiv.org/html/2606.30347v1","pdf_url":"https://arxiv.org/pdf/2606.30347v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30344v1","title":"Early Cue Precision Shapes Visual Shortcut Learning in Controlled Cue-Manipulation Benchmarks","abstract":"Visual classifiers can achieve high matched-distribution accuracy while relying on low-level cues that fail under conflict or suppression. We test whether this failure is shaped by early cue precision: the reliability with which a low-level cue predicts the label during early learning or downstream probe fitting. Across synthetic shape-texture tasks, sequential digit training, a 10-class frozen-representation audit, and a CIFAR-10 natural-image-based texture-overlay benchmark, we manipulate object-texture match probability and evaluate matched-ID accuracy, conflict accuracy, texture-choice rate, and suppression behavior. Degraded-but-predictive input does not substitute for cue decorrelation. In 10-class digit probes, conflict accuracy drops from 0.589 under chance-like cue precision to 0.005 under target-perfect texture. In CIFAR-10 frozen probes, conflict accuracy drops from 0.569 to 0.114, while texture choice rises from 0.049 to 0.855; this ordering persists across texture-overlay strengths alpha in {0.15,0.25,0.35,0.50}. End-to-end CIFAR-10 training shows that low early cue precision improves pre-target conflict behavior, but shortcut-rich fine-tuning can rapidly overwrite this benefit. Cue decorrelation must therefore be maintained during downstream adaptation rather than treated as a one-time inoculation.","authors":["Chanho Park","Woochan Lee","Janyeong Oh","Geongho Gong","Minshu Kim","Yeachan Kwak","Seongim Choi"],"published":"2026-06-29T14:20:30Z","updated":"2026-06-29T14:20:30Z","abstract_url":"https://arxiv.org/abs/2606.30344v1","html_url":"https://arxiv.org/html/2606.30344v1","pdf_url":"https://arxiv.org/pdf/2606.30344v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30332v1","title":"UniGP: Taming Diffusion Transformer for Prior-Preserved Unified Generation and Perception","abstract":"Recent advances in diffusion models have shown impressive performance in controllable image generation and dense prediction tasks. However, existing approaches typically treat diffusion-based controllable generation and dense prediction as separate tasks, overlooking the potential benefits of jointly modeling the heterogeneous distributions. In this work, we introduce UniGP, a framework built upon MMDiT, which unifies controllable generation and dense prediction through simple joint training, without the need for complex task-specific designs or losses, while preserving the backbone's versatile priors. By learning controllable generation and prediction under different conditions, our model effectively captures the joint distribution of image-geometry pairs. UniGP is capable of versatile controllable generation, dense prediction, and joint generation. Specifically, the proposed UniGP consists of DUGP and a unified dataset training strategy. The former, following the principle of Occam's razor, uses only a copied image branch of MMDiT to model dense distributions beyond RGB, while the latter integrates heterogeneous datasets into a unified training framework to jointly model generation and perception tasks. Extensive experiments demonstrate that our unified model surpasses prior unified approaches and performs on par with specialized methods. Furthermore, we demonstrate that multi-task joint training provides complementary benefits: generative priors enrich perceptual details, while perceptual learning improves structural alignment in generation.","authors":["Qin Guo","Hao Luo","Dongxu Yue","Weixuan Jin","Xiao Fu","Fan Wang","Dan Xu"],"published":"2026-06-29T14:13:27Z","updated":"2026-06-29T14:13:27Z","abstract_url":"https://arxiv.org/abs/2606.30332v1","html_url":"https://arxiv.org/html/2606.30332v1","pdf_url":"https://arxiv.org/pdf/2606.30332v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30319v1","title":"BrainJanus: A Unified Model for Understanding and Generation across Brain, Vision, and Language","abstract":"Modeling the bidirectional correspondence between external sensory stimuli and internal neural activity has emerged as a critical frontier in neuroscience. However, existing approaches predominantly treat brain encoding and decoding as isolated tasks, relying heavily on unimodal alignment and external priors while overlooking the brain's intrinsic nature as a multimodal integration system. To address these limitations, we propose BrainJanus, the first unified brain model that integrates brain, vision, and language within a single framework. Specifically, we introduce a Unified Brain Tokenizer to quantize continuous neural dynamics into discrete tokens aligned with visual and linguistic representations in a shared Omni space. Building on this, we utilize an All-in-One autoregressive architecture that leverages next-token prediction to enable seamless any-to-any generation, which encompasses image-to-brain and text-to-brain encoding, and brain-to-image and brain-to-text decoding. Extensive experiments demonstrate that BrainJanus achieves superior performance across diverse benchmarks. Furthermore, our framework exhibits zero-shot generalization and preserves interpretable biological topography, highlighting its potential as a general-purpose brain modeling paradigm. The code is available at \\href{https://github.com/HaitaoWuTJU/BrainJanus}{GitHub}.","authors":["Haitao Wu","Qirui Zhang","Zhouheng Yao","Shangquan Sun","Qihao Zheng","Mianxin Liu","Chi Zhang","Wanli Ouyang","Chunfeng Song","Changqing Zhang","Jiamin Wu"],"published":"2026-06-29T14:02:15Z","updated":"2026-06-29T14:02:15Z","abstract_url":"https://arxiv.org/abs/2606.30319v1","html_url":"https://arxiv.org/html/2606.30319v1","pdf_url":"https://arxiv.org/pdf/2606.30319v1.pdf","matched_keywords":["representation","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30313v1","title":"TRACE: A Concept Bottleneck Model for Longitudinal 3D Glioblastoma Response Assessment","abstract":"Longitudinal glioblastoma response assessment requires comparing subtle tumor changes across MRI time points using structured clinical criteria such as RANO. However, most deep learning methods predict response labels directly from imaging features, which limits clinical inspection, verification, and correction. We introduce TRACE, a RANO 2.0-aligned concept bottleneck model for interpretable 4-class glioblastoma response classification on longitudinal 3D MRI. TRACE processes paired baseline and follow-up multimodal MRI scans with a shared 3D vision encoder, predicts clinically meaningful tumor measurements as root concepts, computes downstream RANO-derived concepts through deterministic rules, and incorporates scan interval and new-lesion information as passthrough concepts. This design frames response assessment as structured concept reasoning rather than direct image-to-label prediction. Using 5-fold patient-wise cross-validation on the LUMIERE dataset, TRACE achieves a 4-class macro F1 of 0.4769 and a binary progression-versus-non-progression macro F1 of 0.7085. It improves over a concept bottleneck baseline and remains within the range of published non-interpretable deep learning approaches. Ablation studies show that the expert RANO graph and intervention-consistency training are important for performance, while intervention experiments demonstrate that correcting concepts can improve downstream predictions. These results suggest that structured concept bottlenecks offer a transparent and clinically aligned direction for longitudinal glioblastoma response assessment, while highlighting the need for larger protocol-aligned datasets and external validation.","authors":["Alia Tarek","Hamsa Saberr","Hamza Elghonemy","Youssef Afify","Tamer Basha","Omair Shahzad Bhatti","Abdulrahman M. Selim","Hasan Md Tusfiqur Alam Daniel Sonntag"],"published":"2026-06-29T13:56:17Z","updated":"2026-06-29T13:56:17Z","abstract_url":"https://arxiv.org/abs/2606.30313v1","html_url":"https://arxiv.org/html/2606.30313v1","pdf_url":"https://arxiv.org/pdf/2606.30313v1.pdf","matched_keywords":["3d","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30308v1","title":"The Surprising Effectiveness of Video Diffusion Models for Hand Motion Reconstruction","abstract":"4D hand motion reconstruction from egocentric video is bottlenecked by clear limitations of existing methods: image-based pipelines depend on a detector that fails under heavy occlusion, while video-based methods rely on temporal modules learned only from scarce hand-pose annotations, a narrow signal insufficient to model motion dynamics, occlusion reasoning, and hand-object interaction. These capabilities, however, are exactly what video generative models must implicitly acquire when trained to synthesize coherent video at internet scale. Motivated by this, we present ViDiHand, which leverages the representations of a pretrained video diffusion model to reconstruct 4D two-hand pose. We adapt it via a hand-overlay rendering objective that specializes its features for hands while preserving its world priors. A decoder then recovers metric-scale pose from the adapted features. The whole pipeline operates directly on full frames--no detector, no infiller, and no test-time optimization. On ARCTIC, HOT3D, and HOI4D, ViDiHand substantially outperforms prior methods, establishing video diffusion models as a powerful new foundation for hand motion reconstruction and a promising route to scalable in-the-wild data collection for embodied AI. Project page: https://vidihand.github.io.","authors":["Yuxi Wang","Chengkai Jin","Yufei Liu","Wenqi Ouyang","Tianyi Wei","Zhiwei Zeng","Siyuan Huang","Zhiqi Shen","Xingang Pan"],"published":"2026-06-29T13:53:00Z","updated":"2026-06-29T13:53:00Z","abstract_url":"https://arxiv.org/abs/2606.30308v1","html_url":"https://arxiv.org/html/2606.30308v1","pdf_url":"https://arxiv.org/pdf/2606.30308v1.pdf","matched_keywords":["video","3d","representation","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30292v1","title":"DreamForge-World 0.1 Preview: A Low-Compute Real-Time Controllable World Model","abstract":"We present DreamForge-World 0.1 Preview, a preview foundational world model for real-time interactive world simulation. The system adapts the LongLive 1 autoregressive video stack, itself derived from Wan2.1-T2V-1.3B, with a residual action pathway inspired by the Matrix-Game family. DreamForge-World 0.1 Preview focuses on a complementary axis to frontier-scale world simulators: low-compute adaptation, consumer-GPU runtime, and broad interactive capability coverage. It supports live keyboard and mouse control, multimodal initialization, mid-stream reprompting, dual-view operation, and minute-scale interactive rollouts at native 480p resolution, reaching up to 14 to 15 FPS FPS on a single RTX 4090 with a low memory footprint. By leveraging open video backbones and applying targeted adaptation runs, we build the preview system with high cost-efficiency. DF-World 0.1 Preview is not yet a memory-complete or frontier-quality world simulator, but demonstrates a practical low-compute route toward real-time controllable world-model previews on consumer GPUs.","authors":["Daniyel Ayupov","Artur Markov-Tsoy"],"published":"2026-06-29T13:35:44Z","updated":"2026-06-29T13:35:44Z","abstract_url":"https://arxiv.org/abs/2606.30292v1","html_url":"https://arxiv.org/html/2606.30292v1","pdf_url":"https://arxiv.org/pdf/2606.30292v1.pdf","matched_keywords":["video","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30288v1","title":"VisReflect: Latent Visual Reflection for Fine-Grained Perception in Long Visual Context","abstract":"Large Vision Language Models (LVLMs) have achieved remarkable success on vision-language tasks, yet fine-grained perception over high-resolution images and long-context videos remains challenging. As the number of visual tokens increases, the visual attention sink phenomenon becomes increasingly severe, causing irrelevant tokens to absorb a disproportionate amount of attention mass. Recent approaches attempt to mitigate this issue by explicitly predicting bounding boxes or temporal spans and re-encoding the cropped visual regions. Such methods depend on unreliable numeric localization in the discrete token space and incur significant computational overhead due to additional forward passes. In this work, we propose **VisReflect**, a simple yet effective framework that improves fine-grained perception in long visual contexts through latent visual reflection. Instead of decoding intermediate predictions into discrete tokens, the model generates continuous visual reflection that represents question-relevant visual features in the latent space. These reflections selectively emphasize salient regions or frames, guiding attention towards relevant visual tokens within a single forward pass. We conduct comprehensive evaluations on challenging high-resolution image benchmarks, including BLINK, V*, and HRBench-4K/8K, as well as video understanding benchmarks such as MVBench, VideoMME, and MLVU. Our method consistently improves over strong baselines, achieving gains of 4.1% on image benchmarks and 1.8% on video benchmarks. Compared with zooming-based methods, our model achieves comparable performance while reducing inference time by roughly 44% on video understanding.","authors":["Xiaoqian Shen","Mohamed Elhoseiny"],"published":"2026-06-29T13:30:17Z","updated":"2026-06-29T13:30:17Z","abstract_url":"https://arxiv.org/abs/2606.30288v1","html_url":"https://arxiv.org/html/2606.30288v1","pdf_url":"https://arxiv.org/pdf/2606.30288v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30262v1","title":"Intermediate Text Representation Guided Text-to-Image Generation for Enhancing One-and-Only Alignment","abstract":"Text-to-image (T2I) diffusion models often fail to faithfully render explicit textual descriptions, instead defaulting to strongly learned visual priors due to a phenomenon referred to as concept association bias. We show that such bias is particularly strong for one-and-only (OAO) objects, entities that exist in a single canonical form, such as celestial bodies, landmarks, and artworks. The deeply ingrained visual identity for these concepts often resists modification through prompting alone. Addressing this challenge, we first identify through an information-theoretic analysis that the final text embedding discards concept-level information present in the intermediate-layer text representations, reducing the mutual information available to the subsequent denoising process. We then propose Intermediate Text Representation (IR)-guided diffusion, which injects intermediate hidden states of the text encoder into the conditioning signal during early denoising steps, recovering suppressed concepts without any additional training, optimization, or external models. To systematically evaluate the challenging task of aligning generative outputs with unusual prompts for OAO objects, we introduce OAO-AttackBench, a benchmark comprising counterfactual prompts that directly conflict with the core visual identity of OAO objects. Experiments on four benchmarks, including OAO-AttackBench, show that our method achieves up to a 19.1 percentage-point improvement in VQAScore while preserving generation fidelity and human preference. Project page: https://soyoun-won.github.io/one-and-only-ir-guidance/.","authors":["Soyoun Won","Aryan Yazdan Parast","Basim Azam","Jean Honorio","Naveed Akhtar"],"published":"2026-06-29T13:09:39Z","updated":"2026-06-29T13:09:39Z","abstract_url":"https://arxiv.org/abs/2606.30262v1","html_url":"https://arxiv.org/html/2606.30262v1","pdf_url":"https://arxiv.org/pdf/2606.30262v1.pdf","matched_keywords":["representation","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30248v1","title":"Your Data Manifold is Secretly a Reward Model: Shell-LCC for Text-to-Video Generation","abstract":"Recent text-to-video (T2V) diffusion models rely heavily on auxiliary reward signals (e.g., via reward models or DPO) to align generated content with human aesthetics and improve realism. These signals, however, incur substantial computational overhead, require costly human annotations, and often yield limited improvement in fine-grained local details. In this paper, we argue that your data manifold is secretly a reward model. By explicitly modeling the manifold structure of high-quality Supervised Fine-Tuning (SFT) data and encouraging video latents to lie on this manifold, we derive dense, differentiable, and nearly cost-free reward signals that significantly improve video quality, particularly in mitigating low-level distortions. Our modeling builds upon Local Coordinate Coding (LCC), which captures the `skeleton' of the manifold. However, directly applying LCC suffers from mean regression, pulling latents toward the geometric mean and losing high-frequency details. We therefore extend it to Shell Local Coordinate Coding (Shell-LCC), which models the manifold `surface' as an isotropic shell to align with the true high-density region. Experiments demonstrate that our approach improves realism, enhances high-frequency details, reduces over-smoothing artifacts, and alleviates motion blur.","authors":["Shihao Zhang","Yuguang Yan","Junzhe Zhang","Wei Zhao","Bohan Wang","Hanwang Zhang"],"published":"2026-06-29T12:57:34Z","updated":"2026-06-29T12:57:34Z","abstract_url":"https://arxiv.org/abs/2606.30248v1","html_url":"https://arxiv.org/html/2606.30248v1","pdf_url":"https://arxiv.org/pdf/2606.30248v1.pdf","matched_keywords":["video","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30244v1","title":"Semantic-Driven Scale and Spatial Selection for Efficient Cross-Modal Alignment in Referring Remote Sensing Image Segmentation","abstract":"Referring Remote Sensing Image Segmentation (RRSIS) seeks to localize and segment the target object or region specified by a natural language expression in a remote sensing image. While existing RRSIS models have benefited from large-scale foundation models, they predominantly rely on full fine-tuning. These approaches are computationally intensive and may weaken the generalization ability of pre-trained models, as extensive fine-tuning on significantly smaller downstream datasets can distort the well-structured feature representations learned during large-scale pre-training. Although Parameter-Efficient Tuning (PET) offers a potential alternative, existing PET frameworks primarily focus on single-modal optimization, failing to capture the complex cross-modal dependencies required for multimodal reasoning, while simultaneously struggling to bridge the substantial domain gap between natural scenes and aerial imagery. To address these limitations, we propose a novel framework, Semantic-driven Scale and Spatial Selection for Efficient Cross-modal Alignment (S4ECA), which enables effective and efficient cross-modal interaction through parameter-efficient adaptation. Specifically, we design a dual-encoder adapter architecture. The textual adapter employs learnable queries to distill highly semantic language proxies from word-level embeddings, facilitating early grounding. Simultaneously, the visual adapter refines hierarchical feature representations through a multi-scale dense extractor, followed by a language-guided scale and spatial selection mechanism that dynamically emphasizes relevant visual contexts, ensuring precise cross-modal alignment. By updating only 2.4% of the backbone parameters, our proposed model achieves state-of-the-art performance on the RRSIS-D and RefSegRS datasets, demonstrating superior efficiency and precision in complex aerial scenarios.","authors":["Kun Li","Shengxi Gui","Francesco Nex","Michael Ying Yang"],"published":"2026-06-29T12:54:10Z","updated":"2026-06-29T12:54:10Z","abstract_url":"https://arxiv.org/abs/2606.30244v1","html_url":"https://arxiv.org/html/2606.30244v1","pdf_url":"https://arxiv.org/pdf/2606.30244v1.pdf","matched_keywords":["representation","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30220v1","title":"From Accuracy to Visual Dependence: Auditing and Filtering Modality Collapse in Traffic VideoQA","abstract":"High benchmark accuracy does not guarantee genuine use of visual evidence. We study this problem in traffic accident Video Question Answering (VideoQA), where correct answers should depend on scene-specific visual evidence but may instead be inferred from textual shortcuts. Through an audit of four public benchmarks, we find that several recent open-weight Vision-Language Models (VLMs) perform competitively, and sometimes better, without video input. On the MM-AU benchmark, removing video consistently improves accuracy, and adding more frames further degrades performance. To quantify visual dependence, we introduce two dataset-level diagnostics: Blind Gap, measuring above-chance text-only performance, and Visual Gain, measuring the marginal benefit of adding video. We further propose an instance-level Shortcut Score that combines text-only confidence with visual necessity signals, enabling continuous, training-free filtering of shortcut-prone questions. The resulting subsets reduce shortcut bias and improve visual grounding. Our findings reveal large differences in grounding quality across benchmarks and show that visually grounded evaluation, not just high accuracy, is essential in safety-critical VideoQA.","authors":["Sena Korkut","María Alejandra Bravo Sarmiento","Sanghwan Kim","Zeynep Akata"],"published":"2026-06-29T12:33:15Z","updated":"2026-06-29T12:33:15Z","abstract_url":"https://arxiv.org/abs/2606.30220v1","html_url":"https://arxiv.org/html/2606.30220v1","pdf_url":"https://arxiv.org/pdf/2606.30220v1.pdf","matched_keywords":["video","instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30183v1","title":"DrivenMorph: Bridging Attention Mechanism and Variational Image Registration via Difference Modeling","abstract":"Medical image registration benefits significantly from deep learning, yet existing approaches often lack physical explainability and fine-grained deformation control. Motivated by Demons algorithms, we propose a novel DrivenMorph framework that bridges attention mechanisms with variational image registration by incorporating difference modeling as a physically inspired inductive bias. The resulting driving force, computed from local differences in the latent feature space, provides explicit semantic guidance throughout the registration process. It directly drives the registration process through a neural Demons layer that simulates force-displacement interactions to generate smooth and anatomically consistent deformation. Unlike previous methods, our approach not only integrates traditional registration principles with popular deep networks, providing an explainable and efficient solution for learning-based medical image registration, but also separates difference modeling from deformation, improving modularity and explainability. Extensive experiments on multiple 3D brain MRI datasets demonstrate superior performance over state of-the-art learning-based and optimization-based methods. Furthermore, visualizations and statistical analyses confirm that the learned driving force aligns closely with actual deformation patterns, supporting its explanatory value.","authors":["Mingke Li","Jianping Zhang","Jinqiu Deng"],"published":"2026-06-29T11:57:51Z","updated":"2026-06-29T11:57:51Z","abstract_url":"https://arxiv.org/abs/2606.30183v1","html_url":"https://arxiv.org/html/2606.30183v1","pdf_url":"https://arxiv.org/pdf/2606.30183v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30179v1","title":"HiRes: A Hierarchical Cascaded Method for Resistor Value Identification","abstract":"Accurate identification of resistor values from unconstrained images remains a challenging computer vision task due to variations in lighting, orientation, scale, and background complexity. This paper presents HiRes, a hierarchical cascaded pipeline for end-to-end resistor value identification directly from full-frame images. The approach combines object detection (YOLOv8n), semantic segmentation (UNet++ with EfficientNet-B2), and structured geometric decoding via projection along the resistor axis. To improve robustness, we incorporate geometric filtering, gap-preserving band separation, and validation against the E24 resistor series. Experiments across diverse real-world images show that HiRes achieves a detection mAP50 of 0.9906, a segmentation mIoU of 0.8444, and an end-to-end identification accuracy of 85.8% (95% CI: 78.0-91.9%), outperforming the publicly available classical baseline, CVResist, which fails to generalize beyond controlled conditions. In addition, our architecture outperforms state-of-the-art MLLMs on our challenging test set, offering a lower cost, high efficiency, and an interpretable alternative method. These results demonstrate the effectiveness of integrating learned visual representations with structured reasoning for robust resistor interpretation. Code and dataset are available at https://github.com/HiRes491/HiRes.","authors":["Rama Y. AlHamidi","Aseel A. Mohamed","Mustafa A. Eltayeb","Osama Hasoneh","Mohammad Shaqfeh"],"published":"2026-06-29T11:55:06Z","updated":"2026-06-29T11:55:06Z","abstract_url":"https://arxiv.org/abs/2606.30179v1","html_url":"https://arxiv.org/html/2606.30179v1","pdf_url":"https://arxiv.org/pdf/2606.30179v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30168v1","title":"Latent Noise Mask for Reducing Visual Redundancy in Multimodal Large Language Models","abstract":"Multimodal large language models (MLLMs) often fail in fine-grained visual reasoning, as question-relevant visual cues are diluted by dense and redundant image tokens. Recent multimodal reasoning methods usually extend chain-of-thought from language models into visual or latent spaces, seeking to add intermediate reasoning states while overlooking the negative impact of redundant visual tokens. We propose LatEnt Noise maSk (Lens), a question-conditioned visual evidence purification framework that empowers MLLMs to reason with cleaner visual cues in latent space. Lens introduces a lightweight Lens Evidence Token (LET) to score which visual tokens support the current question and preserve them during decoding. Guided by the LET scores, it injects adaptive latent noise into low-relevance tokens, softly suppressing distractors without changing the model backbone or token sequence. With only one temporary learnable control token and a lightweight noise generator, Lens adds minimal overhead while improving the base MLLM by 2.4-6.4 points on most VQA datasets and by 4.1-6.4 points on grounding tasks. These results show that multimodal reasoning can benefit more directly from cleaner question-relevant visual evidence than from simply extending the reasoning trace.","authors":["Kai Jiang","Ruishu Zhu","Siqi Huang","Hongyuan Zhang","Xuelong Li"],"published":"2026-06-29T11:44:09Z","updated":"2026-06-29T11:44:09Z","abstract_url":"https://arxiv.org/abs/2606.30168v1","html_url":"https://arxiv.org/html/2606.30168v1","pdf_url":"https://arxiv.org/pdf/2606.30168v1.pdf","matched_keywords":["multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30147v1","title":"T2LDM++: A Self-Conditioned Representation Guided Diffusion Model for Realistic Text-to-LiDAR Scene Generation","abstract":"Recent progress in Text-to-Image generation benefits from large-scale Text-Image pairs. However, the scarcity of Text-LiDAR pairs often causes over-smoothed scenes and limited controllability. In this paper, we rethink the limitations of Text-LiDAR generation task, focusing on alleviating insufficient training priors and constructing controllable Text-LiDAR data. We propose a \\textbf{T}ext-\\textbf{to}-\\textbf{L}iDAR \\textbf{D}iffusion \\textbf{M}odel for LiDAR scene generation, T2LDM++, with a Self-Conditioned Representation Guidance (SCRG). Specifically, to alleviate object over-smoothing, SCRG employs a Guidance Network (GN) to provide reconstruction-based soft supervision to the Denoising Network (DN). This enables DN to learn geometry-aware representations through reconstruction guidance, leading to more accurate denoising in DDPMs. Meanwhile, through analysis and design, SCRG exhibits more effective and lightweight, while decoupled in inference, avoiding computational overhead. Furthermore, we construct two high-quality Text-LiDAR benchmarks ($>$100K samples) using a generalized strategy of geometric annotations, along with a controllability metric. Moreover, a directional position prior is designed to mitigate street distortion, further improving scene fidelity. Additionally, T2LDM++ supports multiple conditions, including (Semantic, Box, BEV, Camera)-to-LiDAR, Sparse-to-Dense, and Dense-to-Sparse generation, by learning a control encoder via frozen DN. With effective prior modeling and high-quality Text-LiDAR benchmarks, T2LDM++ can generate realistic LiDAR scenes with rich geometric details in unconditional and conditional settings.","authors":["Wentao Qu","Qi Zhang","Chenxu Wang","Guofeng Mei","Yongfei Liu","Xiaoshui Huang","Gim Hee Lee","Liang Xiao"],"published":"2026-06-29T11:23:11Z","updated":"2026-06-29T11:23:11Z","abstract_url":"https://arxiv.org/abs/2606.30147v1","html_url":"https://arxiv.org/html/2606.30147v1","pdf_url":"https://arxiv.org/pdf/2606.30147v1.pdf","matched_keywords":["representation","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30131v1","title":"Hyper-Network Neural Functional Maps for Unsupervised Robust 3D Shape Matching","abstract":"Functional maps are the cornerstone of recent non-rigid 3D shape matching methods due to their efficiency and performance. However, existing methods struggle with challenging scenarios, such as partiality, topological noise, and raw point clouds. A primary bottleneck is that significant intrinsic distortion prevents truncated spectral bases from being accurately aligned via linear transformations (i.e., functional maps). To address this, we introduce a hyper-network that predicts non-linear neural functional maps (NFM), learned in an unsupervised manner, to better align spectral bases. Specifically, we model the NFM as an MLP with skip-connection to refine standard FM and employ a hyper-network to predict its weights, conditioned on standard FM. Our framework is trained using a novel unsupervised spectral alignment loss. Experiments demonstrate that our approach can be seamlessly integrated into state-of-the-art unsupervised deep functional map pipelines, substantially improving matching accuracy in demanding scenarios.","authors":["Dongliang Cao","Florian Bernard"],"published":"2026-06-29T11:09:05Z","updated":"2026-06-29T11:09:05Z","abstract_url":"https://arxiv.org/abs/2606.30131v1","html_url":"https://arxiv.org/html/2606.30131v1","pdf_url":"https://arxiv.org/pdf/2606.30131v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30108v1","title":"LETT-NeXt: A Lightweight RECIST-Guided Model for 3D CT Lesion Segmentation","abstract":"RECIST diameter measurements are widely used for tumor response assessment, but they provide only a limited 2D description of lesion extent. We present LETT-NeXt, a lightweight RECIST-guided model that predicts 3D lesion masks from CT volumes and RECIST markers for the CVPR 2026 Foundation Models for Pan-cancer Segmentation in CT Images competition. LETT-NeXt extracts a RECIST-centered regional crop, encodes the RECIST line and endpoints as two prompt channels, and concatenates them with the CT input. A compact MedNeXt-v2 encoder--decoder predicts the lesion mask, followed by prompt-aware component selection and adaptive AutoZoom inference. On the public validation set, LETT-NeXt achieved a Dice Similarity Coefficient (DSC) of 79.4 $\\pm$ 10.1 and a Normalized Surface Dice (NSD) of 72.3 $\\pm$ 16.2. On the hidden test set, it achieved a DSC of 73.9 and an NSD of 67.3, corresponding to a challenge score of 70.6\\%. On the public validation mirror, LETT-NeXt completed CPU inference in 6.9 $\\pm$ 3.0 s per case with a peak memory use of 3.6 GB. Code is available at github.com/Ahus-AIM/lett-next.","authors":["Sebastian Aas","Elias Stenhede","Arian Ranjbar"],"published":"2026-06-29T10:44:51Z","updated":"2026-06-29T10:44:51Z","abstract_url":"https://arxiv.org/abs/2606.30108v1","html_url":"https://arxiv.org/html/2606.30108v1","pdf_url":"https://arxiv.org/pdf/2606.30108v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30101v1","title":"SIR: Structured Image Representations for Explainable Robot Learning","abstract":"Existing robot policies based on learned visual embeddings lack explicit structure and are sensitive to visual distractions. Thus, the representations that drive their behaviour are often opaque, making their decision-making process difficult to interpret. To address this, we introduce Structured Image Representations (SIR), a method that leverages Scene Graphs (SGs) as an intermediate representation for robot policy learning. Our approach first constructs a fully connected graph, using image-derived features as initial node representations. Then, a module learns to sparsify this graph end-to-end, creating a task-relevant sub-graph that is passed to the action generation model. This process makes our model intrinsically explainable. Evaluations on RoboCasa show that our sparse graph policies outperform image-based baselines on average with 19.5% vs 14.81% success rate. Most importantly, we show that the learned sparse graphs are a powerful tool for model analysis. By analysing when the model's sub-graph deviates from human expectation, such as by including distractor nodes or omitting key objects, we successfully uncover dataset biases, including spurious correlations and positional biases. https://github.com/intuitive-robots/SIR_Model","authors":["Paul Mattes","Jan Schwab","Jens Bosch","Nils Blank","Maximilian Xiling Li","Minh-Trung Tang","Moritz Haberland","Rudolf Lioutikov"],"published":"2026-06-29T10:37:21Z","updated":"2026-06-29T10:37:21Z","abstract_url":"https://arxiv.org/abs/2606.30101v1","html_url":"https://arxiv.org/html/2606.30101v1","pdf_url":"https://arxiv.org/pdf/2606.30101v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30097v1","title":"CylindTrack: Depth-Aware Cylindrical Motion Modeling for Panoramic Multi-Object Tracking","abstract":"Multi-Object Tracking (MOT) is a core capability for embodied perception, and panoramic cameras are attractive for embodied systems because their 360° field of view reduces blind spots and keeps surrounding targets observable for longer durations. However, panoramic MOT is not a straightforward extension of perspective MOT. In equirectangular panoramic videos, the horizontal image domain is periodic rather than Euclidean, which breaks planar motion assumptions and makes IoU-based association unreliable near the 0°/360° seam. Meanwhile, large-FoV scenes often contain more objects, stronger scale variation, and more frequent interactions, making online association particularly sensitive to unstable frame-wise depth cues. To address these issues, we propose CylindTrack, a depth-aware cylindrical tracking-by-detection framework for panoramic MOT. CylindTrack first introduces Depth-Temporal Trajectory Modeling (DTM), which promotes instance depth from an isolated frame-wise cue to a temporally filtered trajectory-level state. To improve the reliability of depth observations, we further develop Spherical Spatio-Temporal Consistency Learning (SSTC), which combines a Temporal Mixer and Spherical Geometry-aware Attention to enhance temporal coherence and panoramic geometric alignment in depth-aware representations. Finally, we design a Topology-Aware Cylindrical Motion Model (TCMM) that lifts horizontal motion into a continuous angular state space and performs seam-consistent motion prediction and association in the periodic panoramic domain. By jointly modeling trajectory-level depth consistency and panoramic topology, CylindTrack improves identity preservation and trajectory continuity in challenging panoramic scenes. The source code will be released at https://github.com/warriordby/CylindTrack.","authors":["Buyin Deng","Kai Luo","Lingxin Huang","Xinqi Liu","Fei Cheng","Hang Zheng","Liming Yin","Kailun Yang"],"published":"2026-06-29T10:32:08Z","updated":"2026-06-29T10:32:08Z","abstract_url":"https://arxiv.org/abs/2606.30097v1","html_url":"https://arxiv.org/html/2606.30097v1","pdf_url":"https://arxiv.org/pdf/2606.30097v1.pdf","matched_keywords":["video","representation","instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30082v1","title":"Clinical Risk-Aware Multi-Level Grading for Coronary Artery Stenosis through Curved Feature Reconstruction","abstract":"Developing a multi-level grading model for coronary artery stenosis holds great clinical significance for the diagnosis of coronary artery disease. However, designing an effective multi-level deep learning algorithm faces significant challenges. Specifically, utilizing CCTA or 3D SCPR images alone presents inherent shortcomings: CCTA images are difficult to analyze due to the tortuous paths of blood vessels, while 3D SCPR images are prone to abnormal distortions that hinder accurate grading. Furthermore, different stenosis grades are associated with varying clinical risks, and incorporating this association into the algorithm is non-trivial. To address the former problems, we propose the Curved Feature Reconstruction (CFR) module, which uses vessel curves as prior and employs a point-by-point correspondence strategy to precisely align and fuse features from both 3D SCPR and CCTA images. Meanwhile, a Clinical Risk-Aware (CR) Loss is employed to introduce clinical risk relevance into the network training so that the algorithm can better align with the clinical diagnosis. The experimental results on a in-house dataset reveal that our approach significantly outperforms other methods, and several ablation studies also demonstrate the effectiveness of our proposed designs.","authors":["Shishuang Zhao","Hongtai Li","Junjie Hou","Yuhang Liu"],"published":"2026-06-29T10:17:22Z","updated":"2026-06-29T10:17:22Z","abstract_url":"https://arxiv.org/abs/2606.30082v1","html_url":"https://arxiv.org/html/2606.30082v1","pdf_url":"https://arxiv.org/pdf/2606.30082v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30067v1","title":"Neural Subspace Reallocation: Continual Learning as Retrieval-Based Subspace Memory Management","abstract":"We introduce Neural Subspace Reallocation (NSR), which reframes continual learning as memory management over parameter subspaces. Instead of treating Low-Rank Adaptation (LoRA) modules as disposable per-task adapters, NSR manages them as compressible, retrievable memory units on a frozen backbone through a recurring cycle: (1) compress learned LoRAs via SVD, (2) reserve them in a TaskKnowledgeBank, (3) recall related past LoRAs by embedding similarity to warm-start new or returning tasks, and (4) reallocate the active subspace accordingly, with distillation protecting prior tasks. We prove that in cyclic environments any memoryless allocation policy incurs cumulative regret Omega(T(M-1)Delta_switch) relative to a history-aware policy backed by the Bank (Theorem 1). Empirically, on Split-CIFAR-100 the Bank reduces cyclic recovery time by 10x, exactly as predicted, and on the heterogeneous 5-Datasets benchmark NSR achieves the highest accuracy and the least forgetting, about 9x closer to zero backward transfer than the memoryless heuristics. Crucially, we run a controlled study that isolates which component matters: holding the Bank fixed and varying only the allocation rule, we find that a simple similarity-based retrieval rule matches or beats a learned reinforcement-learning controller (recovering recurring tasks in 0 vs 1.8 steps and reaching equal accuracy). Our central, honest finding is therefore that the memory mechanism -- compression and similarity retrieval -- rather than a learned allocation policy, drives continual-learning performance under fixed capacity. A memory-budget analysis confirms the compressed Bank stays small -- 0.29 MB of parameter memory per task -- so a top-K retention cap bounds the total footprint while preserving fast recovery for retained tasks.","authors":["Byeong Hoon Yoon"],"published":"2026-06-29T10:00:29Z","updated":"2026-06-29T10:00:29Z","abstract_url":"https://arxiv.org/abs/2606.30067v1","html_url":"https://arxiv.org/html/2606.30067v1","pdf_url":"https://arxiv.org/pdf/2606.30067v1.pdf","matched_keywords":["retrieval"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30058v1","title":"Emergence of a Shared Canonical Object Frame from In-the-Wild Videos","abstract":"Comparing object orientations and positions across different instances requires their poses to be expressed in a shared canonical frame. Establishing such frames has traditionally required manual annotation, creating a scaling bottleneck that limits category and instance diversity. We show that a shared canonical frame can instead emerge from self-supervised training on object-centric videos captured in the wild, using only noisy camera poses from Structure-from-Motion. Our key idea is to route all training sequences through a shared geometric bottleneck: a coarse canonical mesh that carries no category-specific detail. By learning dense correspondences from image pixels to this mesh, and estimating per-sequence alignments from noisy SfM geometry, a common canonical frame emerges from multi-view consistency and the semantic priors of the feature extractor, without any canonical pose labels or category conditioning. Trained in a self-supervised manner on 160,000 in-the-wild object videos, our method achieves competitive accuracy on category-level pose estimation benchmarks compared to methods that rely on canonical pose supervision. The code and checkpoint is available on https://github.com/Fischer-Tom/Emergent-Canonical-Frame/.","authors":["Tom Fischer","Martin Sundermeyer","Adam Kortylewski","Eddy Ilg"],"published":"2026-06-29T09:48:39Z","updated":"2026-06-29T09:48:39Z","abstract_url":"https://arxiv.org/abs/2606.30058v1","html_url":"https://arxiv.org/html/2606.30058v1","pdf_url":"https://arxiv.org/pdf/2606.30058v1.pdf","matched_keywords":["video","instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30054v1","title":"Illuminating Unified Multimodal Model for Free-form Interleaved Text-Image Generation","abstract":"The advancement of generative AI models capable of producing text and image marks a critical step forward in the realm of multimodal intelligence, particularly for tasks involving the interleaving of both modalities. To advance this intelligence to the next stage, it is crucial for models to autonomously generate free-form interleaved text-image sequences. In this paper, we introduce ILLUME-X, an advanced unified multimodal paradigm that enables high-quality, free-form interleaved text-image generation by improving multimodal data efficiency and stabilizing the multimodal training process. ILLUME-X comprises three key components: (i) an expanded training data pipeline optimized for interleaved text-image generation, (ii) a progressive training strategy with self-adaptive objectives for free-length multimodal token sequences, and (iii) an objective and comprehensive evaluation method ILScore for interleaved text-image sequences. Notably, our ILLUME-X outperforms previous unified models across multiple interleaved text-image generation tasks like style transfer, image decomposition and storytelling.","authors":["Chonghuinan Wang","Zhikai Chen","Chunwei Wang","Yecong Wan","Junwei Yang","Zhixin Wang","Wei Zhang","Jiaqi Xu","Renjing Pei","Xiaohe Wu","Fan Li","Wangmeng Zuo"],"published":"2026-06-29T09:45:15Z","updated":"2026-06-29T09:45:15Z","abstract_url":"https://arxiv.org/abs/2606.30054v1","html_url":"https://arxiv.org/html/2606.30054v1","pdf_url":"https://arxiv.org/pdf/2606.30054v1.pdf","matched_keywords":["multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30049v1","title":"Bridging the Gap Between Image Restoration and Navigational Safety in Hazy Conditions: A New Visibility Estimation Metric for Maritime Surveillance","abstract":"Visibility distance is critical to maritime navigational safety because it determines the effective observation range of shipborne and shore-based monitoring systems. Under hazy conditions, degraded visual information shortens observable distance and increases navigational risks and economic losses. Although numerous image dehazing methods have been developed, conventional image quality assessment metrics, such as PSNR, SSIM, FSIM, FADE, and NIQE, cannot establish a physically interpretable relationship between restoration quality and practical visibility thresholds. To address this limitation, this work proposes a visibility-oriented evaluation framework that links dehazing performance with visible-distance estimation. First, a Maritime Simulated Visibility Dataset (MSVD) is constructed using Unity3D to simulate maritime traffic scenes under graded visibility conditions. The dataset provides paired hazy and clear images with precise visibility annotations, enabling quantitative analysis of visibility restoration. Second, a dehazing visibility evaluation metric is developed by using object detection accuracy as an intermediate indicator. By establishing a mapping between visibility distance and detection performance, the proposed metric converts image restoration improvements into measurable visibility gains. Six representative dehazing methods are evaluated using both conventional image quality metrics and the proposed visibility metric. Experimental results under different imaging conditions demonstrate that MSVD provides a reliable benchmark for evaluating dehazing performance across graded visibility levels, while the proposed metric enables interpretable and reliable visible-distance estimation, thereby supporting the assessment of navigational safety and operational efficiency.","authors":["Wentao Feng","Guobei Peng","Wengang Mao","Ryan Wen Liu"],"published":"2026-06-29T09:42:25Z","updated":"2026-06-29T09:42:25Z","abstract_url":"https://arxiv.org/abs/2606.30049v1","html_url":"https://arxiv.org/html/2606.30049v1","pdf_url":"https://arxiv.org/pdf/2606.30049v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30047v1","title":"Argus: Metric Panoramic 3D Reconstruction for Indoor Scenes","abstract":"Metric feed-forward 3D reconstruction for panoramic data remains under-explored due to the lack of large-scale panoramic RGB-D training data. We present Realsee3D, a hybrid dataset of 10K indoor scenes (1K real, 9K synthetic) with 299K panoramic viewpoints and precise metric annotations, and Argus, a feed-forward network trained on it for metric panoramic 3D reconstruction. In the sparse unordered capture setting of Realsee3D, a poorly chosen coordinate anchor can cause global pose drift. Argus addresses this with a learned covisibility module that selects the geometrically optimal reference view to anchor the metric world frame. To further improve multi-task learning, we decompose the bidirectional pixel-to-world mapping into interpretable sub-steps with per-step supervision and cross-coordinate joint constraints, reinforcing geometric consistency across prediction branches. On the Realsee3D benchmark, Argus achieves state-of-the-art metric performance in camera pose estimation, depth estimation, and point cloud reconstruction. Project page: https://argus-paper.realsee.ai.","authors":["Xi Li","Linyuan Li","Yan Wu","Tong Rao","Kai Zhang","Xinchen Hui","Cihui Pan"],"published":"2026-06-29T09:39:17Z","updated":"2026-06-29T09:39:17Z","abstract_url":"https://arxiv.org/abs/2606.30047v1","html_url":"https://arxiv.org/html/2606.30047v1","pdf_url":"https://arxiv.org/pdf/2606.30047v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30045v1","title":"Walking in the Implicit: Interactive World Exploration via Neural Scene Representation","abstract":"Interactive video generation systems for camera-controlled world exploration roll out growing sequences of latent video frames, entangling state transition with high-frequency observation synthesis. We propose Walking in the Implicit, a scene-centric paradigm that changes the rollout variable from frame latents to a fixed-length, renderable implicit state, termed Neural Implicit Scene (NIS). This factorizes interactive generation into stochastic transition of a compact scene state and deterministic pose-conditioned rendering given the sampled state. We instantiate this paradigm as NeuWorld: a transformer VAE learns locally anchored NIS from sparse posed frames, and a diffusion transformer evolves NIS conditioned on future camera trajectories and geometry-aware retrieved history. By reusing the VAE encoder as a unified conditioner, NeuWorld maps camera, reference-image, and history cues into the same NIS modality, avoiding external heterogeneous encoders. Trained from scratch on public posed-view data without pretrained video backbones or auxiliary 3D reconstructors, NeuWorld achieves strong long-horizon consistency with favorable inference efficiency.","authors":["Zhiqi Li","Chengrui Dong","Zhenhua Du","Hangning Zhou","Cong Qiu","Hailong Qin","Mu Yang","Dongxu Wei","Peidong Liu"],"published":"2026-06-29T09:37:33Z","updated":"2026-06-29T09:37:33Z","abstract_url":"https://arxiv.org/abs/2606.30045v1","html_url":"https://arxiv.org/html/2606.30045v1","pdf_url":"https://arxiv.org/pdf/2606.30045v1.pdf","matched_keywords":["video","3d","representation","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30027v1","title":"Cross-Modal Iteration Distillation for Robust IHD Screening: The IDNet Framework and A New Benchmark","abstract":"Color Fundus Photography (CFP) offers a low-cost and non-invasive route for ischemic heart disease (IHD) screening, but current studies are limited by scarce public benchmarks and ineffective fusion of retinal images with sparse clinical variables. We propose IDNet, a multimodal framework with a Cross-Modal Distillation Aggregator (CDA) that uses learnable queries to sequentially integrate left-eye, right-eye, and clinical features, mitigating the imbalance between high-dimensional visual features and low-dimensional tabular inputs. We also construct a reproducible UK Biobank benchmark with open-source curation and quality-control pipelines, yielding 50,410 images from 25,205 subjects. On this benchmark, IDNet outperforms image-only, clinical-only, and several multimodal baselines, and CDA consistently improves multiple visual encoders as a plug-in fusion module.","authors":["Yongchang Gao","Junjie Pang","Shuaiyu Yang","Yusheng Yang","Xichao Jia","Shaojie Li","Hongfei Zhang","Jia Mu"],"published":"2026-06-29T09:27:06Z","updated":"2026-06-29T09:27:06Z","abstract_url":"https://arxiv.org/abs/2606.30027v1","html_url":"https://arxiv.org/html/2606.30027v1","pdf_url":"https://arxiv.org/pdf/2606.30027v1.pdf","matched_keywords":["multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30026v1","title":"MuseBench: Benchmarking Intent-Level Audiovisual Arts Understanding in MLLMs","abstract":"Audiovisual arts encompass diverse creative disciplines, including cinema, visual arts, stage performance, and game design, where artistic meaning arises from deliberate combinations of visual, auditory, and narrative elements (e.g., fear amplified through claustrophobic framing, or grief conveyed through silence and lingering close-ups). True artistic understanding extends beyond recognizing what is depicted to reasoning about why it is expressed through particular creative choices. Despite the strong progress of multimodal large language models (MLLMs), this critical aspect of artistic understanding remains underexplored, as existing benchmarks largely measure perceptual recognition while overlooking reasoning about creative intent. To address this gap, we introduce Musebench, a comprehensive benchmark designed to evaluate MLLMs on nuanced artistic understanding. It comprises 4,016 questions spanning cinematic arts, static visual arts, stage performing arts, and game arts, distilled from over 10K candidate video essays that pair professional commentary with visual demonstration. To capture the open-ended nature of artistic analysis at scale, the benchmark combines single-select and variable-option multi-select questions. All questions are generated and refined through a four-phase iterative pipeline combining shortcut filtering, adversarial distractors, and expert validation. Comprehensive zero-shot evaluation of 28 state-of-the-art MLLMs reveals that even the best-performing model achieves only 48.29% accuracy, substantially below human expert performance of 87.18%, exposing a significant gap in current models' creative domain expertise.","authors":["Yuxuan Fan","Gyusik Seo","Jing Hao","Jaemin Cho","Mohit Bansal","Jaehong Yoon"],"published":"2026-06-29T09:27:02Z","updated":"2026-06-29T09:27:02Z","abstract_url":"https://arxiv.org/abs/2606.30026v1","html_url":"https://arxiv.org/html/2606.30026v1","pdf_url":"https://arxiv.org/pdf/2606.30026v1.pdf","matched_keywords":["video","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30024v1","title":"IBRSteG: Learning a Generalizable Steganography Framework for 3D Gaussian Splatting","abstract":"Recent advances in deep learning have notably improved steganographic message hiding. However, designing a generalizable steganographic approach for 3D Gaussian Splatting (3DGS) that can embed meaningful 3D scene content remains challenging. In this paper, we propose IBRSteG, a generalizable framework for 3DGS steganography that enables undetectable concealment of secret scenes within a steganographic scene. Unlike existing approaches whose parameter generation is rigidly coupled with the specific scene, we formulate 3D steganography as a feed-forward 3D Gaussian embedding process that generalizes across different 3DGS scenes. To realize this, we introduce GAS (Gaussian Attributes Steganographer), a network that learns a scene-independent embedding function by injecting the attributes of secret 3D Gaussian points into a cover scene, thereby directly reconstructing the steganographic scenes without per-scene finetuning or optimization. By transforming 3D Gaussian into these structured attributes, these attributes are compatible with 2D learning paradigms and benefit from their structured nature, thereby enhancing generalization to unseen 3DGS scenes. Extensive experiments on established datasets demonstrate that IBRSteG can effectively conceal different scenes with high visual quality, and achieves superior capacity and security. Code is available at https://github.com/LingXiang2023/IBRSteG.","authors":["Fanye Kong","Hongyu Xia","Yu Zheng","Boyang Gong","Jie Zhou","Jiwen Lu"],"published":"2026-06-29T09:25:58Z","updated":"2026-06-29T09:25:58Z","abstract_url":"https://arxiv.org/abs/2606.30024v1","html_url":"https://arxiv.org/html/2606.30024v1","pdf_url":"https://arxiv.org/pdf/2606.30024v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30020v1","title":"Uncertainty Estimation in Pathology Foundation Models via Deep Mutual Learning","abstract":"Pathology foundation models (PFMs) offer generalizable representations for whole-slide image (WSI) analysis, yet their clinical adoption remains limited. Specifically, their predictions lack reliable confidence estimates, and no single PFM is universally best across tasks, which severely undermines trust in medical settings. To overcome this, we propose $\\mathtt{DICE}$, a plug-and-play framework that ensembles $K$ frozen PFMs and models their disagreement as a proxy for uncertainty estimation. To ensure this proxy yields meaningful estimates, we align the ensemble members via deep mutual learning, and theoretically show that this objective upper-bounds the model uncertainty. Additionally, we demonstrate that the ensemble's consensus localizes abnormalities at the patch level without any explicit supervision. We evaluate $\\mathtt{DICE}$ on three challenging WSI benchmarks. Notably, our framework provides reliable uncertainty estimates that accurately flag failure-prone cases under in- and out-of-distribution settings, while matching or outperforming SOTA baselines in classification, calibration, and localization. Overall, $\\mathtt{DICE}$ takes a crucial step toward translating PFMs into uncertainty-aware decision-support systems.","authors":["Gbègninougbo Aurel Davy Tchokponhoue","Sevda Öğüt","Ali Idri","Dorina Thanou","Pascal Frossard"],"published":"2026-06-29T09:24:22Z","updated":"2026-06-29T09:24:22Z","abstract_url":"https://arxiv.org/abs/2606.30020v1","html_url":"https://arxiv.org/html/2606.30020v1","pdf_url":"https://arxiv.org/pdf/2606.30020v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30019v1","title":"OmniDance: Multimodal Driven Dance Video Generation with Large-scale Internet Data","abstract":"Music-driven dance video generation aims to synthesize expressive human motion that is temporally aligned with music while maintaining high visual fidelity. Despite recent progress, existing methods still face two key limitations: the lack of large-scale, high-quality dance video datasets, and the absence of principled frameworks for integrating music as a complementary conditioning signal into Video Generation Foundation Models. To address these limitations, we introduce CIPE-Dance, a large-scale Internet-sourced dance video dataset with choreography-informed text annotations, constructed via a progressive expert pipeline. To the best of our knowledge, CIPE-Dance is the largest dataset for dance video generation to date, comprising 300k high-quality clips over 400 hours and covering diverse dancers, environments, and dance genres. We further propose OmniDance, a framework-level recipe for integrating music into a TI2V foundation model without sacrificing its original controllability or visual fidelity. Motivated by the complementary roles of text as low-frequency semantics and music as high-frequency temporal dynamics, OmniDance co-designs a depth-aware specialization architecture, an anchored easy-to-hard curriculum learning strategy, and a modality-specialized time-dependent CFG strategy, enabling unified TI2V, MI2V, and MTI2V generation. Extensive experiments on CIPE-Dance demonstrate that OmniDance achieves state-of-the-art performance across all three tasks and exhibits robust multimodal integration capability. Project is available at https://github.com/AMAP-ML/OmniDance.","authors":["Kaixing Yang","Jiashu Zhu","Xulong Tang","Ziqiao Peng","Xiangyue Zhang","Chubin Chen","Puwei Wang","Jiahong Wu","Xiangxiang Chu","Hongyan Liu","Jun He"],"published":"2026-06-29T09:23:53Z","updated":"2026-06-29T09:23:53Z","abstract_url":"https://arxiv.org/abs/2606.30019v1","html_url":"https://arxiv.org/html/2606.30019v1","pdf_url":"https://arxiv.org/pdf/2606.30019v1.pdf","matched_keywords":["video","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30017v1","title":"Monte Carlo Energy Aggregation for Mobile 3D Gaussian Splatting","abstract":"Recent advances in 3D Gaussian Splatting have demonstrated unprecedented success in novel view synthesis. However, the substantial inference and storage overhead driven by high-order Spherical Harmonics (SH) are primary bottlenecks for mobile platforms. In this paper, we present Flux-GS, a real-time Gaussian Splatting method designed to achieve high-fidelity rendering with significantly reduced overhead for resource-constrained mobile platforms. We first propose a Monte Carlo Specular Energy Aggregator, sampling third-order radiance residuals and aggregating specular energy into a compact latent space. In this way, our method effectively preserves visually salient lighting features in lower-order bands without expensive distillation or pre-training. To mitigate the high-frequency details lost during compression, we introduce an Attribute-Conditioned SH Enhancement module. This module predicts Gaussian-aware offsets based on intrinsic Gaussian attributes, which enhance the first-order SH representation prior to inference, without extra inference costs. Furthermore, the original single-view gradient-based densification is prone to producing excessive Gaussians and overfitting to a certain view. We address these limitations by proposing a Multi-view Alpha-based Densification and Pruning strategy. By leveraging multi-view guidance, we ensure multi-view structure consistency and the precise removal of redundant primitives. Extensive experiments demonstrate that Flux-GS achieves substantial parameter reduction while maintaining competitive visual quality, offering a robust and scalable solution for real-time mobile rendering. Code: \\textcolor{magenta}{\\href{https://xiaobiaodu.github.io/flux-gs-project/}{https://xiaobiaodu.github.io/flux-gs-project/}}.","authors":["Xiaobiao Du","YuAn Wang","Hao Li","Bosheng Wang","Xun Sun","Xin Yu"],"published":"2026-06-29T09:21:57Z","updated":"2026-06-29T09:21:57Z","abstract_url":"https://arxiv.org/abs/2606.30017v1","html_url":"https://arxiv.org/html/2606.30017v1","pdf_url":"https://arxiv.org/pdf/2606.30017v1.pdf","matched_keywords":["3d","agent","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30014v1","title":"Shell-Supervised Gaussian Splatting for Urban Real-to-Sim Reconstruction","abstract":"Real-to-sim reconstruction for embodied AI requires geometry that is useful for collision reasoning, navigation, and agent-environment interaction, not only photorealistic novel-view synthesis. However, close-range urban facades are difficult for video-to-3D reconstruction: glass, reflections, repeated windows, and weak texture can produce visually plausible renderings with unstable surface geometry. We introduce shell-supervised Gaussian Splatting, a reconstruction-stage framework that uses an external facade structural shell as lightweight geometric supervision for video-driven Gaussian reconstruction. The method aligns an exterior shell to the video reconstruction frame, renders per-view depth, camera-space normal, and valid-mask maps, and applies these cues through mask-gated losses during Gaussian optimization. This design preserves RGB-driven appearance while regularizing only visible shell-supported facade regions. Experiments on anonymized close-range urban facade scenes show improved facade orientation and visible-surface point-cloud consistency over photo-only, monocular-cue, and surface-oriented Gaussian baselines, while maintaining comparable held-out rendering quality.","authors":["Yuan Yang","Peijun Lu","Fangzhou Lu","Sai Fan","Siqi Yan","Chenyuan Zhang","Haobo Liang","Yichen Wang"],"published":"2026-06-29T09:19:24Z","updated":"2026-06-29T09:19:24Z","abstract_url":"https://arxiv.org/abs/2606.30014v1","html_url":"https://arxiv.org/html/2606.30014v1","pdf_url":"https://arxiv.org/pdf/2606.30014v1.pdf","matched_keywords":["video","3d","agent"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30012v1","title":"SkelEM: Training-Signal Decoupling of Skeleton and Diffusion for Self-supervised Axial Super-Resolution in Volume Microscopy","abstract":"Volume microscopy, including electron and light microscopy, suffers from severe anisotropic resolution due to physical axial sectioning. Existing self-supervised axial super-resolution (ASR) methods face a trilemma bounded by overly smoothed regression textures, structural hallucinations of pure diffusion models, and prohibitive inference latency. In this paper, we propose Skeleton-refinE Microscopy (SkelEM), a self-supervised framework that decouples ASR at the training-signal level: a frozen topological network and a diffusion refiner are optimized by disjoint objectives, separating low-frequency topology formulation from high-frequency detail enhancement. Building on this deterministic skeleton, we exploit a unified cycle-consistent mechanism on input sparse slices to simultaneously extract a real-domain residual prior and bidirectionally align the diffusion refiner, washing away cross-plane artifacts without synthetic bias. By truncating the reverse diffusion process with this physical prior, SkelEM achieves high-fidelity detail restoration in merely $\\le 5$ steps. To rigorously assess cross-instrument generalization, we further introduce BRAVE-ASR, a new benchmark of co-aligned anisotropic and isotropic volumes acquired on a Plasma-FIB instrument. Across public benchmarks, SkelEM achieves the most favorable balance across the fidelity-perception trade-off among self-supervised methods, with state-of-the-art downstream membrane segmentation performance and robust zero-shot generalization across distinct modalities.","authors":["Bohao Chen","Yanchao Zhang","Yanan Lv","Chenxun Deng","Hua Han","Xi Chen"],"published":"2026-06-29T09:19:04Z","updated":"2026-06-29T09:19:04Z","abstract_url":"https://arxiv.org/abs/2606.30012v1","html_url":"https://arxiv.org/html/2606.30012v1","pdf_url":"https://arxiv.org/pdf/2606.30012v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30003v1","title":"GeoEdit: Geometry-Aware Object Editing via Dual-Branch Denoising","abstract":"Precisely manipulating objects in a single photograph (translation, rotation, scaling) while obeying 3D physical constraints remains unsolved for diffusion-based editors. Current 2D methods lack spatial awareness and produce perspective violations. Forcing structural proxies into the latent space also disrupts variance homogeneity, and the resulting self-attention leakage leads to ghosting and background blur. The core difficulty is asymmetric: the relocated object must follow a rigid geometry, yet the uncovered background needs freedom to synthesize plausible content. We present GeoEdit, a training-free Lift-Manipulate-Render-Denoise pipeline that satisfies both constraints. We decouple scene and object in 3D, align them through point correspondence, and render a geometry-aligned proxy with a structural depth map. A Dual-Branch Denoising stage then refines this proxy: a video diffusion backbone preserves object identity, while 3D constraints are injected into the foreground within a narrow denoising window at matching noise variance (variance-homogeneous injection). The background denoises freely. Because the injected signal matches the native latent statistics, self-attention stays undisturbed. We also introduce GeoEditBench, a pose-aware benchmark covering object translation, object rotation, and camera movement with pose-aware evaluation metrics. Experiments confirm consistent gains in geometric accuracy, identity fidelity, and background quality. Our codes are available at https://github.com/Heey731/GeoEdit.","authors":["Yi He","Jiangming Wang","Xinyu Wang","Mark Fong","Songchun Zhang","Yuxuan Xue","Hai-Tao Zheng","Yue Ma"],"published":"2026-06-29T09:12:20Z","updated":"2026-06-29T09:12:20Z","abstract_url":"https://arxiv.org/abs/2606.30003v1","html_url":"https://arxiv.org/html/2606.30003v1","pdf_url":"https://arxiv.org/pdf/2606.30003v1.pdf","matched_keywords":["video","3d","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.30001v1","title":"SICAGE: Speaker-Independent Culture-Aware Gesture Generation using TED4C-L Dataset","abstract":"Recent co-speech gesture generation methods often overlook cultural differences, limiting their effectiveness in human-agent interaction. Moreover, culture-conditioned models are rarely evaluated under speaker-disjoint splits, so apparent \"cultural\" behavior may be confounded with speaker-specific gesturing style. We introduce SICAGE, a modular framework for culture-aware co-speech gesture generation that conditions motion synthesis models on speaker-independent cultural representations. SICAGE learns these representations from audio and text by treating each speaker as a separate domain while imposing invariance across speakers. This encourages representations to remain culture-discriminative while reducing dependence on speaker identity. The resulting cultural embeddings condition a multimodal generator to produce culturally appropriate gestures. We instantiate this idea with two domain generalization approaches: adversarial learning and Fishr regularization. We further introduce ALaDiT, a real-time diffusion-based gesture generator designed to efficiently incorporate the learned cultural embeddings. To validate our method, we built TED4C-L, a 106-hour multimodal dataset of 764 TED speakers from four cultural groups. Experiments show that SICAGE improves motion realism, diversity, beat synchronization, semantic relevance, and cultural consistency.","authors":["Ariel Gjaci","Antonio Sgorbissa","Vittorio Murino"],"published":"2026-06-29T09:11:15Z","updated":"2026-06-29T09:11:15Z","abstract_url":"https://arxiv.org/abs/2606.30001v1","html_url":"https://arxiv.org/html/2606.30001v1","pdf_url":"https://arxiv.org/pdf/2606.30001v1.pdf","matched_keywords":["agent","representation","multimodal","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.29997v1","title":"Rigel: Self-Distilled Score Adaptation for Image and Video Captioning Evaluation","abstract":"Automatic evaluation of image and video captioning is essential for benchmarking multimodal systems, although standard evaluation metrics show limited alignment with human judgments. Recent approaches using large language models (LLMs), commonly referred to as LLM-as-a-Judge, have improved alignment with human judgments but still suffer from a mismatch between large-vocabulary language modeling and evaluation over a small label set. To address this, we propose Rigel, an automatic evaluation metric for image and video captioning, based on self-distilled score adaptation. The metric employs an evaluation-specific scoring head distilled from a frozen LLM, which captures judgment signals in a task-aligned space without relying on large-vocabulary token sets. We then refine the LLM backbone with human judgment data. To train Rigel, we constructed the Vid-Lepus dataset, which contains 3,338 video clips, 33,380 reference captions, and 5,637 candidate captions. Experiments on multiple benchmarks show that Rigel outperforms state-of-the-art metrics, achieving over 10-point improvements on ActivityNet-Fact in the reference-free setting.","authors":["Shuitsu Koyama","Kazuki Matsuda","Yuiga Wada","Shinnosuke Hirano","Daichi Yashima","Komei Sugiura"],"published":"2026-06-29T09:07:29Z","updated":"2026-06-29T09:07:29Z","abstract_url":"https://arxiv.org/abs/2606.29997v1","html_url":"https://arxiv.org/html/2606.29997v1","pdf_url":"https://arxiv.org/pdf/2606.29997v1.pdf","matched_keywords":["video","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.29977v1","title":"A multi-architecture study of specificity refinement and false-positive mechanism analysis in prostate MRI","abstract":"Objectives: To characterize residual false positives in prostate MRI detection, and to evaluate a lightweight post-hoc refinement head for case-level specificity. Materials and Methods: This retrospective study used PI-CAI (5-fold cross-validation) and Prostate158 (n=158; external). A context-aware evidence head and an 89,216-parameter refinement head were trained on a frozen detection backbone; the evidence head was also trained on four further backbones (bare nnU-Net, bare U-Net, bare Mamba, MIGF-Mamba). For each false-positive region, T2-weighted, apparent-diffusion-coefficient, and high-b-value contrast ratios versus peri-lesional rings were compared against ground-truth lesions and contralateral benign regions. Results: False positives were closer to true cancers than to benign tissue in evidence and raw T2-weighted and apparent-diffusion-coefficient contrast, reproducing 35/35 across five architectures (Cohen's d 1.10; FP/benign evidence ratio 2.38x) and 105/105 across modality-perturbation scenarios. On PI-CAI fold-0, refinement raised case-level specificity from 0.469 to 0.549 (+17.2%) at preserved sensitivity (0.943); 5-fold cross-validation showed fold-conditional behavior (9/15 observations positive; range -22% to +28%). On Prostate158, both models saturated (McNemar pooled p=0.69), while the false-positive contrast-matching finding replicated. Conclusion: Residual false positives are contrast-matched to cancer (sharing raw imaging features rather than histologically confirmed mimicry), reproducing across five architectures -- a data-level imaging property, not model-specific artifacts; post-hoc refinement adds practical specificity in-domain but is fold-conditional.","authors":["Yongbo Shu","Kewen Chen","Yifeng Yuan","Zirui Xin","Luo Lei","Yang Yang","Xi Chen","Aijing Luo"],"published":"2026-06-29T08:50:34Z","updated":"2026-06-29T08:50:34Z","abstract_url":"https://arxiv.org/abs/2606.29977v1","html_url":"https://arxiv.org/html/2606.29977v1","pdf_url":"https://arxiv.org/pdf/2606.29977v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.29976v1","title":"Learning Efficient 4D Gaussian Representations from Monocular Videos with Flow Splatting","abstract":"Reconstructing dynamic 3D scenes from monocular videos is challenging due to scene complexity and temporal dynamics. With the advancement of 3D Gaussian Splatting in novel view synthesis, existing methods extend 3D Gaussians to 4D domain with deformation fields, trajectories or spatiotemporal 4D volumes to model scene element deformation. However, these methods suffer from long training time, low rendering speed or high memory consumption for per-frame reconstruction of 4D volumes, without fully exploiting dense dynamic information. To address this issue, we propose Flow Splatting, which constructs the velocity field and enables the conventional splatting technique to render optical flow from the velocity field to supervise dynamics learning process from monocular videos. Specifically, we extend 4D volumes with time varying means and covariance to represent complex dynamics. Then, we construct and approximate the velocity field naturally based on this representations. While conventional volume rendering techniques support to render color fields, we extend the volume rendering strategy to splat the velocity field by considering the influence of camera motions. We conduct experiments on various benchmarks to demonstrate the efficiency and effectiveness of our method. Compared to the state-of-the-art methods, our model achieves better image quality with less time consumption and higher rendering speed.","authors":["Shengjun Zhang","Jinzhao Li","Xin Fei","Yueqi Duan"],"published":"2026-06-29T08:50:27Z","updated":"2026-06-29T08:50:27Z","abstract_url":"https://arxiv.org/abs/2606.29976v1","html_url":"https://arxiv.org/html/2606.29976v1","pdf_url":"https://arxiv.org/pdf/2606.29976v1.pdf","matched_keywords":["video","3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.29964v1","title":"Variance Reduction on the Camera Axis: Multi-View Score Distillation for 3D","abstract":"Score distillation turns a pretrained 2D diffusion model into a 3D generator, but the per-step gradient is estimated from a single randomly chosen view: it is high-variance and blind to global shape consistency. Prior work addresses this by retraining the diffusion prior on multi-view data; this improves consistency but makes the sampling contribution inseparable from prior quality. We instead isolate the sampling axis. The per-step gradient is one noisy sample of an expectation over views; aggregating K samples per step at a fixed total UNet budget reduces variance without touching the prior. We introduce Multi-View Aggregated Score Distillation (MV-SDI), which aggregates gradients from K views per step via gradient accumulation, keeping peak memory unchanged and the 2D prior frozen, and draws views as antithetic antipodal pairs, a prior-independent geometric property, for balanced angular coverage. At a fixed 10,000-UNet-call budget, K=2 raises CLIP R-Precision from 74.8% to 83.8% and CLIP score from 0.297 to 0.312, with consistent gains on HPSv2 and ImageReward and a 0.0% divergence rate on the 43-prompt benchmark; optimization steps halve as a consequence. K=4 gives a fourfold step reduction at R-Precision 86.9% and CLIP 0.307, still well above the single-view baseline on every alignment metric. MV-SDI is compatible with gradient-based score-distillation pipelines, including Score Distillation via Inversion, and requires no retraining and no multi-view data.","authors":["Marian Lupascu","Mihai Sorin Stupariu","Ionut Mironica"],"published":"2026-06-29T08:41:42Z","updated":"2026-06-29T08:41:42Z","abstract_url":"https://arxiv.org/abs/2606.29964v1","html_url":"https://arxiv.org/html/2606.29964v1","pdf_url":"https://arxiv.org/pdf/2606.29964v1.pdf","matched_keywords":["3d","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.29963v1","title":"Explainability-Aware Frustum Attack: Exposing Structural Vulnerabilities in LiDAR-Based 3D Object Detectors","abstract":"The structural vulnerabilities of point cloud-based 3D object detectors remain poorly understood. Prior work has studied adversarial robustness primarily on isolated 3D object models, while recent LiDAR spoofing attacks target richer and more realistic driving scenes but focus mainly on physical realizability rather than understanding detector behavior or attack efficiency. In this work, we investigate how LiDAR-based detectors rely on spatial evidence in complex scenes and whether these reliance patterns can be exploited to induce failures more efficiently. To this end, we propose an explainability-guided adversarial analysis methodology. We introduce the Saliency-LiDAR (SALL) method, which aggregates Integrated Gradient attributions across scenes to produce universal saliency maps for LiDAR-based 3D object detectors. Guided by these maps, we design the Explainability-aware Frustum Attack (EFA), which selectively perturbs only the most influential frustums rather than uniformly attacking entire object regions. Experiments on KITTI and nuScenes, across detectors such as PointPillars and SECOND, show that EFA reduces detection recall by more than 15 percentage points while requiring 25-50% fewer perturbed frustums than the state-of-the-art non-saliency-aware baseline. These findings reveal that modern 3D detectors concentrate discriminative evidence in a small subset of spatial regions, exposing a structural robustness vulnerability in current LiDAR perception systems. Our code is released at https://github.com/SecMindLab/Saliency_LiDAR.","authors":["Chengzeng You","Binbin Xu","Soteris Demetriou"],"published":"2026-06-29T08:40:16Z","updated":"2026-06-29T08:40:16Z","abstract_url":"https://arxiv.org/abs/2606.29963v1","html_url":"https://arxiv.org/html/2606.29963v1","pdf_url":"https://arxiv.org/pdf/2606.29963v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"},{"id":"2606.29941v1","title":"Seeing Touch from Motion: A Unified Modality-Aware Visuo-Tactile Policy with Tactile Motion Correlation","abstract":"Visuo-Tactile policies leveraging optical tactile sensors have shown great promise in contact-rich manipulation. These sensors achieve high spatial resolution and multi-dimensional force sensing by utilizing an internal camera to monitor the deformation of their elastic gel surface, thereby indirectly inferring tactile cues. Despite their advantages, extracting fine-grained contact states necessary for contact-rich manipulation remains an open challenge. Existing methods typically use either raw images or cumulative motion fields to represent tactile cues. However, both are prone to perception ambiguity. Raw tactile images mainly capture appearance changes, while cumulative motion fields only reflect the aggregate gel deformation. Consequently, distinct fine-grained contact states can exhibit highly similar patterns, making it difficult to explicitly distinguish subtle contact variations. To address this issue, we explore the dynamic priors of tactile motion and discover that the correlation between transient and cumulative motion can explicitly distinguish fine-grained contact states. Based on this insight, we propose a motion-aware tactile representation to facilitate contact-rich manipulation. Beyond tactile representation, effective fusion of tactile and visual modalities is also critical. Most existing fusion methods either directly concatenate features from each modality or train modality-specific networks separately and fuse their outputs. However, these strategies struggle to simultaneously model cross-modal interactions and preserve modality-specific characteristics. In this work, we take advantage of the Mixture-of-Transformers architecture and propose a unified modality-aware visuo-tactile policy that captures cross-modal complementarity while maintaining modality-specific properties.","authors":["Shengqi Xu","Guojin Zhong","Yang Liu","Fanjie Wang","Hu Luo","Hanyu Zhou","Weiyao Zhang","Ziyi Ye","Zuxuan Wu","Yu-Gang Jiang"],"published":"2026-06-29T08:20:18Z","updated":"2026-06-29T08:20:18Z","abstract_url":"https://arxiv.org/abs/2606.29941v1","html_url":"https://arxiv.org/html/2606.29941v1","pdf_url":"https://arxiv.org/pdf/2606.29941v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-30T04:58:51+00:00","last_seen_at":"2026-06-30T04:58:51+00:00"}],"tracked_paper_count":73,"storage_mode":"latest_overwrite"}};
